/// File metadata and digest evidence shared by child scenarios in one
/// prepared/native Vortex batch run.
#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct TraditionalVortexSourceSnapshot {
    fact_vortex_bytes: u64,
    fact_delta_overlay_vortex_bytes: u64,
    dim_vortex_bytes: u64,
    cdc_delta_vortex_bytes: u64,
    fact_vortex_digest: String,
    fact_delta_overlay_vortex_digest: Option<String>,
    dim_vortex_digest: String,
    cdc_delta_vortex_digest: Option<String>,
    source_bytes_read: u64,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalVortexSourceSnapshot {
    fn from_paths(
        fact_vortex: &std::path::Path,
        dim_vortex: &std::path::Path,
        cdc_delta_vortex: Option<&std::path::Path>,
        fact_delta_overlay_vortex: Option<&std::path::Path>,
    ) -> Result<Self> {
        let fact_vortex_bytes = file_len(fact_vortex, "fact Vortex file")?;
        let fact_delta_overlay_vortex_bytes = fact_delta_overlay_vortex.map_or(Ok(0), |path| {
            file_len(path, "fact append-only delta overlay Vortex file")
        })?;
        let dim_vortex_bytes = file_len(dim_vortex, "dimension Vortex file")?;
        let cdc_delta_vortex_bytes =
            cdc_delta_vortex.map_or(Ok(0), |path| file_len(path, "CDC delta Vortex file"))?;
        let fact_vortex_digest = file_digest(fact_vortex, "fact Vortex file")?;
        let fact_delta_overlay_vortex_digest = fact_delta_overlay_vortex
            .map(|path| file_digest(path, "fact append-only delta overlay Vortex file"))
            .transpose()?;
        let dim_vortex_digest = file_digest(dim_vortex, "dimension Vortex file")?;
        let cdc_delta_vortex_digest = cdc_delta_vortex
            .map(|path| file_digest(path, "CDC delta Vortex file"))
            .transpose()?;
        let source_bytes_read = fact_vortex_bytes
            .checked_add(fact_delta_overlay_vortex_bytes)
            .and_then(|bytes| bytes.checked_add(dim_vortex_bytes))
            .and_then(|bytes| bytes.checked_add(cdc_delta_vortex_bytes))
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "native Vortex traditional analytics source byte count overflow".to_string(),
                )
            })?;

        Ok(Self {
            fact_vortex_bytes,
            fact_delta_overlay_vortex_bytes,
            dim_vortex_bytes,
            cdc_delta_vortex_bytes,
            fact_vortex_digest,
            fact_delta_overlay_vortex_digest,
            dim_vortex_digest,
            cdc_delta_vortex_digest,
            source_bytes_read,
        })
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq)]
struct TraditionalDimensionKeyLookup {
    dense_membership: Option<Vec<bool>>,
    dense_contiguous_max_key: Option<u32>,
    key_count: usize,
    max_key: Option<u32>,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalDimensionKeyLookup {
    fn from_dim_keys(keys: impl Iterator<Item = u32>) -> Self {
        let keys = keys.collect::<Vec<_>>();
        let max_key = keys.iter().copied().max();
        let dense_membership = max_key
            .filter(|key| TraditionalDenseU32GroupAccum::can_admit(*key))
            .and_then(|key| {
                let len = usize::try_from(key).ok()?.checked_add(1)?;
                let mut membership = vec![false; len];
                for key in &keys {
                    let index = usize::try_from(*key).ok()?;
                    membership[index] = true;
                }
                Some(membership)
            });
        let dense_contiguous_max_key = max_key.filter(|_| {
            dense_membership.as_ref().is_some_and(|membership| {
                membership.len() == keys.len() && membership.iter().all(|present| *present)
            })
        });
        Self {
            dense_membership,
            dense_contiguous_max_key,
            key_count: keys.len(),
            max_key,
        }
    }

    fn contains(&self, key: u32) -> Option<bool> {
        if let Some(max_key) = self.dense_contiguous_max_key {
            return Some(key <= max_key);
        }
        self.dense_membership.as_ref().map(|membership| {
            usize::try_from(key)
                .ok()
                .and_then(|index| membership.get(index))
                .copied()
                .unwrap_or(false)
        })
    }

    const fn dense_contiguous_max_key(&self) -> Option<u32> {
        self.dense_contiguous_max_key
    }

    fn status(&self) -> &'static str {
        if self.key_count == 0 {
            "empty_dimension_key_membership"
        } else if self.dense_contiguous_max_key.is_some() {
            "dense_contiguous_dimension_key_range"
        } else if self.dense_membership.is_some() {
            "dense_dimension_key_membership"
        } else {
            "sparse_hash_dimension_key_membership"
        }
    }
}

