#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct TraditionalVortexWriteTiming {
    array_build_micros: u64,
    vortex_write_micros: u64,
    writer_context_open_micros: u64,
    writer_context_write_count: usize,
    writer_context_reuse_hit_count: usize,
    segment_write_micros: u64,
    workspace_stage_micros: u64,
    artifact_digest: Option<String>,
    artifact_bytes: Option<u64>,
    artifact_rows: Option<u64>,
    array_build_provider_kind: &'static str,
    array_build_provider_surface: &'static str,
    array_build_strategy: &'static str,
    array_build_input_layout: &'static str,
    array_build_record_batch_count: usize,
    manual_scalar_copy_avoided: bool,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalVortexWriteTiming {
    const VORTEX_RECORD_BATCH_PROVIDER_KIND: &'static str = "vortex_array_kernel";
    const VORTEX_RECORD_BATCH_PROVIDER_SURFACE: &'static str = "ArrayRef::from_arrow(RecordBatch)";
    const VORTEX_RECORD_BATCH_STRATEGY: &'static str = "vortex_from_arrow_record_batch";
    const VORTEX_RECORD_BATCH_INPUT_LAYOUT: &'static str = "traditional_arrow_record_batch";
    const VORTEX_DIRECT_COLUMNAR_STRATEGY: &'static str =
        "vortex_from_arrow_record_batch_without_traditional_rows";
    const VORTEX_DIRECT_COLUMNAR_INPUT_LAYOUT: &'static str =
        "traditional_vortex_provider_record_batch";
    const VORTEX_DIRECT_TEXT_STRATEGY: &'static str =
        "vortex_from_text_adapter_record_batch_without_persistent_traditional_rows";
    const VORTEX_DIRECT_TEXT_INPUT_LAYOUT: &'static str = "traditional_text_adapter_record_batch";
    const VORTEX_MIXED_RECORD_BATCH_STRATEGY: &'static str =
        "vortex_from_arrow_record_batch_mixed_traditional_text_and_direct_columnar";
    const VORTEX_MIXED_RECORD_BATCH_INPUT_LAYOUT: &'static str =
        "mixed_traditional_arrow_record_batch_text_adapter_and_vortex_provider_record_batch";

    fn vortex_record_batch_provider(array_build_micros: u64, vortex_write_micros: u64) -> Self {
        Self::vortex_record_batch_provider_with_layout(
            array_build_micros,
            vortex_write_micros,
            Self::VORTEX_RECORD_BATCH_STRATEGY,
            Self::VORTEX_RECORD_BATCH_INPUT_LAYOUT,
        )
    }

    fn direct_columnar_record_batch_provider(
        array_build_micros: u64,
        vortex_write_micros: u64,
    ) -> Self {
        Self::vortex_record_batch_provider_with_layout(
            array_build_micros,
            vortex_write_micros,
            Self::VORTEX_DIRECT_COLUMNAR_STRATEGY,
            Self::VORTEX_DIRECT_COLUMNAR_INPUT_LAYOUT,
        )
    }

    fn direct_text_record_batch_provider(
        array_build_micros: u64,
        vortex_write_micros: u64,
    ) -> Self {
        Self::vortex_record_batch_provider_with_layout(
            array_build_micros,
            vortex_write_micros,
            Self::VORTEX_DIRECT_TEXT_STRATEGY,
            Self::VORTEX_DIRECT_TEXT_INPUT_LAYOUT,
        )
    }

    fn vortex_record_batch_provider_with_layout(
        array_build_micros: u64,
        vortex_write_micros: u64,
        array_build_strategy: &'static str,
        array_build_input_layout: &'static str,
    ) -> Self {
        Self {
            array_build_micros,
            vortex_write_micros,
            writer_context_open_micros: 0,
            writer_context_write_count: 0,
            writer_context_reuse_hit_count: 0,
            segment_write_micros: 0,
            workspace_stage_micros: 0,
            artifact_digest: None,
            artifact_bytes: None,
            artifact_rows: None,
            array_build_provider_kind: Self::VORTEX_RECORD_BATCH_PROVIDER_KIND,
            array_build_provider_surface: Self::VORTEX_RECORD_BATCH_PROVIDER_SURFACE,
            array_build_strategy,
            array_build_input_layout,
            array_build_record_batch_count: 1,
            manual_scalar_copy_avoided: true,
        }
    }

    fn add(self, other: &Self) -> Result<Self> {
        Ok(Self {
            array_build_micros: checked_u64_sum(self.array_build_micros, other.array_build_micros)?,
            vortex_write_micros: checked_u64_sum(
                self.vortex_write_micros,
                other.vortex_write_micros,
            )?,
            writer_context_open_micros: checked_u64_sum(
                self.writer_context_open_micros,
                other.writer_context_open_micros,
            )?,
            writer_context_write_count: self
                .writer_context_write_count
                .checked_add(other.writer_context_write_count)
                .ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "traditional analytics Vortex writer context write count overflow"
                            .to_string(),
                    )
                })?,
            writer_context_reuse_hit_count: self
                .writer_context_reuse_hit_count
                .checked_add(other.writer_context_reuse_hit_count)
                .ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "traditional analytics Vortex writer context reuse hit count overflow"
                            .to_string(),
                    )
                })?,
            segment_write_micros: checked_u64_sum(
                self.segment_write_micros,
                other.segment_write_micros,
            )?,
            workspace_stage_micros: checked_u64_sum(
                self.workspace_stage_micros,
                other.workspace_stage_micros,
            )?,
            artifact_digest: None,
            artifact_bytes: merge_optional_vortex_write_u64(
                self.artifact_bytes,
                other.artifact_bytes,
                "traditional analytics Vortex artifact byte count",
            )?,
            artifact_rows: merge_optional_vortex_write_u64(
                self.artifact_rows,
                other.artifact_rows,
                "traditional analytics Vortex artifact row count",
            )?,
            array_build_provider_kind: merge_static_evidence_field(
                self.array_build_provider_kind,
                other.array_build_provider_kind,
                "traditional analytics Vortex array build provider kind",
            )?,
            array_build_provider_surface: merge_static_evidence_field(
                self.array_build_provider_surface,
                other.array_build_provider_surface,
                "traditional analytics Vortex array build provider surface",
            )?,
            array_build_strategy: merge_vortex_record_batch_strategy(
                self.array_build_strategy,
                other.array_build_strategy,
            )?,
            array_build_input_layout: merge_vortex_record_batch_input_layout(
                self.array_build_input_layout,
                other.array_build_input_layout,
            )?,
            array_build_record_batch_count: self
                .array_build_record_batch_count
                .checked_add(other.array_build_record_batch_count)
                .ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "traditional analytics Vortex array build record batch count overflow"
                            .to_string(),
                    )
                })?,
            manual_scalar_copy_avoided: self.manual_scalar_copy_avoided
                && other.manual_scalar_copy_avoided,
        })
    }

    fn writer_context_reuse_status(&self) -> &'static str {
        if self.writer_context_write_count == 0 {
            "not_reported"
        } else if self.writer_context_reuse_hit_count > 0 {
            "single_vortex_runtime_session_reused_across_artifacts"
        } else {
            "single_artifact_no_reuse_hit"
        }
    }

    fn write_coalescing_status(&self) -> &'static str {
        if self.writer_context_write_count == 0 {
            "not_reported"
        } else if self.writer_context_write_count > 1 {
            "scheduled_multi_artifact_writes_on_shared_context"
        } else {
            "single_artifact_write"
        }
    }

    fn write_coalescing_reason(&self) -> &'static str {
        if self.writer_context_write_count == 0 {
            "not_reported"
        } else if self.writer_context_write_count > 1 {
            "distinct_fact_dim_cdc_artifact_contract_preserved_while_reusing_vortex_runtime_session"
        } else {
            "coalescing_not_applicable_single_artifact"
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn vortex_write_artifact_digest(
    timing: &TraditionalVortexWriteTiming,
    label: &str,
) -> Result<String> {
    timing.artifact_digest.clone().ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!(
            "traditional analytics {label} writer did not return an artifact digest; no fallback execution was attempted"
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn vortex_write_artifact_bytes(timing: &TraditionalVortexWriteTiming, label: &str) -> Result<u64> {
    timing.artifact_bytes.ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!(
            "traditional analytics {label} writer did not return artifact bytes; no fallback execution was attempted"
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn merge_optional_vortex_write_u64(
    left: Option<u64>,
    right: Option<u64>,
    label: &str,
) -> Result<Option<u64>> {
    match (left, right) {
        (Some(left), Some(right)) => Ok(Some(checked_u64_sum(left, right)?)),
        (None, None) => Ok(None),
        _ => Err(ShardLoomError::InvalidOperation(format!(
            "{label} metadata source mismatch while merging Vortex write timing; no fallback execution was attempted"
        ))),
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn merge_static_evidence_field(
    left: &'static str,
    right: &'static str,
    label: &str,
) -> Result<&'static str> {
    if left == right {
        Ok(left)
    } else {
        Err(ShardLoomError::InvalidOperation(format!(
            "{label} mismatch: {left} vs {right}; no fallback execution was attempted"
        )))
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn merge_vortex_record_batch_strategy(
    left: &'static str,
    right: &'static str,
) -> Result<&'static str> {
    merge_vortex_record_batch_evidence_field(
        left,
        right,
        &[
            TraditionalVortexWriteTiming::VORTEX_RECORD_BATCH_STRATEGY,
            TraditionalVortexWriteTiming::VORTEX_DIRECT_COLUMNAR_STRATEGY,
            TraditionalVortexWriteTiming::VORTEX_DIRECT_TEXT_STRATEGY,
            TraditionalVortexWriteTiming::VORTEX_MIXED_RECORD_BATCH_STRATEGY,
        ],
        TraditionalVortexWriteTiming::VORTEX_MIXED_RECORD_BATCH_STRATEGY,
        "traditional analytics Vortex array build strategy",
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn merge_vortex_record_batch_input_layout(
    left: &'static str,
    right: &'static str,
) -> Result<&'static str> {
    merge_vortex_record_batch_evidence_field(
        left,
        right,
        &[
            TraditionalVortexWriteTiming::VORTEX_RECORD_BATCH_INPUT_LAYOUT,
            TraditionalVortexWriteTiming::VORTEX_DIRECT_COLUMNAR_INPUT_LAYOUT,
            TraditionalVortexWriteTiming::VORTEX_DIRECT_TEXT_INPUT_LAYOUT,
            TraditionalVortexWriteTiming::VORTEX_MIXED_RECORD_BATCH_INPUT_LAYOUT,
        ],
        TraditionalVortexWriteTiming::VORTEX_MIXED_RECORD_BATCH_INPUT_LAYOUT,
        "traditional analytics Vortex array build input layout",
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn merge_vortex_record_batch_evidence_field(
    left: &'static str,
    right: &'static str,
    compatible_values: &[&'static str],
    mixed_strategy: &'static str,
    label: &str,
) -> Result<&'static str> {
    if left == right {
        return Ok(left);
    }
    let is_record_batch_strategy = |value| compatible_values.contains(&value);
    if is_record_batch_strategy(left) && is_record_batch_strategy(right) {
        Ok(mixed_strategy)
    } else {
        merge_static_evidence_field(left, right, label)
    }
}

fn traditional_capillary_source_refs(
    source_state_id: &str,
    source_path: &std::path::Path,
    source_bytes: u64,
    row_count: u64,
    split_count: usize,
) -> (String, String, String) {
    let split_count = split_count.max(1);
    let split_count_u64 = u64::try_from(split_count).unwrap_or(u64::MAX).max(1);
    let mut split_refs = Vec::with_capacity(split_count);
    let mut byte_refs = Vec::with_capacity(split_count);
    let mut row_refs = Vec::with_capacity(split_count);
    for split_index in 0..split_count {
        let split_index_u64 = u64::try_from(split_index).unwrap_or(u64::MAX);
        let next_split_u64 = split_index_u64.saturating_add(1);
        let byte_start = source_bytes.saturating_mul(split_index_u64) / split_count_u64;
        let byte_end = source_bytes.saturating_mul(next_split_u64) / split_count_u64;
        let row_start = row_count.saturating_mul(split_index_u64) / split_count_u64;
        let row_end = row_count.saturating_mul(next_split_u64) / split_count_u64;
        split_refs.push(format!(
            "{source_state_id}:split={split_index}:source={}:bytes={byte_start}..{byte_end}:rows={row_start}..{row_end}",
            source_path.display()
        ));
        byte_refs.push(format!(
            "{source_state_id}:split={split_index}:bytes={byte_start}..{byte_end}"
        ));
        row_refs.push(format!(
            "{source_state_id}:split={split_index}:rows={row_start}..{row_end}"
        ));
    }
    (
        split_refs.join(";"),
        byte_refs.join(";"),
        row_refs.join(";"),
    )
}

struct TraditionalCapillarySourceRef<'a> {
    role: &'static str,
    path: &'a std::path::Path,
    bytes: u64,
    rows: u64,
    split_count: usize,
}

fn traditional_capillary_source_refs_for_roles(
    source_state_id: &str,
    sources: &[TraditionalCapillarySourceRef<'_>],
) -> (String, String, String, usize, u64, u64) {
    let mut split_refs = Vec::with_capacity(sources.len());
    let mut byte_refs = Vec::with_capacity(sources.len());
    let mut row_refs = Vec::with_capacity(sources.len());
    let mut split_count = 0usize;
    let mut source_bytes = 0u64;
    let mut row_count = 0u64;
    for source in sources {
        let role_source_state_id = format!("{source_state_id}:{}", source.role);
        let (role_split_refs, role_byte_refs, role_row_refs) = traditional_capillary_source_refs(
            &role_source_state_id,
            source.path,
            source.bytes,
            source.rows,
            source.split_count,
        );
        split_refs.push(role_split_refs);
        byte_refs.push(role_byte_refs);
        row_refs.push(role_row_refs);
        split_count = split_count.saturating_add(source.split_count.max(1));
        source_bytes = source_bytes.saturating_add(source.bytes);
        row_count = row_count.saturating_add(source.rows);
    }
    (
        split_refs.join(";"),
        byte_refs.join(";"),
        row_refs.join(";"),
        split_count,
        source_bytes,
        row_count,
    )
}

