#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone)]
struct TraditionalPreparedBatchWorkspaceReuseDecision {
    hit: bool,
    reason: String,
    manifest_digest: String,
    manifest_path: PathBuf,
    manifest_payload: Option<serde_json::Value>,
    request_payload: serde_json::Value,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalPreparedBatchWorkspaceReuseDecision {
    fn miss(
        manifest_path: PathBuf,
        reason: impl Into<String>,
        request_payload: serde_json::Value,
    ) -> Self {
        let reason = reason.into();
        Self {
            hit: false,
            reason,
            manifest_digest: "none".to_string(),
            manifest_path,
            manifest_payload: None,
            request_payload,
        }
    }

    fn miss_with_manifest(
        manifest_path: PathBuf,
        reason: impl Into<String>,
        manifest_digest: String,
        manifest_payload: serde_json::Value,
        request_payload: serde_json::Value,
    ) -> Self {
        let reason = reason.into();
        Self {
            hit: false,
            reason,
            manifest_digest,
            manifest_path,
            manifest_payload: Some(manifest_payload),
            request_payload,
        }
    }

    fn hit(
        manifest_path: PathBuf,
        manifest_digest: String,
        manifest_payload: serde_json::Value,
        request_payload: serde_json::Value,
    ) -> Self {
        Self {
            hit: true,
            reason: "manifest_fingerprints_match".to_string(),
            manifest_digest,
            manifest_path,
            manifest_payload: Some(manifest_payload),
            request_payload,
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_batch_reuse_manifest_path(workspace_dir: &std::path::Path) -> PathBuf {
    workspace_dir
        .join(PREPARED_STATE_REUSE_MANIFEST_DIR)
        .join(PREPARED_STATE_REUSE_MANIFEST_FILE)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_batch_index_path(workspace_dir: &std::path::Path) -> PathBuf {
    workspace_dir
        .join(PREPARED_STATE_REUSE_MANIFEST_DIR)
        .join(PREPARED_STATE_INDEX_FILE)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_state_index_digest_from_manifest(manifest_payload: &serde_json::Value) -> String {
    json_string_field(manifest_payload, "prepared_state_index_digest")
        .unwrap_or_else(|| prepared_state_index_payload(manifest_payload).1)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_state_index_payload(
    manifest_payload: &serde_json::Value,
) -> (serde_json::Value, String) {
    let prepare_fields = manifest_payload
        .get("prepare_fields")
        .and_then(serde_json::Value::as_object);
    let prepare_field = |key: &str| -> String {
        prepare_fields
            .and_then(|fields| fields.get(key))
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_string()
    };
    let artifact_path = |role: &str| -> String {
        manifest_payload
            .get("prepared_artifacts")
            .and_then(|artifacts| artifacts.get(role))
            .and_then(|artifact| artifact.get("path"))
            .and_then(serde_json::Value::as_str)
            .unwrap_or("none")
            .to_string()
    };
    let artifact_digest = |role: &str| -> String {
        manifest_payload
            .get("prepared_artifacts")
            .and_then(|artifacts| artifacts.get(role))
            .and_then(|artifact| artifact.get("digest"))
            .and_then(serde_json::Value::as_str)
            .unwrap_or("none")
            .to_string()
    };
    let prepare_policy_digest = manifest_payload.get("prepare_policy").map_or_else(
        || "missing_prepare_policy".to_string(),
        stable_json_value_digest,
    );
    let key = serde_json::json!({
        "schema_version": PREPARED_STATE_INDEX_SCHEMA_VERSION,
        "source_admission_packet_digest": json_string_field(
            manifest_payload,
            "source_admission_packet_digest",
        )
        .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string()),
        "schema_hash": traditional_source_admission_schema_hash(),
        "route_family": "compatibility_prepare_to_prepared_native_vortex",
        "layout_policy": {
            "strategy": prepare_field("vortex_array_build_strategy"),
            "input_layout": prepare_field("vortex_array_build_input_layout"),
        },
        "native_io_status": prepare_field("native_io_certificate_status"),
        "artifact_refs": {
            "fact": artifact_path("fact"),
            "fact_delta_overlay": artifact_path("fact_delta_overlay"),
            "dim": artifact_path("dim"),
            "cdc_delta": artifact_path("cdc_delta"),
        },
        "artifact_digests": {
            "fact": artifact_digest("fact"),
            "fact_delta_overlay": artifact_digest("fact_delta_overlay"),
            "dim": artifact_digest("dim"),
            "cdc_delta": artifact_digest("cdc_delta"),
        },
        "prepare_policy_digest": prepare_policy_digest,
    });
    let index_digest = stable_json_value_digest(&key);
    let payload = serde_json::json!({
        "schema_version": PREPARED_STATE_INDEX_SCHEMA_VERSION,
        "index_digest": index_digest,
        "index_key": key,
        "manifest_digest": json_string_field(manifest_payload, "manifest_digest")
            .unwrap_or_else(|| "missing_manifest_digest".to_string()),
        "manifest_path": json_string_field(manifest_payload, "manifest_path")
            .unwrap_or_else(|| PREPARED_STATE_REUSE_PATH_WORKSPACE.to_string()),
        "fallback_attempted": false,
        "external_engine_invoked": false,
        "claim_boundary": "workspace-local prepared-state index only; lookup never bypasses manifest digest, source fingerprint, artifact fingerprint, replay proof, Native I/O certificate, or no-fallback checks",
    });
    (payload, index_digest)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn write_prepared_state_index(
    workspace_dir: &std::path::Path,
    manifest_payload: &serde_json::Value,
) -> Result<String> {
    let (index_payload, index_digest) = prepared_state_index_payload(manifest_payload);
    write_json_manifest_atomically(
        &traditional_prepared_batch_index_path(workspace_dir),
        &index_payload,
    )?;
    Ok(index_digest)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn evaluate_traditional_prepared_batch_workspace_reuse(
    fact_input: &std::path::Path,
    dim_input: &std::path::Path,
    cdc_delta_input: Option<&std::path::Path>,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<TraditionalPreparedBatchWorkspaceReuseDecision> {
    let manifest_path = traditional_prepared_batch_reuse_manifest_path(workspace_dir);
    let request_payload = traditional_prepared_batch_reuse_request_payload(
        fact_input,
        dim_input,
        cdc_delta_input,
        workspace_dir,
        input_format,
        resource_policy,
    )?;
    let request_digest =
        json_string_field(&request_payload, "route_request_digest").unwrap_or_default();
    if !manifest_path.exists() {
        return Ok(TraditionalPreparedBatchWorkspaceReuseDecision::miss(
            manifest_path,
            "no_reuse_manifest",
            request_payload,
        ));
    }
    let manifest_text = match std::fs::read_to_string(&manifest_path) {
        Ok(text) => text,
        Err(error) => {
            return Ok(TraditionalPreparedBatchWorkspaceReuseDecision::miss(
                manifest_path,
                format!("reuse_manifest_unreadable:{error}"),
                request_payload,
            ));
        }
    };
    let manifest_payload: serde_json::Value = match serde_json::from_str(&manifest_text) {
        Ok(payload) => payload,
        Err(error) => {
            return Ok(TraditionalPreparedBatchWorkspaceReuseDecision::miss(
                manifest_path,
                format!("reuse_manifest_unparseable:{error}"),
                request_payload,
            ));
        }
    };
    let manifest_digest =
        json_string_field(&manifest_payload, "manifest_digest").unwrap_or_default();
    if json_string_field(&manifest_payload, "schema_version").as_deref()
        != Some(PREPARED_STATE_REUSE_POLICY_WORKSPACE)
    {
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                "reuse_manifest_schema_mismatch",
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    if manifest_digest != prepared_batch_manifest_digest(&manifest_payload) {
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                "reuse_manifest_digest_mismatch",
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    if json_string_field(&manifest_payload, "route_request_digest").as_deref()
        != Some(request_digest.as_str())
    {
        let reason =
            prepared_batch_request_invalidation_reason(&manifest_payload, &request_payload);
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                reason,
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    let artifact_reason = prepared_batch_artifact_invalidation_reason(&manifest_payload)?;
    if artifact_reason != "none" {
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                artifact_reason,
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    if json_bool_field(&manifest_payload, "fallback_attempted") {
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                "reuse_manifest_fallback_attempted",
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    if json_bool_field(&manifest_payload, "external_engine_invoked") {
        return Ok(
            TraditionalPreparedBatchWorkspaceReuseDecision::miss_with_manifest(
                manifest_path,
                "reuse_manifest_external_engine_invoked",
                manifest_digest,
                manifest_payload,
                request_payload,
            ),
        );
    }
    Ok(TraditionalPreparedBatchWorkspaceReuseDecision::hit(
        manifest_path,
        manifest_digest,
        manifest_payload,
        request_payload,
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_arguments)]
fn traditional_prepared_batch_reuse_request_payload(
    fact_input: &std::path::Path,
    dim_input: &std::path::Path,
    cdc_delta_input: Option<&std::path::Path>,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<serde_json::Value> {
    let fact_input_fingerprint = local_reuse_path_fingerprint(fact_input, "fact input")?;
    let dim_input_fingerprint = local_reuse_path_fingerprint(dim_input, "dimension input")?;
    let cdc_delta_input_fingerprint = match cdc_delta_input {
        Some(path) => local_reuse_path_fingerprint(path, "CDC delta input")?,
        None => serde_json::Value::Null,
    };
    let (source_admission_packet, source_admission_packet_digest) =
        traditional_source_admission_request_packet(
            &fact_input_fingerprint,
            &dim_input_fingerprint,
            &cdc_delta_input_fingerprint,
            workspace_dir,
            input_format,
            resource_policy,
        );
    let mut payload = serde_json::json!({
        "schema_version": PREPARED_STATE_REUSE_POLICY_WORKSPACE,
        "route_id": "local_file_prepare_once_first_query",
        "batch_route_id": "local_file_prepare_once_batch",
        "fact_input": fact_input_fingerprint,
        "dim_input": dim_input_fingerprint,
        "cdc_delta_input": cdc_delta_input_fingerprint,
        "source_admission_packet": source_admission_packet,
        "source_admission_packet_digest": source_admission_packet_digest,
        "prepare_policy": {
            "input_format": input_format.as_str(),
            "artifact_root": normalize_manifest_path(workspace_dir),
            "artifact_layout": "fact.vortex,dim.vortex,optional_cdc_delta.vortex",
            "artifact_output_policy": "caller_owned_workspace_local_vortex_artifacts",
            "cdc_delta_present": cdc_delta_input.is_some(),
            "preserve_all_text_columns_for_reuse": true,
            "memory_gb": resource_policy.requested_memory_gb,
            "max_parallelism": resource_policy.requested_max_parallelism,
            "vortex_normalization_point": "SourceState -> vortex_ingest -> VortexPreparedState",
            "fallback_attempted": false,
            "external_engine_invoked": false,
        },
    });
    let route_request_digest = stable_json_value_digest(&payload);
    json_object_insert(
        &mut payload,
        "route_request_digest",
        serde_json::Value::String(route_request_digest),
    );
    Ok(payload)
}

fn traditional_source_admission_schema_hash() -> String {
    route_evidence_digest(&[
        "source_admission_schema",
        TRADITIONAL_FACT_SCHEMA_SUMMARY,
        TRADITIONAL_DIM_SCHEMA_SUMMARY,
        TRADITIONAL_CDC_DELTA_SCHEMA_SUMMARY,
    ])
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_source_admission_request_packet(
    fact_input_fingerprint: &serde_json::Value,
    dim_input_fingerprint: &serde_json::Value,
    cdc_delta_input_fingerprint: &serde_json::Value,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> (serde_json::Value, String) {
    let mut packet = serde_json::json!({
        "schema_version": SOURCE_ADMISSION_PACKET_SCHEMA_VERSION,
        "packet_kind": "local_source_admission_prediction",
        "route_family": "compatibility_prepare_to_prepared_native_vortex",
        "route_id": "local_file_prepare_once_first_query",
        "batch_route_id": "local_file_prepare_once_batch",
        "input_format": input_format.as_str(),
        "source_schema_hash": traditional_source_admission_schema_hash(),
        "source_path_fingerprint_kind": "local_path_size_mtime_metadata",
        "digest_policy": {
            "schema_version": SOURCE_ADMISSION_DIGEST_POLICY_SCHEMA_VERSION,
            "status": "metadata_fingerprint_fast_path",
            "normal_warm_reuse_content_digest_requested": false,
            "claim_grade_content_digest_required": true,
            "full_content_digest_status": "not_requested_for_local_non_publication_row",
            "claim_boundary": "metadata fingerprint admission is valid only for local non-publication benchmark rows; claim-grade publication rows must request full content digest verification",
        },
        "fact_input": fact_input_fingerprint.clone(),
        "dim_input": dim_input_fingerprint.clone(),
        "cdc_delta_input": cdc_delta_input_fingerprint.clone(),
        "row_estimate": {
            "status": "deferred_until_prepare_materializes_source",
            "fact_rows": serde_json::Value::Null,
            "dim_rows": serde_json::Value::Null,
            "cdc_delta_rows": serde_json::Value::Null,
        },
        "artifact_manifest_hash": "pending_until_prepared_artifact_manifest",
        "artifact_root": normalize_manifest_path(workspace_dir),
        "resource_policy": {
            "memory_gb": resource_policy.requested_memory_gb,
            "max_parallelism": resource_policy.requested_max_parallelism,
        },
        "fallback_attempted": false,
        "external_engine_invoked": false,
        "claim_boundary": "admission prediction packet only; packet reuse never bypasses prepared artifact fingerprint checks, Native I/O certificates, correctness replay, or no-fallback evidence",
    });
    let packet_digest = stable_json_value_digest(&packet);
    json_object_insert(
        &mut packet,
        "packet_digest",
        serde_json::Value::String(packet_digest.clone()),
    );
    (packet, packet_digest)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_delta_overlay_base_payload(
    prepare_fields: &[(String, String)],
    fact_input: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
) -> Result<serde_json::Value> {
    if !matches!(
        input_format,
        TraditionalAnalyticsInputFormat::Csv | TraditionalAnalyticsInputFormat::JsonLines
    ) {
        return Ok(serde_json::json!({
            "schema_version": PREPARED_STATE_DELTA_OVERLAY_SCHEMA_VERSION,
            "status": "blocked_base_not_local_text_format",
            "base_source_content_digest": serde_json::Value::Null,
            "base_source_size_bytes": serde_json::Value::Null,
            "base_fact_row_count": serde_json::Value::Null,
            "fallback_attempted": false,
            "external_engine_invoked": false,
        }));
    }
    if !fact_input.is_file() {
        return Ok(serde_json::json!({
            "schema_version": PREPARED_STATE_DELTA_OVERLAY_SCHEMA_VERSION,
            "status": "blocked_base_not_single_local_file",
            "base_source_content_digest": serde_json::Value::Null,
            "base_source_size_bytes": serde_json::Value::Null,
            "base_fact_row_count": serde_json::Value::Null,
            "fallback_attempted": false,
            "external_engine_invoked": false,
        }));
    }
    let base_source_content_digest =
        file_sha256_digest(fact_input, "prepared-state append-only base fact source")?;
    let base_source_size_bytes =
        file_len(fact_input, "prepared-state append-only base fact source")?;
    let base_fact_row_count = prepare_field_from_slice(prepare_fields, "fact_rows")
        .parse::<u64>()
        .unwrap_or_default();
    Ok(serde_json::json!({
        "schema_version": PREPARED_STATE_DELTA_OVERLAY_SCHEMA_VERSION,
        "status": "base_manifest_ready_for_append_only_fact_delta_overlay",
        "base_source_format": input_format.as_str(),
        "base_source_path": normalize_manifest_path(fact_input),
        "base_source_content_digest": base_source_content_digest,
        "base_source_size_bytes": base_source_size_bytes,
        "base_fact_row_count": base_fact_row_count,
        "schema_hash": traditional_source_admission_schema_hash(),
        "route_family": "compatibility_prepare_to_prepared_native_vortex",
        "claim_boundary": "scoped local append-only fact source proof for prepared-state delta overlay only; no update/delete/schema-change/table/CDC claim",
        "fallback_attempted": false,
        "external_engine_invoked": false,
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_lines)]
fn write_traditional_prepared_batch_workspace_reuse_manifest(
    prepare_report: &TraditionalAnalyticsReport,
    fact_input: &std::path::Path,
    workspace_dir: &std::path::Path,
    prior_reuse_reason: &str,
    request_payload: &serde_json::Value,
) -> Result<TraditionalPreparedBatchReuseReport> {
    let manifest_path = traditional_prepared_batch_reuse_manifest_path(workspace_dir);
    let prepare_fields = prepare_report.fields();
    if prepare_field_bool_from_slice(&prepare_fields, "fallback_attempted")
        || prepare_field_bool_from_slice(&prepare_fields, "external_engine_invoked")
    {
        return Ok(TraditionalPreparedBatchReuseReport::no_manifest_yet(
            manifest_path,
            "prepare_report_not_reuse_eligible".to_string(),
        ));
    }
    let source_admission_packet_digest =
        json_string_field(request_payload, "source_admission_packet_digest")
            .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string());
    let fact_artifact = prepared_batch_artifact_manifest(
        &prepare_report.fact_vortex_path,
        "fact",
        &prepare_report.fact_vortex_digest,
    )?;
    let dim_artifact = prepared_batch_artifact_manifest(
        &prepare_report.dim_vortex_path,
        "dimension",
        &prepare_report.dim_vortex_digest,
    )?;
    let cdc_delta_artifact = prepare_report
        .cdc_delta_vortex_path
        .as_ref()
        .zip(prepare_report.cdc_delta_vortex_digest.as_ref())
        .map(|(path, digest)| prepared_batch_artifact_manifest(path, "CDC delta", digest))
        .transpose()?;
    let mut prepared_artifacts = serde_json::Map::new();
    prepared_artifacts.insert("fact".to_string(), fact_artifact);
    prepared_artifacts.insert("dim".to_string(), dim_artifact);
    prepared_artifacts.insert(
        "cdc_delta".to_string(),
        cdc_delta_artifact.unwrap_or(serde_json::Value::Null),
    );
    let prepared_artifacts = serde_json::Value::Object(prepared_artifacts);
    let source_admission_packet_artifact_manifest_hash =
        stable_json_value_digest(&prepared_artifacts);
    let mut manifest_payload = request_payload.clone();
    json_object_insert(
        &mut manifest_payload,
        "created_unix_seconds",
        serde_json::Value::Number(serde_json::Number::from(current_unix_seconds())),
    );
    json_object_insert(
        &mut manifest_payload,
        "manifest_path",
        serde_json::Value::String(manifest_path.display().to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepare_command",
        serde_json::Value::String("traditional-analytics-run".to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepare_fields",
        field_pairs_to_json_object(&prepare_fields),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_artifacts",
        prepared_artifacts,
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_row_estimate_status",
        serde_json::Value::String("observed_after_prepare_materialized_source".to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_fact_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "fact_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_dim_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "dim_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_cdc_delta_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "cdc_delta_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_artifact_manifest_hash",
        serde_json::Value::String(source_admission_packet_artifact_manifest_hash.clone()),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_digest_policy_schema_version",
        serde_json::Value::String(SOURCE_ADMISSION_DIGEST_POLICY_SCHEMA_VERSION.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_digest_policy_status",
        serde_json::Value::String("metadata_fingerprint_fast_path".to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_full_content_digest_requested",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_full_content_digest_required_for_claim_grade",
        serde_json::Value::Bool(true),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_digest_policy_claim_boundary",
        serde_json::Value::String(
            "normal local warm reuse compares normalized path, size, and mtime; claim-grade publication evidence must request full content digest verification"
                .to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_schema_version",
        serde_json::Value::String(PREPARED_STATE_DEPENDENCY_SCHEMA_VERSION.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_checked_roles",
        serde_json::Value::String(PREPARED_BATCH_DEPENDENCY_CHECKED_ROLES.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_recheck_policy",
        serde_json::Value::String(
            "validate_manifest_digest_route_request_source_fingerprints_artifact_fingerprints_no_fallback_before_reuse"
                .to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_schema_version",
        serde_json::Value::String(PREPARED_STATE_PARTIAL_REPAIR_SCHEMA_VERSION.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_status",
        serde_json::Value::String(
            "blocked_until_dependency_specific_segment_repair_is_admitted".to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_regeneration_performed",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_stale_segment_reuse_allowed",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_delta_overlay_base",
        traditional_prepared_delta_overlay_base_payload(
            &prepare_fields,
            fact_input,
            prepare_report.input_format,
        )?,
    );
    json_object_insert(
        &mut manifest_payload,
        "source_state_id",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "source_state_id")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_state_digest",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "source_state_digest",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_id",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "prepared_state_id",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_digest",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "prepared_state_digest",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "fallback_attempted",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "external_engine_invoked",
        serde_json::Value::Bool(false),
    );
    let manifest_digest = stable_json_value_digest(&manifest_payload);
    json_object_insert(
        &mut manifest_payload,
        "manifest_digest",
        serde_json::Value::String(manifest_digest.clone()),
    );
    write_json_manifest_atomically(&manifest_path, &manifest_payload)?;
    let index_digest = write_prepared_state_index(workspace_dir, &manifest_payload)?;
    Ok(TraditionalPreparedBatchReuseReport::first_preparation(
        manifest_path,
        manifest_digest,
        source_admission_packet_digest,
        source_admission_packet_artifact_manifest_hash,
        index_digest,
        prior_reuse_reason.to_string(),
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_reused_roles_for_repair(
    repaired_role: TraditionalPreparedRepairRole,
    cdc_delta_present: bool,
) -> String {
    [
        TraditionalPreparedRepairRole::Fact,
        TraditionalPreparedRepairRole::Dim,
        TraditionalPreparedRepairRole::CdcDelta,
    ]
    .into_iter()
    .filter(|role| *role != repaired_role)
    .filter(|role| *role != TraditionalPreparedRepairRole::CdcDelta || cdc_delta_present)
    .map(TraditionalPreparedRepairRole::source_role)
    .collect::<Vec<_>>()
    .join(",")
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_invalidated_derived_states_for_repair(
    repaired_role: TraditionalPreparedRepairRole,
) -> &'static str {
    match repaired_role {
        TraditionalPreparedRepairRole::Fact => {
            "fact_source_state_families,prepared_state_digest,source_state_digest"
        }
        TraditionalPreparedRepairRole::Dim => {
            "dimension_label_state,join_derived_state,prepared_state_digest,source_state_digest"
        }
        TraditionalPreparedRepairRole::CdcDelta => {
            "cdc_delta_state,small_change_overlay_state,prepared_state_digest,source_state_digest"
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn write_traditional_prepared_batch_partial_repair_manifest(
    prior_manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
    role_repair: &TraditionalPreparedRoleRepairReport,
    fact_input: &std::path::Path,
    dim_input: &std::path::Path,
    cdc_delta_input: Option<&std::path::Path>,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    reason: &str,
) -> Result<TraditionalPreparedBatchReuseReport> {
    let manifest_path = traditional_prepared_batch_reuse_manifest_path(workspace_dir);
    let mut prepare_fields = prepared_batch_reuse_prepare_fields(prior_manifest_payload);
    apply_prepared_role_repair_fields(
        &mut prepare_fields,
        role_repair,
        request_payload,
        fact_input,
        dim_input,
        cdc_delta_input,
        input_format,
    )?;
    let Some(prior_artifacts) = prior_manifest_payload
        .get("prepared_artifacts")
        .and_then(serde_json::Value::as_object)
    else {
        return Err(ShardLoomError::InvalidOperation(
            "prepared-state partial repair requires prepared_artifacts in the base manifest; fallback execution was not attempted"
                .to_string(),
        ));
    };
    let mut prepared_artifacts = prior_artifacts.clone();
    prepared_artifacts.insert(
        role_repair.role.artifact_role().to_string(),
        prepared_batch_artifact_manifest(
            &role_repair.artifact_path,
            role_repair.role.artifact_role(),
            &role_repair.artifact_digest,
        )?,
    );
    let prepared_artifacts = serde_json::Value::Object(prepared_artifacts);
    let source_admission_packet_artifact_manifest_hash =
        stable_json_value_digest(&prepared_artifacts);
    let source_admission_packet_digest =
        json_string_field(request_payload, "source_admission_packet_digest")
            .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string());
    let mut manifest_payload = prior_manifest_payload.clone();
    if let Some(request_object) = request_payload.as_object() {
        for (key, value) in request_object {
            json_object_insert(&mut manifest_payload, key, value.clone());
        }
    }
    if let Some(object) = manifest_payload.as_object_mut() {
        object.remove("manifest_digest");
    }
    json_object_insert(
        &mut manifest_payload,
        "created_unix_seconds",
        serde_json::Value::Number(serde_json::Number::from(current_unix_seconds())),
    );
    json_object_insert(
        &mut manifest_payload,
        "manifest_path",
        serde_json::Value::String(manifest_path.display().to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepare_command",
        serde_json::Value::String("traditional-analytics-partial-repair".to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepare_fields",
        field_pairs_to_json_object(&prepare_fields),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_artifacts",
        prepared_artifacts,
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_row_estimate_status",
        serde_json::Value::String(
            "observed_after_partial_repair_materialized_changed_role".to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_fact_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "fact_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_dim_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "dim_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_cdc_delta_row_estimate",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "cdc_delta_rows")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_admission_packet_artifact_manifest_hash",
        serde_json::Value::String(source_admission_packet_artifact_manifest_hash.clone()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_schema_version",
        serde_json::Value::String(PREPARED_STATE_DEPENDENCY_SCHEMA_VERSION.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_checked_roles",
        serde_json::Value::String(PREPARED_BATCH_DEPENDENCY_CHECKED_ROLES.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_dependency_recheck_policy",
        serde_json::Value::String(
            "validate_manifest_digest_route_request_source_fingerprints_artifact_fingerprints_no_fallback_before_reuse"
                .to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_schema_version",
        serde_json::Value::String(PREPARED_STATE_PARTIAL_REPAIR_SCHEMA_VERSION.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_status",
        serde_json::Value::String("admitted_role_repair_completed".to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_changed_roles",
        serde_json::Value::String(role_repair.role.source_role().to_string()),
    );
    let cdc_delta_present = cdc_delta_input.is_some();
    let reused_roles = prepared_batch_reused_roles_for_repair(role_repair.role, cdc_delta_present);
    let invalidated_derived_states =
        prepared_batch_invalidated_derived_states_for_repair(role_repair.role);
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_reused_roles",
        serde_json::Value::String(reused_roles.clone()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_repaired_roles",
        serde_json::Value::String(role_repair.role.source_role().to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_invalidated_derived_states",
        serde_json::Value::String(invalidated_derived_states.to_string()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_micros",
        serde_json::Value::String(
            role_repair
                .write_timing
                .array_build_micros
                .saturating_add(role_repair.write_timing.vortex_write_micros)
                .saturating_add(role_repair.replay_verification_micros)
                .to_string(),
        ),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_replay_proof",
        serde_json::Value::String(role_repair.replay_proof.clone()),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_regeneration_performed",
        serde_json::Value::Bool(true),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_partial_repair_stale_segment_reuse_allowed",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_state_id",
        serde_json::Value::String(prepare_field_from_slice(&prepare_fields, "source_state_id")),
    );
    json_object_insert(
        &mut manifest_payload,
        "source_state_digest",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "source_state_digest",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_id",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "prepared_state_id",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "prepared_state_digest",
        serde_json::Value::String(prepare_field_from_slice(
            &prepare_fields,
            "prepared_state_digest",
        )),
    );
    json_object_insert(
        &mut manifest_payload,
        "fallback_attempted",
        serde_json::Value::Bool(false),
    );
    json_object_insert(
        &mut manifest_payload,
        "external_engine_invoked",
        serde_json::Value::Bool(false),
    );
    let manifest_digest = stable_json_value_digest(&manifest_payload);
    json_object_insert(
        &mut manifest_payload,
        "manifest_digest",
        serde_json::Value::String(manifest_digest.clone()),
    );
    write_json_manifest_atomically(&manifest_path, &manifest_payload)?;
    let index_digest = write_prepared_state_index(workspace_dir, &manifest_payload)?;
    Ok(TraditionalPreparedBatchReuseReport::partial_repair(
        manifest_path,
        manifest_digest,
        source_admission_packet_digest,
        source_admission_packet_artifact_manifest_hash,
        index_digest,
        reason.to_string(),
        prepare_fields,
        reused_roles,
        role_repair.role.source_role().to_string(),
        invalidated_derived_states.to_string(),
        role_repair.replay_proof.clone(),
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_reuse_prepare_fields(
    manifest_payload: &serde_json::Value,
) -> Vec<(String, String)> {
    manifest_payload
        .get("prepare_fields")
        .and_then(serde_json::Value::as_object)
        .map_or_else(Vec::new, |fields| {
            fields
                .iter()
                .map(|(key, value)| {
                    (
                        key.clone(),
                        value
                            .as_str()
                            .map_or_else(|| value.to_string(), ToString::to_string),
                    )
                })
                .collect()
        })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn source_admission_packet_digest_from_manifest(manifest_payload: &serde_json::Value) -> String {
    json_string_field(manifest_payload, "source_admission_packet_digest")
        .or_else(|| {
            manifest_payload
                .get("source_admission_packet")
                .and_then(|packet| packet.get("packet_digest"))
                .and_then(serde_json::Value::as_str)
                .map(ToString::to_string)
        })
        .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn source_admission_packet_artifact_manifest_hash_from_manifest(
    manifest_payload: &serde_json::Value,
) -> String {
    json_string_field(
        manifest_payload,
        "source_admission_packet_artifact_manifest_hash",
    )
    .unwrap_or_else(|| "missing_source_admission_packet_artifact_manifest_hash".to_string())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_reuse_artifact_path(
    manifest_payload: &serde_json::Value,
    role: &str,
) -> Result<PathBuf> {
    manifest_payload
        .get("prepared_artifacts")
        .and_then(|artifacts| artifacts.get(role))
        .and_then(|artifact| artifact.get("path"))
        .and_then(serde_json::Value::as_str)
        .filter(|path| !path.is_empty())
        .map(PathBuf::from)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "prepared-state reuse manifest is missing {role} artifact path; fallback execution was not attempted"
            ))
        })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_reuse_optional_artifact_path(
    manifest_payload: &serde_json::Value,
    role: &str,
) -> Option<PathBuf> {
    manifest_payload
        .get("prepared_artifacts")
        .and_then(|artifacts| artifacts.get(role))
        .and_then(|artifact| artifact.get("path"))
        .and_then(serde_json::Value::as_str)
        .filter(|path| !path.is_empty())
        .map(PathBuf::from)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_artifact_manifest(
    path: &std::path::Path,
    role: &str,
    digest: &str,
) -> Result<serde_json::Value> {
    Ok(serde_json::json!({
        "path": path.display().to_string(),
        "fingerprint": local_reuse_path_fingerprint(path, role)?,
        "digest": digest,
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_artifact_invalidation_reason(
    manifest_payload: &serde_json::Value,
) -> Result<String> {
    let Some(artifacts) = manifest_payload
        .get("prepared_artifacts")
        .and_then(serde_json::Value::as_object)
    else {
        return Ok("reuse_manifest_missing_prepared_artifacts".to_string());
    };
    let cdc_required = manifest_payload
        .get("prepare_policy")
        .and_then(|policy| policy.get("cdc_delta_present"))
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false);
    for role in ["fact", "dim", "cdc_delta"] {
        let stored = artifacts.get(role);
        if role == "cdc_delta" && stored.is_none_or(serde_json::Value::is_null) {
            if cdc_required {
                return Ok("cdc_delta_prepared_artifact_manifest_missing".to_string());
            }
            continue;
        }
        let Some(stored) = stored.and_then(serde_json::Value::as_object) else {
            return Ok(format!("{role}_prepared_artifact_manifest_missing"));
        };
        let Some(path) = stored
            .get("path")
            .and_then(serde_json::Value::as_str)
            .filter(|path| !path.is_empty())
        else {
            return Ok(format!("{role}_prepared_artifact_path_missing"));
        };
        let current = local_reuse_path_fingerprint(std::path::Path::new(path), role)?;
        if stored.get("fingerprint") != Some(&current) {
            return Ok(format!("{role}_prepared_artifact_fingerprint_changed"));
        }
    }
    Ok("none".to_string())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TraditionalPreparedRepairRole {
    Fact,
    Dim,
    CdcDelta,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalPreparedRepairRole {
    const fn source_role(self) -> &'static str {
        match self {
            Self::Fact => "fact_input",
            Self::Dim => "dim_input",
            Self::CdcDelta => "cdc_delta_input",
        }
    }

    const fn artifact_role(self) -> &'static str {
        match self {
            Self::Fact => "fact",
            Self::Dim => "dim",
            Self::CdcDelta => "cdc_delta",
        }
    }

    const fn path_filename(self) -> &'static str {
        match self {
            Self::Fact => "fact.vortex",
            Self::Dim => "dim.vortex",
            Self::CdcDelta => "cdc_delta.vortex",
        }
    }

    const fn row_field(self) -> &'static str {
        match self {
            Self::Fact => "fact_rows",
            Self::Dim => "dim_rows",
            Self::CdcDelta => "cdc_delta_rows",
        }
    }

    const fn digest_field(self) -> &'static str {
        match self {
            Self::Fact => "fact_vortex_digest",
            Self::Dim => "dim_vortex_digest",
            Self::CdcDelta => "cdc_delta_vortex_digest",
        }
    }

    const fn bytes_field(self) -> &'static str {
        match self {
            Self::Fact => "fact_vortex_bytes",
            Self::Dim => "dim_vortex_bytes",
            Self::CdcDelta => "cdc_delta_vortex_bytes",
        }
    }

    const fn path_field(self) -> &'static str {
        match self {
            Self::Fact => "fact_vortex_path",
            Self::Dim => "dim_vortex_path",
            Self::CdcDelta => "cdc_delta_vortex_path",
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct TraditionalPreparedRoleRepairReport {
    role: TraditionalPreparedRepairRole,
    artifact_path: PathBuf,
    artifact_digest: String,
    artifact_bytes: u64,
    row_count: u64,
    source_read_evidence: TraditionalSourceReadEvidence,
    write_timing: TraditionalVortexWriteTiming,
    replay_verification_micros: u64,
    replay_proof: String,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_source_changed_roles(
    manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
) -> Vec<TraditionalPreparedRepairRole> {
    [
        (TraditionalPreparedRepairRole::Fact, "fact_input"),
        (TraditionalPreparedRepairRole::Dim, "dim_input"),
        (TraditionalPreparedRepairRole::CdcDelta, "cdc_delta_input"),
    ]
    .into_iter()
    .filter_map(|(role, key)| {
        (manifest_payload.get(key) != request_payload.get(key)).then_some(role)
    })
    .collect()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_single_role_repair_admission(
    manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
) -> Result<Option<TraditionalPreparedRepairRole>> {
    if manifest_payload.get("prepare_policy") != request_payload.get("prepare_policy") {
        return Ok(None);
    }
    if json_bool_field(manifest_payload, "fallback_attempted")
        || json_bool_field(manifest_payload, "external_engine_invoked")
    {
        return Ok(None);
    }
    let artifact_reason = prepared_batch_artifact_invalidation_reason(manifest_payload)?;
    if artifact_reason != "none" {
        return Ok(None);
    }
    let changed_roles = prepared_batch_source_changed_roles(manifest_payload, request_payload);
    Ok(match changed_roles.as_slice() {
        [TraditionalPreparedRepairRole::CdcDelta]
            if manifest_payload
                .get("cdc_delta_input")
                .is_none_or(serde_json::Value::is_null)
                || request_payload
                    .get("cdc_delta_input")
                    .is_none_or(serde_json::Value::is_null) =>
        {
            None
        }
        [role] => Some(*role),
        _ => None,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_delta_overlay_scenario_supported(
    scenario: TraditionalAnalyticsScenario,
) -> bool {
    matches!(
        scenario,
        TraditionalAnalyticsScenario::CsvFileIngest
            | TraditionalAnalyticsScenario::ManySmallFilesScan
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_delta_overlay_manifest_path(workspace_dir: &std::path::Path) -> PathBuf {
    workspace_dir
        .join(PREPARED_STATE_REUSE_MANIFEST_DIR)
        .join(PREPARED_STATE_DELTA_OVERLAY_MANIFEST_FILE)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_delta_overlay_source_path(
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    current_source_digest: &str,
) -> PathBuf {
    let extension = match input_format {
        TraditionalAnalyticsInputFormat::Csv => "csv",
        TraditionalAnalyticsInputFormat::JsonLines => "jsonl",
        _ => "txt",
    };
    let digest_slug = current_source_digest.replace(':', "-");
    workspace_dir
        .join(PREPARED_STATE_REUSE_MANIFEST_DIR)
        .join(format!("fact-append-only-delta-{digest_slug}.{extension}"))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_prepared_delta_overlay_artifact_path(
    workspace_dir: &std::path::Path,
    current_source_digest: &str,
) -> PathBuf {
    let digest_slug = current_source_digest.replace(':', "-");
    workspace_dir
        .join(PREPARED_STATE_REUSE_MANIFEST_DIR)
        .join(format!("fact-append-only-delta-{digest_slug}.vortex"))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn evaluate_and_materialize_traditional_fact_delta_overlay(
    manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
    fact_input: &std::path::Path,
    _dim_input: &std::path::Path,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    scenarios: &[TraditionalAnalyticsScenario],
    reason: &str,
) -> Result<Option<TraditionalPreparedDeltaOverlayReport>> {
    if reason != "fact_input_fingerprint_changed" {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_non_fact_append_only_change",
            "perf-split-9.not-fact-input-fingerprint-change",
        )));
    }
    if manifest_payload.get("prepare_policy") != request_payload.get("prepare_policy") {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_prepare_policy_changed",
            "perf-split-9.prepare-policy-changed",
        )));
    }
    if json_bool_field(manifest_payload, "fallback_attempted")
        || json_bool_field(manifest_payload, "external_engine_invoked")
    {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_manifest_has_external_or_fallback_execution",
            "perf-split-9.no-fallback-policy-violation",
        )));
    }
    if !matches!(
        input_format,
        TraditionalAnalyticsInputFormat::Csv | TraditionalAnalyticsInputFormat::JsonLines
    ) {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_input_format_not_local_text_append_only",
            "perf-split-9.unsupported-input-format",
        )));
    }
    if !fact_input.is_file() {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_fact_input_not_single_local_file",
            "perf-split-9.unsupported-fact-source-shape",
        )));
    }
    if scenarios
        .iter()
        .any(|scenario| !traditional_prepared_delta_overlay_scenario_supported(*scenario))
    {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_consumer_family_not_overlay_mergeable",
            "perf-split-9.consumer-family-not-overlay-mergeable",
        )));
    }
    let changed_roles = prepared_batch_source_changed_roles(manifest_payload, request_payload);
    if changed_roles.as_slice() != [TraditionalPreparedRepairRole::Fact].as_slice() {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_non_single_fact_role_change",
            "perf-split-9.non-single-fact-role-change",
        )));
    }
    let artifact_reason = prepared_batch_artifact_invalidation_reason(manifest_payload)?;
    if artifact_reason != "none" {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            format!("blocked_prepared_artifact_dependency_changed:{artifact_reason}"),
            "perf-split-9.prepared-artifact-dependency-changed",
        )));
    }
    let Some(base_overlay_payload) = manifest_payload
        .get("prepared_state_delta_overlay_base")
        .and_then(serde_json::Value::as_object)
    else {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_base_manifest_missing_delta_overlay_source_digest",
            "perf-split-9.base-content-digest-missing",
        )));
    };
    let base_source_content_digest = base_overlay_payload
        .get("base_source_content_digest")
        .and_then(serde_json::Value::as_str)
        .unwrap_or_default()
        .to_string();
    if !base_source_content_digest.starts_with("sha256:") {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_base_manifest_invalid_delta_overlay_source_digest",
            "perf-split-9.base-content-digest-invalid",
        )));
    }
    let base_source_size_bytes = base_overlay_payload
        .get("base_source_size_bytes")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);
    if base_source_size_bytes == 0 {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_base_manifest_missing_delta_overlay_source_size",
            "perf-split-9.base-size-missing",
        )));
    }
    let base_row_count = base_overlay_payload
        .get("base_fact_row_count")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);
    let current_size_bytes = file_len(fact_input, "fact append-only source")?;
    if current_size_bytes <= base_source_size_bytes {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_current_source_not_larger_than_base",
            "perf-split-9.not-append-only-growth",
        )));
    }
    if base_source_size_bytes > 0 {
        let previous_byte = byte_at_file_offset(
            fact_input,
            base_source_size_bytes.saturating_sub(1),
            "fact append-only source",
        )?;
        if previous_byte != b'\n' {
            return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
                "blocked_base_prefix_does_not_end_on_record_boundary",
                "perf-split-9.prefix-record-boundary",
            )));
        }
    }
    let digest_start = std::time::Instant::now();
    let prefix_digest = file_sha256_prefix_digest(
        fact_input,
        base_source_size_bytes,
        "fact append-only source prefix",
    )?;
    if prefix_digest != base_source_content_digest {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_prefix_digest_mismatch",
            "perf-split-9.prefix-digest-mismatch",
        )));
    }
    let current_source_content_digest =
        file_sha256_digest(fact_input, "fact append-only current source")?;
    let content_digest_micros = duration_to_micros(digest_start.elapsed());
    if current_source_content_digest == base_source_content_digest {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_current_source_digest_matches_base",
            "perf-split-9.no-content-change",
        )));
    }
    let delta_source_write_start = std::time::Instant::now();
    let delta_source_path = write_traditional_prepared_batch_delta_source(
        fact_input,
        input_format,
        workspace_dir,
        base_source_size_bytes,
        &current_source_content_digest,
    )?;
    let delta_source_write_micros = duration_to_micros(delta_source_write_start.elapsed());
    let delta_source_digest =
        file_sha256_digest(&delta_source_path, "fact append-only delta source")?;
    let delta_artifact_path = traditional_prepared_delta_overlay_artifact_path(
        workspace_dir,
        &current_source_content_digest,
    );
    let delta_artifact_write_start = std::time::Instant::now();
    let delta_artifact = write_traditional_prepared_batch_delta_artifact(
        &delta_source_path,
        &delta_artifact_path,
        input_format,
        resource_policy,
    )?;
    let delta_artifact_write_micros = duration_to_micros(delta_artifact_write_start.elapsed());
    let base_artifact_ref = prepared_batch_reuse_artifact_path(manifest_payload, "fact")?;
    let base_artifact_digest = manifest_payload
        .pointer("/prepared_artifacts/fact/digest")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("missing_base_fact_artifact_digest")
        .to_string();
    let dim_vortex = prepared_batch_reuse_artifact_path(manifest_payload, "dim")?;
    let dim_rows = vortex_file_row_count(&dim_vortex)?;
    let replay_start = std::time::Instant::now();
    let replay = run_vortex_derived_scenario_from_files_with_fact_delta_overlay(
        TraditionalAnalyticsScenario::CsvFileIngest,
        &base_artifact_ref,
        &delta_artifact.artifact_path,
        dim_rows,
    )?;
    let replay_verification_micros = duration_to_micros(replay_start.elapsed());
    let current_row_count = checked_u64_sum(base_row_count, delta_artifact.row_count)?;
    if replay.fact_rows != current_row_count {
        return Ok(Some(TraditionalPreparedDeltaOverlayReport::blocked(
            "blocked_overlay_replay_row_count_mismatch",
            "perf-split-9.overlay-replay-row-count-mismatch",
        )));
    }
    let correctness_digest = route_evidence_digest(&[
        "prepared_state_delta_overlay_correctness",
        replay.result_json.as_str(),
        &base_artifact_digest,
        &delta_artifact.artifact_digest,
        &base_row_count.to_string(),
        &delta_artifact.row_count.to_string(),
        &current_row_count.to_string(),
    ]);
    let replay_proof = route_evidence_digest(&[
        "prepared_state_delta_overlay_replay",
        &correctness_digest,
        &current_source_content_digest,
        &delta_source_digest,
    ]);
    Ok(Some(TraditionalPreparedDeltaOverlayReport::admitted(
        traditional_prepared_delta_overlay_manifest_path(workspace_dir),
        "pending_manifest_digest".to_string(),
        json_string_field(manifest_payload, "manifest_digest").unwrap_or_default(),
        json_string_field(manifest_payload, "prepared_state_digest").unwrap_or_default(),
        base_artifact_ref.display().to_string(),
        base_artifact_digest,
        base_source_content_digest,
        current_source_content_digest,
        delta_source_path,
        delta_source_digest,
        delta_artifact.artifact_path,
        delta_artifact.artifact_digest,
        delta_artifact.artifact_bytes,
        base_source_size_bytes,
        current_size_bytes,
        base_row_count,
        delta_artifact.row_count,
        correctness_digest,
        replay_proof,
        content_digest_micros,
        delta_source_write_micros,
        delta_artifact_write_micros,
        replay_verification_micros,
    )))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct TraditionalPreparedDeltaArtifactReport {
    artifact_path: PathBuf,
    artifact_digest: String,
    artifact_bytes: u64,
    row_count: u64,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn write_traditional_prepared_batch_delta_artifact(
    delta_source_path: &std::path::Path,
    delta_artifact_path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    _resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<TraditionalPreparedDeltaArtifactReport> {
    let delta_source_bytes = file_len(delta_source_path, "fact append-only delta source")?;
    let source = read_traditional_fact_text_vortex_provider_batch_with_evidence(
        delta_source_path,
        input_format,
        delta_source_bytes,
        TraditionalAnalyticsScenario::CsvFileIngest,
        TraditionalFactTextColumnSelection::full(),
    )?;
    let row_count = usize_to_u64(source.row_count)?;
    let vortex_io = TraditionalVortexIoContext::new();
    let write_timing = write_vortex_text_record_batch_with_io(
        &vortex_io,
        source.batch,
        "traditional fact append-only delta overlay",
        delta_artifact_path,
    )?;
    Ok(TraditionalPreparedDeltaArtifactReport {
        artifact_path: delta_artifact_path.to_path_buf(),
        artifact_digest: vortex_write_artifact_digest(&write_timing, "fact_delta_overlay")?,
        artifact_bytes: vortex_write_artifact_bytes(&write_timing, "fact_delta_overlay")?,
        row_count,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn write_traditional_prepared_batch_delta_source(
    source_path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    workspace_dir: &std::path::Path,
    delta_start: u64,
    current_source_digest: &str,
) -> Result<PathBuf> {
    let bytes = std::fs::read(source_path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to read prepared-state append-only source '{}': {error}; fallback execution was not attempted",
            source_path.display()
        ))
    })?;
    let delta_start = usize::try_from(delta_start).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "prepared-state append-only delta offset does not fit usize: {error}; fallback execution was not attempted"
        ))
    })?;
    if delta_start >= bytes.len() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "prepared-state append-only delta source '{}' contains no delta bytes; fallback execution was not attempted",
            source_path.display()
        )));
    }
    let content = std::str::from_utf8(&bytes).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "prepared-state append-only delta source '{}' must be UTF-8: {error}; fallback execution was not attempted",
            source_path.display()
        ))
    })?;
    let delta_text = std::str::from_utf8(&bytes[delta_start..]).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "prepared-state append-only delta bytes for '{}' must be UTF-8: {error}; fallback execution was not attempted",
            source_path.display()
        ))
    })?;
    let delta_payload = match input_format {
        TraditionalAnalyticsInputFormat::Csv => {
            let header_end = content.find('\n').ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "prepared-state CSV append-only delta source '{}' requires a header line; fallback execution was not attempted",
                    source_path.display()
                ))
            })?;
            let header = content[..header_end].trim_end_matches('\r');
            let body = delta_text.trim_start_matches(['\n', '\r']);
            if body.trim().is_empty() {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "prepared-state CSV append-only delta source '{}' has no non-empty delta rows; fallback execution was not attempted",
                    source_path.display()
                )));
            }
            format!("{header}\n{body}")
        }
        TraditionalAnalyticsInputFormat::JsonLines => {
            let body = delta_text.trim_start_matches(['\n', '\r']);
            if body.trim().is_empty() {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "prepared-state JSONL append-only delta source '{}' has no non-empty delta rows; fallback execution was not attempted",
                    source_path.display()
                )));
            }
            body.to_string()
        }
        _ => {
            return Err(ShardLoomError::InvalidOperation(format!(
                "prepared-state append-only delta source supports CSV/JSONL only, not {}; fallback execution was not attempted",
                input_format.as_str()
            )));
        }
    };
    let delta_path = traditional_prepared_delta_overlay_source_path(
        workspace_dir,
        input_format,
        current_source_digest,
    );
    let Some(parent) = delta_path.parent() else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "prepared-state append-only delta source path '{}' has no parent; fallback execution was not attempted",
            delta_path.display()
        )));
    };
    std::fs::create_dir_all(parent).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to create prepared-state append-only delta directory '{}': {error}; fallback execution was not attempted",
            parent.display()
        ))
    })?;
    std::fs::write(&delta_path, delta_payload).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to write prepared-state append-only delta source '{}': {error}; fallback execution was not attempted",
            delta_path.display()
        ))
    })?;
    Ok(delta_path)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn write_traditional_prepared_batch_delta_overlay_manifest(
    prior_manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
    workspace_dir: &std::path::Path,
    reason: &str,
    mut delta_overlay: TraditionalPreparedDeltaOverlayReport,
) -> Result<TraditionalPreparedBatchReuseReport> {
    let manifest_path = traditional_prepared_delta_overlay_manifest_path(workspace_dir);
    let mut prepare_fields = prepared_batch_reuse_prepare_fields(prior_manifest_payload);
    set_field(
        &mut prepare_fields,
        "timing_scope",
        "workspace_manifest_delta_overlay",
    );
    set_field(
        &mut prepare_fields,
        "fact_rows",
        delta_overlay.current_row_count.to_string(),
    );
    set_field(
        &mut prepare_fields,
        "fact_delta_overlay_vortex_path",
        delta_overlay
            .delta_artifact_path
            .as_ref()
            .map_or_else(String::new, |path| path.display().to_string()),
    );
    set_field(
        &mut prepare_fields,
        "fact_delta_overlay_vortex_digest",
        delta_overlay.delta_artifact_digest.clone(),
    );
    set_field(
        &mut prepare_fields,
        "fact_delta_overlay_vortex_bytes",
        delta_overlay.delta_artifact_bytes.to_string(),
    );
    set_field(
        &mut prepare_fields,
        "source_read_micros",
        delta_overlay
            .content_digest_micros
            .saturating_add(delta_overlay.delta_source_write_micros)
            .to_string(),
    );
    set_field(
        &mut prepare_fields,
        "vortex_write_micros",
        delta_overlay.delta_artifact_write_micros.to_string(),
    );
    set_field(
        &mut prepare_fields,
        "vortex_reopen_verify_micros",
        delta_overlay.replay_verification_micros.to_string(),
    );
    set_field(
        &mut prepare_fields,
        "total_runtime_micros",
        delta_overlay
            .content_digest_micros
            .saturating_add(delta_overlay.delta_source_write_micros)
            .saturating_add(delta_overlay.delta_artifact_write_micros)
            .saturating_add(delta_overlay.replay_verification_micros)
            .to_string(),
    );
    let source_state_digest = route_evidence_digest(&[
        "source_state_delta_overlay",
        &delta_overlay.base_source_content_digest,
        &delta_overlay.current_source_content_digest,
        &delta_overlay.base_artifact_digest,
        &delta_overlay.delta_artifact_digest,
        &delta_overlay.current_row_count.to_string(),
    ]);
    set_field(
        &mut prepare_fields,
        "source_state_id",
        format!("source-state://traditional-analytics/{source_state_digest}"),
    );
    set_field(
        &mut prepare_fields,
        "source_state_digest",
        source_state_digest.clone(),
    );
    let dim_digest = prepare_field_from_slice(&prepare_fields, "dim_vortex_digest");
    let cdc_delta_digest = prepare_field_from_slice(&prepare_fields, "cdc_delta_vortex_digest");
    let prepared_state_digest = route_evidence_digest(&[
        "prepared_state_delta_overlay",
        &delta_overlay.base_artifact_digest,
        &delta_overlay.delta_artifact_digest,
        dim_digest.as_str(),
        if cdc_delta_digest.is_empty() {
            "none"
        } else {
            cdc_delta_digest.as_str()
        },
    ]);
    set_field(
        &mut prepare_fields,
        "prepared_state_id",
        format!("prepared-state://traditional-analytics/{prepared_state_digest}"),
    );
    set_field(
        &mut prepare_fields,
        "prepared_state_digest",
        prepared_state_digest.clone(),
    );
    let source_admission_packet_digest =
        json_string_field(request_payload, "source_admission_packet_digest")
            .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string());
    let base_artifacts = prior_manifest_payload
        .get("prepared_artifacts")
        .cloned()
        .unwrap_or_else(|| serde_json::json!({}));
    let mut prepared_artifacts = base_artifacts.as_object().cloned().unwrap_or_default();
    prepared_artifacts.insert(
        "fact_delta_overlay".to_string(),
        prepared_batch_artifact_manifest(
            delta_overlay
                .delta_artifact_path
                .as_deref()
                .ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "admitted prepared-state delta overlay missing delta artifact path; fallback execution was not attempted"
                            .to_string(),
                    )
                })?,
            "fact append-only delta overlay",
            &delta_overlay.delta_artifact_digest,
        )?,
    );
    let prepared_artifacts = serde_json::Value::Object(prepared_artifacts);
    let source_admission_packet_artifact_manifest_hash =
        stable_json_value_digest(&prepared_artifacts);
    let mut manifest_payload = serde_json::json!({
        "schema_version": PREPARED_STATE_DELTA_OVERLAY_SCHEMA_VERSION,
        "created_unix_seconds": current_unix_seconds(),
        "manifest_path": manifest_path.display().to_string(),
        "base_reuse_manifest_digest": json_string_field(prior_manifest_payload, "manifest_digest").unwrap_or_default(),
        "route_request_digest": json_string_field(request_payload, "route_request_digest").unwrap_or_default(),
        "prepare_policy": request_payload
            .get("prepare_policy")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({})),
        "source_admission_packet_digest": source_admission_packet_digest,
        "source_admission_packet_artifact_manifest_hash": source_admission_packet_artifact_manifest_hash.clone(),
        "reason": reason,
        "prepare_fields": field_pairs_to_json_object(&prepare_fields),
        "prepared_artifacts": prepared_artifacts,
        "delta_overlay": {
            "status": delta_overlay.status.clone(),
            "admitted": delta_overlay.admitted,
            "blocker_id": delta_overlay.blocker_id.clone(),
            "base_prepared_state_digest": delta_overlay.base_prepared_state_digest.clone(),
            "base_artifact_ref": delta_overlay.base_artifact_ref.clone(),
            "base_artifact_digest": delta_overlay.base_artifact_digest.clone(),
            "base_source_content_digest": delta_overlay.base_source_content_digest.clone(),
            "current_source_content_digest": delta_overlay.current_source_content_digest.clone(),
            "delta_source_path": delta_overlay.delta_source_path.as_ref().map(|path| path.display().to_string()).unwrap_or_default(),
            "delta_source_digest": delta_overlay.delta_source_digest.clone(),
            "delta_artifact_path": delta_overlay.delta_artifact_path.as_ref().map(|path| path.display().to_string()).unwrap_or_default(),
            "delta_artifact_digest": delta_overlay.delta_artifact_digest.clone(),
            "delta_artifact_bytes": delta_overlay.delta_artifact_bytes,
            "base_source_size_bytes": delta_overlay.base_source_size_bytes,
            "current_source_size_bytes": delta_overlay.current_source_size_bytes,
            "delta_byte_start": delta_overlay.delta_byte_start,
            "delta_byte_end": delta_overlay.delta_byte_end,
            "base_row_count": delta_overlay.base_row_count,
            "delta_row_count": delta_overlay.delta_row_count,
            "current_row_count": delta_overlay.current_row_count,
            "schema_hash": delta_overlay.schema_hash.clone(),
            "route_family": delta_overlay.route_family.clone(),
            "consumer_family": delta_overlay.consumer_family.clone(),
            "consumer_status": delta_overlay.consumer_status.clone(),
            "correctness_digest": delta_overlay.correctness_digest.clone(),
            "replay_proof": delta_overlay.replay_proof.clone(),
            "fallback_attempted": false,
            "external_engine_invoked": false,
        },
        "fallback_attempted": false,
        "external_engine_invoked": false,
    });
    let manifest_digest = stable_json_value_digest(&manifest_payload);
    json_object_insert(
        &mut manifest_payload,
        "manifest_digest",
        serde_json::Value::String(manifest_digest.clone()),
    );
    write_json_manifest_atomically(&manifest_path, &manifest_payload)?;
    let index_digest = write_prepared_state_index(workspace_dir, &manifest_payload)?;
    delta_overlay.manifest_digest.clone_from(&manifest_digest);
    delta_overlay.manifest_path = Some(manifest_path.clone());
    Ok(TraditionalPreparedBatchReuseReport::delta_overlay(
        manifest_path,
        manifest_digest,
        json_string_field(request_payload, "source_admission_packet_digest")
            .unwrap_or_else(|| "missing_source_admission_packet_digest".to_string()),
        source_admission_packet_artifact_manifest_hash,
        index_digest,
        reason.to_string(),
        prepare_fields,
        delta_overlay,
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_lines)]
fn repair_traditional_prepared_role(
    role: TraditionalPreparedRepairRole,
    fact_input: &std::path::Path,
    dim_input: &std::path::Path,
    cdc_delta_input: Option<&std::path::Path>,
    workspace_dir: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<TraditionalPreparedRoleRepairReport> {
    let fact_source_bytes = fact_source_len(fact_input, input_format, "fact input")?;
    let dim_source_bytes = file_len(dim_input, "dimension input")?;
    let cdc_delta_source_bytes =
        cdc_delta_input.map_or(Ok(0), |path| file_len(path, "CDC delta input"))?;
    let total_source_bytes = checked_u64_sum(
        checked_u64_sum(fact_source_bytes, dim_source_bytes)?,
        cdc_delta_source_bytes,
    )?;
    let resolved_policy = resource_policy.resolve_for_sources(total_source_bytes);
    let vortex_io = TraditionalVortexIoContext::new();
    let artifact_path = workspace_dir.join(role.path_filename());
    let (source_read_evidence, row_count, write_timing) = match role {
        TraditionalPreparedRepairRole::Fact if input_format.is_columnar() => {
            let source = read_traditional_fact_vortex_provider_batch_with_evidence(
                fact_input,
                input_format,
                resolved_policy,
                TraditionalAnalyticsScenario::CsvFileIngest,
                TraditionalFactTextColumnSelection::full(),
            )?;
            let row_count = usize_to_u64(source.row_count)?;
            let timing = write_vortex_provider_record_batch_with_io(
                &vortex_io,
                source.batch,
                "traditional fact table",
                &artifact_path,
            )?;
            (source.evidence, row_count, timing)
        }
        TraditionalPreparedRepairRole::Fact => {
            let source = read_traditional_fact_text_vortex_provider_batch_with_evidence(
                fact_input,
                input_format,
                fact_source_bytes,
                TraditionalAnalyticsScenario::CsvFileIngest,
                TraditionalFactTextColumnSelection::full(),
            )?;
            let row_count = usize_to_u64(source.row_count)?;
            let timing = write_vortex_text_record_batch_with_io(
                &vortex_io,
                source.batch,
                "traditional fact table",
                &artifact_path,
            )?;
            (source.evidence, row_count, timing)
        }
        TraditionalPreparedRepairRole::Dim if input_format.is_columnar() => {
            let source = read_traditional_dim_vortex_provider_batch_with_evidence(
                dim_input,
                input_format,
                resolved_policy,
            )?;
            let row_count = usize_to_u64(source.row_count)?;
            let timing = write_vortex_provider_record_batch_with_io(
                &vortex_io,
                source.batch,
                "traditional dimension table",
                &artifact_path,
            )?;
            (source.evidence, row_count, timing)
        }
        TraditionalPreparedRepairRole::Dim => {
            let source = read_traditional_dim_text_vortex_provider_batch_with_evidence(
                dim_input,
                input_format,
                dim_source_bytes,
            )?;
            let row_count = usize_to_u64(source.row_count)?;
            let timing = write_vortex_text_record_batch_with_io(
                &vortex_io,
                source.batch,
                "traditional dimension table",
                &artifact_path,
            )?;
            (source.evidence, row_count, timing)
        }
        TraditionalPreparedRepairRole::CdcDelta => {
            let cdc_delta_input = cdc_delta_input.ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "CDC delta prepared-state partial repair requires an explicit CDC delta input; fallback execution was not attempted"
                        .to_string(),
                )
            })?;
            let source = read_traditional_cdc_delta_csv_with_evidence(cdc_delta_input)?;
            let row_count = usize_to_u64(source.rows.len())?;
            let timing = write_cdc_delta_vortex_with_io(&vortex_io, &source.rows, &artifact_path)?;
            (source.evidence, row_count, timing)
        }
    };
    let artifact_digest = vortex_write_artifact_digest(&write_timing, role.artifact_role())?;
    let artifact_bytes = vortex_write_artifact_bytes(&write_timing, role.artifact_role())?;
    let replay_start = std::time::Instant::now();
    match role {
        TraditionalPreparedRepairRole::Fact => {
            std::mem::drop(read_fact_vortex(&artifact_path)?);
        }
        TraditionalPreparedRepairRole::Dim => {
            std::mem::drop(read_dim_vortex(&artifact_path)?);
        }
        TraditionalPreparedRepairRole::CdcDelta => {
            std::mem::drop(read_cdc_delta_vortex(&artifact_path)?);
        }
    }
    let replay_verification_micros = duration_to_micros(replay_start.elapsed());
    let replay_proof = route_evidence_digest(&[
        "prepared_state_partial_repair_replay",
        role.source_role(),
        artifact_digest.as_str(),
        &row_count.to_string(),
    ]);
    Ok(TraditionalPreparedRoleRepairReport {
        role,
        artifact_path,
        artifact_digest,
        artifact_bytes,
        row_count,
        source_read_evidence,
        write_timing,
        replay_verification_micros,
        replay_proof,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_lines)]
fn apply_prepared_role_repair_fields(
    prepare_fields: &mut Vec<(String, String)>,
    role_repair: &TraditionalPreparedRoleRepairReport,
    request_payload: &serde_json::Value,
    fact_input: &std::path::Path,
    dim_input: &std::path::Path,
    cdc_delta_input: Option<&std::path::Path>,
    input_format: TraditionalAnalyticsInputFormat,
) -> Result<()> {
    set_field(
        prepare_fields,
        role_repair.role.path_field(),
        role_repair.artifact_path.display().to_string(),
    );
    set_field(
        prepare_fields,
        role_repair.role.digest_field(),
        role_repair.artifact_digest.clone(),
    );
    set_field(
        prepare_fields,
        role_repair.role.bytes_field(),
        role_repair.artifact_bytes.to_string(),
    );
    set_field(
        prepare_fields,
        role_repair.role.row_field(),
        role_repair.row_count.to_string(),
    );
    set_field(prepare_fields, "input_format", input_format.as_str());
    set_field(
        prepare_fields,
        "source_read_micros",
        role_repair.source_read_evidence.read_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "source_parse_micros",
        role_repair.source_read_evidence.parse_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "source_to_columnar_micros",
        role_repair.source_read_evidence.columnar_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_array_build_micros",
        role_repair.write_timing.array_build_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_write_micros",
        role_repair.write_timing.vortex_write_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_reopen_verify_micros",
        role_repair.replay_verification_micros.to_string(),
    );
    set_field(prepare_fields, "vortex_reopen_scan_micros", "0");
    set_field(
        prepare_fields,
        "vortex_writer_context_open_micros",
        role_repair
            .write_timing
            .writer_context_open_micros
            .to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_writer_context_write_count",
        role_repair
            .write_timing
            .writer_context_write_count
            .to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_writer_context_reuse_hit_count",
        role_repair
            .write_timing
            .writer_context_reuse_hit_count
            .to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_writer_context_reuse_status",
        role_repair.write_timing.writer_context_reuse_status(),
    );
    set_field(
        prepare_fields,
        "vortex_segment_write_micros",
        role_repair.write_timing.segment_write_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_workspace_stage_micros",
        role_repair.write_timing.workspace_stage_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_write_coalescing_status",
        role_repair.write_timing.write_coalescing_status(),
    );
    set_field(
        prepare_fields,
        "vortex_write_coalescing_reason",
        role_repair.write_timing.write_coalescing_reason(),
    );
    set_field(
        prepare_fields,
        "vortex_array_build_strategy",
        role_repair.write_timing.array_build_strategy,
    );
    set_field(
        prepare_fields,
        "vortex_array_build_input_layout",
        role_repair.write_timing.array_build_input_layout,
    );
    set_field(
        prepare_fields,
        "vortex_array_build_provider_kind",
        role_repair.write_timing.array_build_provider_kind,
    );
    set_field(
        prepare_fields,
        "vortex_array_build_provider_surface",
        role_repair.write_timing.array_build_provider_surface,
    );
    set_field(
        prepare_fields,
        "vortex_array_build_record_batch_count",
        role_repair
            .write_timing
            .array_build_record_batch_count
            .to_string(),
    );
    set_field(
        prepare_fields,
        "vortex_array_build_manual_scalar_copy_avoided",
        role_repair
            .write_timing
            .manual_scalar_copy_avoided
            .to_string(),
    );
    let total_runtime_micros = role_repair
        .source_read_evidence
        .read_micros
        .saturating_add(role_repair.source_read_evidence.parse_micros)
        .saturating_add(role_repair.source_read_evidence.columnar_micros)
        .saturating_add(role_repair.write_timing.array_build_micros)
        .saturating_add(role_repair.write_timing.vortex_write_micros)
        .saturating_add(role_repair.replay_verification_micros);
    set_field(
        prepare_fields,
        "total_runtime_micros",
        total_runtime_micros.to_string(),
    );
    set_field(
        prepare_fields,
        "timing_scope",
        "workspace_manifest_partial_repair_role_scoped",
    );
    let fact_source_bytes = fact_source_len(fact_input, input_format, "fact input")?;
    let dim_source_bytes = file_len(dim_input, "dimension input")?;
    let cdc_delta_source_bytes =
        cdc_delta_input.map_or(Ok(0), |path| file_len(path, "CDC delta input"))?;
    let fact_source_bytes_text = fact_source_bytes.to_string();
    let dim_source_bytes_text = dim_source_bytes.to_string();
    let cdc_delta_source_bytes_text = cdc_delta_source_bytes.to_string();
    let source_state_digest = route_evidence_digest(&[
        "source_state",
        input_format.as_str(),
        &fact_input.display().to_string(),
        &dim_input.display().to_string(),
        &fact_source_bytes_text,
        &dim_source_bytes_text,
        &cdc_delta_source_bytes_text,
        TRADITIONAL_FACT_SCHEMA_SUMMARY,
        TRADITIONAL_DIM_SCHEMA_SUMMARY,
    ]);
    set_field(
        prepare_fields,
        "source_state_id",
        format!("source-state://traditional-analytics/{source_state_digest}"),
    );
    set_field(
        prepare_fields,
        "source_state_digest",
        source_state_digest.clone(),
    );
    let fact_digest = prepare_field_from_slice(prepare_fields, "fact_vortex_digest");
    let dim_digest = prepare_field_from_slice(prepare_fields, "dim_vortex_digest");
    let cdc_delta_digest = prepare_field_from_slice(prepare_fields, "cdc_delta_vortex_digest");
    let prepared_state_digest = route_evidence_digest(&[
        "prepared_state",
        fact_digest.as_str(),
        dim_digest.as_str(),
        if cdc_delta_digest.is_empty() {
            "none"
        } else {
            cdc_delta_digest.as_str()
        },
    ]);
    set_field(
        prepare_fields,
        "prepared_state_id",
        format!("prepared-state://traditional-analytics/{prepared_state_digest}"),
    );
    set_field(
        prepare_fields,
        "prepared_state_digest",
        prepared_state_digest.clone(),
    );
    let combined_output_digest = combined_artifact_digest(
        fact_digest.as_str(),
        dim_digest.as_str(),
        (!cdc_delta_digest.is_empty()).then_some(cdc_delta_digest.as_str()),
        None,
    );
    set_field(
        prepare_fields,
        "combined_output_digest",
        combined_output_digest,
    );
    let request_digest =
        json_string_field(request_payload, "route_request_digest").unwrap_or_default();
    set_field(
        prepare_fields,
        "prepared_state_partial_repair_request_digest",
        request_digest,
    );
    set_field(prepare_fields, "fallback_attempted", "false");
    set_field(prepare_fields, "external_engine_invoked", "false");
    Ok(())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_request_invalidation_reason(
    manifest_payload: &serde_json::Value,
    request_payload: &serde_json::Value,
) -> String {
    for key in ["fact_input", "dim_input", "cdc_delta_input"] {
        if manifest_payload.get(key) != request_payload.get(key) {
            return format!("{key}_fingerprint_changed");
        }
    }
    if manifest_payload.get("prepare_policy") != request_payload.get("prepare_policy") {
        return "prepare_policy_changed".to_string();
    }
    if manifest_payload.get("source_admission_packet_digest")
        != request_payload.get("source_admission_packet_digest")
    {
        return "source_admission_packet_changed".to_string();
    }
    "route_request_digest_mismatch".to_string()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn ensure_prepared_batch_request_payload_unchanged_after_prepare(
    pre_prepare_request_payload: &serde_json::Value,
    post_prepare_request_payload: &serde_json::Value,
) -> Result<()> {
    if pre_prepare_request_payload.get("route_request_digest")
        == post_prepare_request_payload.get("route_request_digest")
    {
        return Ok(());
    }
    let reason = prepared_batch_request_invalidation_reason(
        pre_prepare_request_payload,
        post_prepare_request_payload,
    );
    let pre_digest =
        json_string_field(pre_prepare_request_payload, "route_request_digest").unwrap_or_default();
    let post_digest =
        json_string_field(post_prepare_request_payload, "route_request_digest").unwrap_or_default();
    Err(ShardLoomError::InvalidOperation(format!(
        "prepared-state full-register source admission packet changed during preparation ({reason}: {pre_digest} -> {post_digest}); reuse manifest was not published and fallback execution was not attempted"
    )))
}

fn prepared_batch_dependency_status(workspace_reuse_hit: bool, reason: &str) -> &'static str {
    if workspace_reuse_hit {
        return "manifest_dependencies_matched";
    }
    if reason == "no_reuse_manifest" {
        return "manifest_missing_first_preparation";
    }
    if prepared_batch_dependency_changed_roles(reason).contains("prepared_artifact_") {
        return "prepared_artifact_dependency_changed_full_reprepare";
    }
    match reason {
        "fact_input_fingerprint_changed"
        | "dim_input_fingerprint_changed"
        | "cdc_delta_input_fingerprint_changed" => "source_dependency_changed_full_reprepare",
        "prepare_policy_changed"
        | "source_admission_packet_changed"
        | "route_request_digest_mismatch" => "route_dependency_changed_full_reprepare",
        reason
            if reason.starts_with("reuse_manifest_")
                || reason == "reuse_manifest_fallback_attempted"
                || reason == "reuse_manifest_external_engine_invoked" =>
        {
            "manifest_integrity_blocked_full_reprepare"
        }
        _ => "dependency_changed_full_reprepare",
    }
}

fn prepared_batch_dependency_changed_roles(reason: &str) -> &'static str {
    match reason {
        "manifest_fingerprints_match" | "none" => "none",
        "no_reuse_manifest" => "workspace_manifest",
        "fact_input_fingerprint_changed" => "fact_input",
        "dim_input_fingerprint_changed" => "dim_input",
        "cdc_delta_input_fingerprint_changed" => "cdc_delta_input",
        "prepare_policy_changed" => "prepare_policy",
        "source_admission_packet_changed" => "source_admission_packet",
        "route_request_digest_mismatch" => "route_request",
        reason if reason.starts_with("fact_prepared_artifact_") => "prepared_artifact_fact",
        reason if reason.starts_with("dim_prepared_artifact_") => "prepared_artifact_dim",
        reason if reason.starts_with("cdc_delta_prepared_artifact_") => {
            "prepared_artifact_cdc_delta"
        }
        reason if reason.starts_with("reuse_manifest_") => "workspace_manifest",
        _ => "unknown_dependency",
    }
}

fn prepared_batch_partial_repair_status(workspace_reuse_hit: bool, reason: &str) -> &'static str {
    if workspace_reuse_hit {
        return "not_needed_manifest_hit";
    }
    match prepared_batch_dependency_status(false, reason) {
        "manifest_missing_first_preparation" => {
            "blocked_missing_base_manifest_full_prepare_required"
        }
        "source_dependency_changed_full_reprepare" => {
            "blocked_source_dependency_changed_full_reprepare_required"
        }
        "prepared_artifact_dependency_changed_full_reprepare" => {
            "blocked_prepared_artifact_dependency_changed_full_reprepare_required"
        }
        "route_dependency_changed_full_reprepare" => {
            "blocked_route_dependency_changed_full_reprepare_required"
        }
        "manifest_integrity_blocked_full_reprepare" => {
            "blocked_manifest_integrity_full_reprepare_required"
        }
        _ => "blocked_unknown_dependency_full_reprepare_required",
    }
}

fn prepared_batch_partial_repair_blocker_id(
    workspace_reuse_hit: bool,
    reason: &str,
) -> &'static str {
    if workspace_reuse_hit {
        return "not_applicable_manifest_dependencies_matched";
    }
    match prepared_batch_dependency_status(false, reason) {
        "manifest_missing_first_preparation" => "hotpath-9.missing-base-manifest",
        "source_dependency_changed_full_reprepare" => {
            "hotpath-9.source-dependency-changed-no-partial-repair"
        }
        "prepared_artifact_dependency_changed_full_reprepare" => {
            "hotpath-9.prepared-artifact-dependency-changed-no-partial-repair"
        }
        "route_dependency_changed_full_reprepare" => {
            "hotpath-9.route-dependency-changed-no-partial-repair"
        }
        "manifest_integrity_blocked_full_reprepare" => {
            "hotpath-9.manifest-integrity-blocked-no-partial-repair"
        }
        _ => "hotpath-9.unknown-dependency-no-partial-repair",
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepared_batch_manifest_digest(manifest_payload: &serde_json::Value) -> String {
    let mut payload_without_digest = manifest_payload.clone();
    if let Some(object) = payload_without_digest.as_object_mut() {
        object.remove("manifest_digest");
    }
    stable_json_value_digest(&payload_without_digest)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn stable_json_value_digest(value: &serde_json::Value) -> String {
    let encoded = serde_json::to_vec(value).unwrap_or_else(|_| b"invalid-json".to_vec());
    sha256_digest(&encoded)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn field_pairs_to_json_object(fields: &[(String, String)]) -> serde_json::Value {
    let mut object = serde_json::Map::new();
    for (key, value) in fields {
        object.insert(key.clone(), serde_json::Value::String(value.clone()));
    }
    serde_json::Value::Object(object)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn json_object_insert(value: &mut serde_json::Value, key: &str, field_value: serde_json::Value) {
    if let Some(object) = value.as_object_mut() {
        object.insert(key.to_string(), field_value);
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn json_string_field(value: &serde_json::Value, key: &str) -> Option<String> {
    value
        .get(key)
        .and_then(serde_json::Value::as_str)
        .map(ToString::to_string)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn json_bool_field(value: &serde_json::Value, key: &str) -> bool {
    value
        .get(key)
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepare_field_from_slice(fields: &[(String, String)], key: &str) -> String {
    fields
        .iter()
        .find_map(|(field_key, value)| (field_key == key).then(|| value.clone()))
        .unwrap_or_default()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn non_empty_prepare_field_path(fields: &[(String, String)], key: &str) -> Option<PathBuf> {
    let value = prepare_field_from_slice(fields, key);
    if value.trim().is_empty() {
        None
    } else {
        Some(PathBuf::from(value))
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn prepare_field_bool_from_slice(fields: &[(String, String)], key: &str) -> bool {
    prepare_field_from_slice(fields, key) == "true"
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn write_json_manifest_atomically(
    manifest_path: &std::path::Path,
    payload: &serde_json::Value,
) -> Result<()> {
    use std::io::Write as _;

    let Some(parent) = manifest_path.parent() else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "prepared-state reuse manifest path '{}' has no parent directory; fallback execution was not attempted",
            manifest_path.display()
        )));
    };
    std::fs::create_dir_all(parent).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to create prepared-state reuse manifest directory '{}': {error}; fallback execution was not attempted",
            parent.display()
        ))
    })?;
    let tmp_path = manifest_path.with_extension("json.tmp");
    let mut file = std::fs::File::create(&tmp_path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to create prepared-state reuse manifest temp file '{}': {error}; fallback execution was not attempted",
            tmp_path.display()
        ))
    })?;
    let encoded = serde_json::to_string_pretty(payload).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to encode prepared-state reuse manifest '{}': {error}; fallback execution was not attempted",
            manifest_path.display()
        ))
    })?;
    file.write_all(encoded.as_bytes()).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to write prepared-state reuse manifest '{}': {error}; fallback execution was not attempted",
            tmp_path.display()
        ))
    })?;
    file.write_all(b"\n").map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to write prepared-state reuse manifest '{}': {error}; fallback execution was not attempted",
            tmp_path.display()
        ))
    })?;
    file.sync_all().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to sync prepared-state reuse manifest '{}': {error}; fallback execution was not attempted",
            tmp_path.display()
        ))
    })?;
    std::fs::rename(&tmp_path, manifest_path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to publish prepared-state reuse manifest '{}' to '{}': {error}; fallback execution was not attempted",
            tmp_path.display(),
            manifest_path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn local_reuse_path_fingerprint(path: &std::path::Path, label: &str) -> Result<serde_json::Value> {
    let normalized = normalize_manifest_path(path);
    if path.is_file() {
        let metadata = std::fs::metadata(path).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "failed to stat {label} '{}' for prepared-state reuse: {error}; fallback execution was not attempted",
                path.display()
            ))
        })?;
        return Ok(serde_json::json!({
            "path": normalized,
            "exists": true,
            "kind": "local_file_size_mtime",
            "size_bytes": metadata.len(),
            "mtime_ns": metadata_mtime_ns(&metadata),
            "content_digest": serde_json::Value::Null,
            "content_digest_status": "not_requested_metadata_fingerprint_fast_path",
            "digest_policy": "metadata_size_mtime_normal_warm_reuse",
        }));
    }
    if path.is_dir() {
        let directory = directory_reuse_fingerprint(path, label)?;
        return Ok(serde_json::json!({
            "path": normalized,
            "exists": true,
            "kind": "local_directory_tree_sha256_size_mtime",
            "size_bytes": directory.size_bytes,
            "mtime_ns": directory.mtime_ns,
            "content_digest": directory.content_digest,
            "content_digest_status": "computed_for_directory_tree_fingerprint",
            "digest_policy": "directory_tree_digest_required_until_metadata_tree_policy_exists",
        }));
    }
    Ok(serde_json::json!({
        "path": normalized,
        "exists": false,
        "kind": "local_path_missing",
        "size_bytes": serde_json::Value::Null,
        "mtime_ns": serde_json::Value::Null,
        "content_digest": serde_json::Value::Null,
        "content_digest_status": "not_available_path_missing",
        "digest_policy": "metadata_size_mtime_normal_warm_reuse",
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct DirectoryReuseFingerprint {
    size_bytes: u64,
    mtime_ns: u64,
    content_digest: String,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn directory_reuse_fingerprint(
    path: &std::path::Path,
    label: &str,
) -> Result<DirectoryReuseFingerprint> {
    let mut files = Vec::new();
    collect_manifest_files(path, &mut files, label)?;
    files.sort();
    let mut total_size = 0_u64;
    let mut max_mtime_ns = 0_u64;
    let mut digest = sha2::Sha256::new();
    for file_path in files {
        let metadata = std::fs::metadata(&file_path).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "failed to stat {label} part '{}' for prepared-state reuse: {error}; fallback execution was not attempted",
                file_path.display()
            ))
        })?;
        let relative_path = file_path.strip_prefix(path).map_or_else(
            |_| file_path.display().to_string(),
            |relative| {
                relative
                    .to_string_lossy()
                    .replace(std::path::MAIN_SEPARATOR, "/")
            },
        );
        let file_digest = file_sha256_digest(&file_path, label)?;
        total_size = total_size.checked_add(metadata.len()).ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "{label} directory '{}' byte count overflow during prepared-state reuse fingerprinting; fallback execution was not attempted",
                path.display()
            ))
        })?;
        max_mtime_ns = max_mtime_ns.max(metadata_mtime_ns(&metadata));
        digest.update(relative_path.as_bytes());
        digest.update(b"\0");
        digest.update(metadata.len().to_string().as_bytes());
        digest.update(b"\0");
        digest.update(metadata_mtime_ns(&metadata).to_string().as_bytes());
        digest.update(b"\0");
        digest.update(file_digest.as_bytes());
        digest.update(b"\0");
    }
    Ok(DirectoryReuseFingerprint {
        size_bytes: total_size,
        mtime_ns: max_mtime_ns,
        content_digest: sha256_digest_string(digest.finalize()),
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn collect_manifest_files(
    path: &std::path::Path,
    files: &mut Vec<PathBuf>,
    label: &str,
) -> Result<()> {
    for entry in std::fs::read_dir(path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to read {label} directory '{}' for prepared-state reuse: {error}; fallback execution was not attempted",
            path.display()
        ))
    })? {
        let entry = entry.map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "failed to read {label} directory entry in '{}' for prepared-state reuse: {error}; fallback execution was not attempted",
                path.display()
            ))
        })?;
        let child = entry.path();
        if child.is_dir() {
            collect_manifest_files(&child, files, label)?;
        } else if child.is_file() {
            files.push(child);
        }
    }
    Ok(())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn normalize_manifest_path(path: &std::path::Path) -> String {
    if let Ok(canonical) = std::fs::canonicalize(path) {
        return canonical.display().to_string();
    }

    let absolute = if path.is_absolute() {
        path.to_path_buf()
    } else {
        std::env::current_dir()
            .unwrap_or_else(|_| PathBuf::from("."))
            .join(path)
    };
    let mut cursor = absolute.as_path();
    let mut missing_components = Vec::new();
    while !cursor.exists() {
        let Some(file_name) = cursor.file_name() else {
            break;
        };
        missing_components.push(file_name.to_os_string());
        let Some(parent) = cursor.parent() else {
            break;
        };
        cursor = parent;
    }
    let mut normalized = std::fs::canonicalize(cursor).unwrap_or_else(|_| cursor.to_path_buf());
    for component in missing_components.iter().rev() {
        normalized.push(component);
    }
    normalized.display().to_string()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn metadata_mtime_ns(metadata: &std::fs::Metadata) -> u64 {
    metadata
        .modified()
        .ok()
        .and_then(|mtime| mtime.duration_since(std::time::UNIX_EPOCH).ok())
        .map_or(0, |duration| {
            u64::try_from(duration.as_nanos()).unwrap_or(u64::MAX)
        })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn current_unix_seconds() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map_or(0, |duration| duration.as_secs())
}

