#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalDenseU32GroupAccum {
    fn can_admit(key: u32) -> bool {
        usize::try_from(key).is_ok_and(|key| key <= TRADITIONAL_DENSE_GROUP_MAX_KEY)
    }

    fn add(&mut self, key: u32, metric: f64) -> Result<()> {
        let index = usize::try_from(key).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "traditional analytics dense group key {key} exceeded usize: {error}; fallback execution was not attempted"
            ))
        })?;
        if index >= self.groups.len() {
            self.groups.resize_with(index + 1, || None);
        }
        let accum = self.groups[index].get_or_insert_with(|| {
            self.populated_keys.push(key);
            TraditionalGroupAccum::default()
        });
        accum.add(metric);
        Ok(())
    }

    fn into_btree_map(self) -> std::collections::BTreeMap<u32, TraditionalGroupAccum> {
        let Self {
            mut groups,
            mut populated_keys,
        } = self;
        populated_keys.sort_unstable();
        populated_keys
            .into_iter()
            .filter_map(|key| {
                let index = usize::try_from(key).ok()?;
                groups
                    .get_mut(index)
                    .and_then(Option::take)
                    .map(|accum| (key, accum))
            })
            .collect()
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq)]
enum TraditionalU32GroupAccumulator {
    Dense(TraditionalDenseU32GroupAccum),
    Sparse(std::collections::BTreeMap<u32, TraditionalGroupAccum>),
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl Default for TraditionalU32GroupAccumulator {
    fn default() -> Self {
        Self::Dense(TraditionalDenseU32GroupAccum::default())
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalU32GroupAccumulator {
    fn add(&mut self, key: u32, metric: f64) -> Result<()> {
        match self {
            Self::Dense(dense) if TraditionalDenseU32GroupAccum::can_admit(key) => {
                dense.add(key, metric)
            }
            Self::Dense(dense) => {
                let mut sparse = std::mem::take(dense).into_btree_map();
                sparse.entry(key).or_default().add(metric);
                *self = Self::Sparse(sparse);
                Ok(())
            }
            Self::Sparse(groups) => {
                groups.entry(key).or_default().add(metric);
                Ok(())
            }
        }
    }

    fn optimization_evidence(&self) -> TraditionalResidualOperatorOptimizationEvidence {
        self.optimization_evidence_for_family(
            "single_key_group_by",
            "applied_residual_dense_u32_group_accumulator",
        )
    }

    fn optimization_evidence_for_family(
        &self,
        family: &'static str,
        dense_status: &'static str,
    ) -> TraditionalResidualOperatorOptimizationEvidence {
        match self {
            Self::Dense(_) => {
                TraditionalResidualOperatorOptimizationEvidence::dense_u32_accumulator_for(
                    family,
                    dense_status,
                )
            }
            Self::Sparse(_) => {
                TraditionalResidualOperatorOptimizationEvidence::sparse_rollover(family)
            }
        }
    }

    fn into_btree_map(self) -> std::collections::BTreeMap<u32, TraditionalGroupAccum> {
        match self {
            Self::Dense(dense) => dense.into_btree_map(),
            Self::Sparse(groups) => groups,
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn pack_traditional_u32_pair(left: u32, right: u32) -> TraditionalPackedU32Pair {
    (u64::from(left) << 32) | u64::from(right)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn unpack_traditional_u32_pair(pair: TraditionalPackedU32Pair) -> (u32, u32) {
    let left = u32::try_from(pair >> 32).expect("packed group left key fits in u32");
    let right = u32::try_from(pair & u64::from(u32::MAX))
        .expect("masked packed group right key fits in u32");
    (left, right)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn add_packed_group_accum(
    groups: &mut std::collections::HashMap<TraditionalPackedU32Pair, TraditionalGroupAccum>,
    left: u32,
    right: u32,
    metric: f64,
) {
    groups
        .entry(pack_traditional_u32_pair(left, right))
        .or_default()
        .add(metric);
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Default, Clone, PartialEq)]
struct TraditionalDensePackedGroupAccum {
    groups: Vec<Option<TraditionalDenseU32GroupAccum>>,
    populated_group_keys: Vec<u32>,
    inner_slot_count: usize,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalDensePackedGroupAccum {
    fn can_admit(left: u32, right: u32) -> bool {
        usize::try_from(left)
            .ok()
            .zip(usize::try_from(right).ok())
            .is_some_and(|(left, right)| {
                left <= TRADITIONAL_DENSE_PACKED_GROUP_MAX_KEY
                    && right <= TRADITIONAL_DENSE_PACKED_GROUP_MAX_KEY
            })
    }

    fn add(&mut self, left: u32, right: u32, metric: f64) -> Result<bool> {
        if !Self::can_admit(left, right) {
            return Ok(false);
        }
        let left_index = usize::try_from(left).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "traditional analytics dense packed group left key {left} exceeded usize: {error}; fallback execution was not attempted"
            ))
        })?;
        let right_index = usize::try_from(right).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "traditional analytics dense packed group right key {right} exceeded usize: {error}; fallback execution was not attempted"
            ))
        })?;
        if left_index >= self.groups.len() {
            self.groups.resize_with(left_index + 1, || None);
        }
        let inner = self.groups[left_index].get_or_insert_with(|| {
            self.populated_group_keys.push(left);
            TraditionalDenseU32GroupAccum::default()
        });
        if right_index >= inner.groups.len() {
            let additional_slots = right_index + 1 - inner.groups.len();
            if self
                .inner_slot_count
                .checked_add(additional_slots)
                .is_none_or(|slots| slots > TRADITIONAL_DENSE_PACKED_GROUP_SLOT_BUDGET)
            {
                return Ok(false);
            }
            self.inner_slot_count += additional_slots;
        }
        inner.add(right, metric)?;
        Ok(true)
    }

    fn into_hash_map(
        self,
    ) -> std::collections::HashMap<TraditionalPackedU32Pair, TraditionalGroupAccum> {
        let Self {
            mut groups,
            mut populated_group_keys,
            ..
        } = self;
        let mut out =
            std::collections::HashMap::with_capacity(TRADITIONAL_GROUP_HASH_INITIAL_CAPACITY);
        populated_group_keys.sort_unstable();
        for left in populated_group_keys {
            let Some(index) = usize::try_from(left).ok() else {
                continue;
            };
            let Some(inner) = groups.get_mut(index).and_then(Option::take) else {
                continue;
            };
            for (right, accum) in inner.into_btree_map() {
                out.insert(pack_traditional_u32_pair(left, right), accum);
            }
        }
        out
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Clone, PartialEq)]
enum TraditionalPackedGroupAccumulator {
    Dense(TraditionalDensePackedGroupAccum),
    Sparse(std::collections::HashMap<TraditionalPackedU32Pair, TraditionalGroupAccum>),
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl Default for TraditionalPackedGroupAccumulator {
    fn default() -> Self {
        Self::Dense(TraditionalDensePackedGroupAccum::default())
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalPackedGroupAccumulator {
    fn add(&mut self, left: u32, right: u32, metric: f64) -> Result<()> {
        match self {
            Self::Dense(dense) => {
                if dense.add(left, right, metric)? {
                    Ok(())
                } else {
                    let mut sparse = std::mem::take(dense).into_hash_map();
                    add_packed_group_accum(&mut sparse, left, right, metric);
                    *self = Self::Sparse(sparse);
                    Ok(())
                }
            }
            Self::Sparse(groups) => {
                add_packed_group_accum(groups, left, right, metric);
                Ok(())
            }
        }
    }

    fn optimization_evidence(&self) -> TraditionalResidualOperatorOptimizationEvidence {
        self.optimization_evidence_for_family(
            "multi_key_group_by",
            "applied_residual_dense_packed_group_accumulator",
        )
    }

    fn optimization_evidence_for_family(
        &self,
        family: &'static str,
        dense_status: &'static str,
    ) -> TraditionalResidualOperatorOptimizationEvidence {
        match self {
            Self::Dense(_) => {
                TraditionalResidualOperatorOptimizationEvidence::dense_packed_accumulator_for(
                    family,
                    dense_status,
                )
            }
            Self::Sparse(_) => {
                TraditionalResidualOperatorOptimizationEvidence::sparse_rollover(family)
            }
        }
    }

    fn into_hash_map(
        self,
    ) -> std::collections::HashMap<TraditionalPackedU32Pair, TraditionalGroupAccum> {
        match self {
            Self::Dense(dense) => dense.into_hash_map(),
            Self::Sparse(groups) => groups,
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[derive(Debug, Default, Clone, PartialEq)]
struct TraditionalStringInterner {
    values: Vec<String>,
    by_value: std::collections::HashMap<String, u32>,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalStringInterner {
    fn with_capacity(capacity: usize) -> Self {
        Self {
            values: Vec::with_capacity(capacity),
            by_value: std::collections::HashMap::with_capacity(capacity),
        }
    }

    fn intern(&mut self, value: &str) -> Result<u32> {
        if let Some(id) = self.by_value.get(value) {
            return Ok(*id);
        }
        let id = u32::try_from(self.values.len()).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "traditional analytics string interner exceeded u32 ids: {error}"
            ))
        })?;
        let value = value.to_string();
        self.values.push(value.clone());
        self.by_value.insert(value, id);
        Ok(id)
    }

    fn value(&self, id: u32) -> Option<&str> {
        let index = usize::try_from(id).ok()?;
        self.values.get(index).map(String::as_str)
    }

    fn len(&self) -> usize {
        self.values.len()
    }
}

