#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalScenarioExecutionEvidence {
    fn table_materialized() -> Self {
        Self {
            streaming_vortex_execution_used: false,
            full_table_materialization_avoided: false,
            filter_pushdown_applied: false,
            projection_pushdown_applied: false,
            arrays_read_count: 0,
            max_chunk_rows: 0,
            projected_columns: Vec::new(),
            result_row_count: 0,
            reader_chunk_columns_observed: Vec::new(),
            reader_chunk_dtype_summary: Vec::new(),
            reader_chunk_encoding_summary: Vec::new(),
            vortex_footer_open_micros: 0,
            vortex_metadata_verify_micros: 0,
            vortex_scan_open_micros: 0,
            vortex_scenario_scan_micros: 0,
            scan_chunk_iter_micros: 0,
            vortex_projected_field_extract_micros: 0,
            vortex_encoded_kernel_evidence_micros: 0,
            operator_kernel_micros: 0,
            operator_finalize_micros: 0,
            result_assembly_micros: 0,
            vortex_scan_bytes_touched: 0,
            vortex_scan_segments_touched: 0,
            vortex_scan_segments_skipped: 0,
            vortex_scan_columns_touched: 0,
            vortex_scan_decoded_values: 0,
            encoded_predicate_provider:
                TraditionalEncodedPredicateProviderRuntimeEvidence::not_applicable(),
            compressed_kernel_registry_pair_execution_evidence: Vec::new(),
            residual_operator_optimization:
                TraditionalResidualOperatorOptimizationEvidence::not_applicable(),
            data_decoded: true,
            data_materialized: true,
            row_read: false,
        }
    }

    fn streaming(stats: TraditionalStreamingScanStats) -> Self {
        let TraditionalStreamingScanStats {
            arrays_read_count,
            max_chunk_rows,
            projected_columns,
            result_row_count,
            filter_pushdown_applied,
            projection_pushdown_applied,
            reader_chunk_columns_observed,
            reader_chunk_dtype_summary,
            reader_chunk_encoding_summary,
            vortex_footer_open_micros,
            vortex_metadata_verify_micros,
            vortex_scan_open_micros,
            vortex_scenario_scan_micros,
            scan_chunk_iter_micros,
            vortex_projected_field_extract_micros,
            vortex_encoded_kernel_evidence_micros,
            operator_kernel_micros,
            operator_finalize_micros,
            result_assembly_micros,
            vortex_scan_bytes_touched,
            vortex_scan_segments_touched,
            vortex_scan_segments_skipped,
            vortex_scan_columns_touched,
            vortex_scan_decoded_values,
            residual_operator_optimization,
            ..
        } = stats;
        Self {
            streaming_vortex_execution_used: true,
            full_table_materialization_avoided: true,
            filter_pushdown_applied,
            projection_pushdown_applied,
            arrays_read_count,
            max_chunk_rows,
            projected_columns,
            result_row_count,
            reader_chunk_columns_observed,
            reader_chunk_dtype_summary,
            reader_chunk_encoding_summary,
            vortex_footer_open_micros,
            vortex_metadata_verify_micros,
            vortex_scan_open_micros,
            vortex_scenario_scan_micros,
            scan_chunk_iter_micros,
            vortex_projected_field_extract_micros,
            vortex_encoded_kernel_evidence_micros,
            operator_kernel_micros,
            operator_finalize_micros,
            result_assembly_micros,
            vortex_scan_bytes_touched,
            vortex_scan_segments_touched,
            vortex_scan_segments_skipped,
            vortex_scan_columns_touched,
            vortex_scan_decoded_values,
            encoded_predicate_provider:
                TraditionalEncodedPredicateProviderRuntimeEvidence::not_applicable(),
            compressed_kernel_registry_pair_execution_evidence: Vec::new(),
            residual_operator_optimization,
            data_decoded: true,
            data_materialized: false,
            row_read: false,
        }
    }

    fn streaming_with_encoded_predicate_provider(
        stats: TraditionalStreamingScanStats,
        encoded_predicate_provider: TraditionalEncodedPredicateProviderRuntimeEvidence,
    ) -> Self {
        let kernel_pair_execution_evidence = encoded_predicate_provider
            .kernel_pair_execution_evidence
            .clone();
        let mut evidence = Self::streaming(stats);
        evidence.encoded_predicate_provider = encoded_predicate_provider;
        evidence
            .compressed_kernel_registry_pair_execution_evidence
            .extend(kernel_pair_execution_evidence);
        evidence
    }

    fn streaming_with_compressed_kernel_pairs(
        stats: TraditionalStreamingScanStats,
        pair_execution_evidence: Vec<TraditionalCompressedKernelPairExecutionEvidence>,
    ) -> Self {
        let mut evidence = Self::streaming(stats);
        evidence.compressed_kernel_registry_pair_execution_evidence = pair_execution_evidence;
        evidence
    }

    fn scan_substage_micros(&self) -> Result<u64> {
        checked_u64_values_sum(
            [
                self.vortex_footer_open_micros,
                self.vortex_metadata_verify_micros,
                self.vortex_scan_open_micros,
                self.scan_chunk_iter_micros,
                self.vortex_projected_field_extract_micros,
                self.vortex_encoded_kernel_evidence_micros,
            ],
            "traditional analytics scan substage timing",
        )
    }

    fn operator_substage_micros(&self) -> Result<u64> {
        checked_u64_values_sum(
            [
                self.operator_kernel_micros,
                self.operator_finalize_micros,
                self.result_assembly_micros,
            ],
            "traditional analytics operator substage timing",
        )
    }
}

