#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn write_compatibility_output_bytes(
    path: &std::path::Path,
    label: &str,
    bytes: &[u8],
) -> Result<()> {
    let workspace_root = shardloom_core::infer_local_output_workspace_root(path)?;
    shardloom_core::write_workspace_safe_bytes(
        workspace_root,
        path,
        true,
        format!("{label} compatibility output"),
        bytes,
    )
    .map(|_| ())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn compatibility_write_error(
    path: &std::path::Path,
    label: &str,
    error: impl std::fmt::Display,
) -> ShardLoomError {
    ShardLoomError::InvalidOperation(format!(
        "failed to write {label} compatibility output '{}': {error}",
        path.display()
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn json_escape(value: &str) -> String {
    value
        .chars()
        .flat_map(|ch| match ch {
            '"' => "\\\"".chars().collect::<Vec<_>>(),
            '\\' => "\\\\".chars().collect::<Vec<_>>(),
            '\n' => "\\n".chars().collect::<Vec<_>>(),
            '\r' => "\\r".chars().collect::<Vec<_>>(),
            '\t' => "\\t".chars().collect::<Vec<_>>(),
            _ => vec![ch],
        })
        .collect()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn fact_record_batch(fact: &VortexFactTable) -> Result<arrow_array::RecordBatch> {
    use std::sync::Arc;

    use arrow_array::{
        ArrayRef, Float64Array, Int8Array, Int32Array, Int64Array, RecordBatch, StringArray,
    };
    use arrow_schema::{DataType, Field, Schema};

    let schema = Schema::new(vec![
        Field::new("id", DataType::Int64, false),
        Field::new("group_key", DataType::Int32, false),
        Field::new("dim_key", DataType::Int32, false),
        Field::new("value", DataType::Int32, false),
        Field::new("metric", DataType::Float64, false),
        Field::new("flag", DataType::Int8, false),
        Field::new("category", DataType::Utf8, false),
        Field::new("event_date", DataType::Utf8, false),
        Field::new("nullable_metric_00", DataType::Utf8, false),
        Field::new("nested_payload", DataType::Utf8, false),
        Field::new("raw_event_time", DataType::Utf8, false),
        Field::new("dirty_numeric", DataType::Utf8, false),
        Field::new("dirty_flag", DataType::Utf8, false),
    ]);
    RecordBatch::try_new(
        Arc::new(schema),
        vec![
            Arc::new(Int64Array::from(u64_values_to_i64(&fact.id, "fact.id")?)) as ArrayRef,
            Arc::new(Int32Array::from(u32_values_to_i32(
                &fact.group_key,
                "fact.group_key",
            )?)) as ArrayRef,
            Arc::new(Int32Array::from(u32_values_to_i32(
                &fact.dim_key,
                "fact.dim_key",
            )?)) as ArrayRef,
            Arc::new(Int32Array::from(u32_values_to_i32(
                &fact.value,
                "fact.value",
            )?)) as ArrayRef,
            Arc::new(Float64Array::from(fact.metric.clone())) as ArrayRef,
            Arc::new(Int8Array::from(u8_values_to_i8(&fact.flag, "fact.flag")?)) as ArrayRef,
            Arc::new(StringArray::from(fact.category.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.event_date.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.nullable_metric_00.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.nested_payload.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.raw_event_time.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.dirty_numeric.clone())) as ArrayRef,
            Arc::new(StringArray::from(fact.dirty_flag.clone())) as ArrayRef,
        ],
    )
    .map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to build fact Arrow compatibility batch: {error}"
        ))
    })
}

