#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn primitive_field<T>(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
) -> Result<Vec<T>>
where
    T: vortex::array::dtype::NativePType + Copy,
{
    let primitive = primitive_array_field(fields, name)?;
    Ok(primitive.as_slice::<T>().to_vec())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn primitive_array_field(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
) -> Result<vortex::array::arrays::PrimitiveArray> {
    use vortex::array::VortexSessionExecute as _;
    use vortex::array::arrays::PrimitiveArray;

    let field = fields.get(name).ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!("Vortex field '{name}' was missing"))
    })?;
    let mut ctx = vortex::array::LEGACY_SESSION.create_execution_ctx();
    let primitive = field
        .clone()
        .execute::<PrimitiveArray>(&mut ctx)
        .map_err(vortex_error)?;
    Ok(primitive)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn varbin_view_field(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
) -> Result<vortex::array::arrays::VarBinViewArray> {
    use vortex::array::VortexSessionExecute as _;
    use vortex::array::arrays::VarBinViewArray;

    let field = fields.get(name).ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!("Vortex field '{name}' was missing"))
    })?;
    let mut ctx = vortex::array::LEGACY_SESSION.create_execution_ctx();
    let utf8 = field
        .clone()
        .execute::<VarBinViewArray>(&mut ctx)
        .map_err(vortex_error)?;
    Ok(utf8)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn utf8_field(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
) -> Result<Vec<String>> {
    let utf8 = varbin_view_field(fields, name)?;
    let mut values = Vec::with_capacity(utf8.len());
    for index in 0..utf8.len() {
        let bytes = utf8.bytes_at(index);
        let text = std::str::from_utf8(bytes.as_slice()).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "Vortex UTF-8 field '{name}' contained invalid UTF-8 at row {index}: {error}"
            ))
        })?;
        values.push(text.to_string());
    }
    Ok(values)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn intern_utf8_value_at(
    interner: &mut TraditionalStringInterner,
    utf8: &vortex::array::arrays::VarBinViewArray,
    name: &str,
    index: usize,
) -> Result<u32> {
    let bytes = utf8.bytes_at(index);
    let text = std::str::from_utf8(bytes.as_slice()).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "Vortex UTF-8 field '{name}' contained invalid UTF-8 at row {index}: {error}"
        ))
    })?;
    interner.intern(text)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn utf8_bytes_at<'a>(bytes: &'a [u8], name: &str, index: usize) -> Result<&'a str> {
    std::str::from_utf8(bytes).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "Vortex UTF-8 field '{name}' contained invalid UTF-8 at row {index}: {error}"
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_required_utf8_f64_at(bytes: &[u8], name: &str, index: usize) -> Result<f64> {
    let text = utf8_bytes_at(bytes, name, index)?;
    text.parse::<f64>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to parse {name} in Vortex chunk at row {}: {error}",
            index + 1
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_optional_utf8_f64_at(bytes: &[u8], name: &str, index: usize) -> Result<Option<f64>> {
    let text = utf8_bytes_at(bytes, name, index)?;
    match text.parse::<f64>() {
        Ok(value) => Ok(Some(value)),
        Err(_) => Ok(None),
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn optional_utf8_field(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
    row_count: usize,
) -> Result<Vec<String>> {
    if fields.contains_key(name) {
        utf8_field(fields, name)
    } else {
        Ok(vec![String::new(); row_count])
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn single_utf8_field(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
    path: &std::path::Path,
) -> Result<String> {
    let mut values = utf8_field(fields, name)?;
    if values.len() != 1 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "Vortex result artifact '{}' field '{name}' expected exactly one row, found {}",
            path.display(),
            values.len()
        )));
    }
    Ok(values.remove(0))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn single_primitive_field<T>(
    fields: &std::collections::BTreeMap<String, vortex::array::ArrayRef>,
    name: &str,
    path: &std::path::Path,
) -> Result<T>
where
    T: vortex::array::dtype::NativePType + Copy,
{
    let values = primitive_field::<T>(fields, name)?;
    if values.len() != 1 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "Vortex result artifact '{}' field '{name}' expected exactly one row, found {}",
            path.display(),
            values.len()
        )));
    }
    Ok(values[0])
}

#[cfg(all(test, feature = "vortex-traditional-analytics-benchmark"))]
fn read_traditional_fact_rows(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<Vec<TraditionalFactRow>> {
    read_traditional_fact_rows_with_evidence(path, input_format, resource_policy, true)
        .map(|source| source.rows)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_fact_rows_with_evidence(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    category_required: bool,
) -> Result<TraditionalSourceRead<TraditionalFactRow>> {
    if path.is_dir() {
        let mut rows = Vec::new();
        let mut evidence = TraditionalSourceReadEvidence::default();
        for part in fact_input_part_paths(path, input_format, "fact input")? {
            match read_traditional_fact_rows_with_evidence(
                &part,
                input_format,
                resource_policy,
                category_required,
            ) {
                Ok(part_source) => {
                    rows.extend(part_source.rows);
                    evidence = evidence.add(part_source.evidence)?;
                }
                Err(error)
                    if input_format == TraditionalAnalyticsInputFormat::JsonLines
                        && error.to_string().contains("contains no rows") => {}
                Err(error) => return Err(error),
            }
        }
        if rows.is_empty() {
            return Err(ShardLoomError::InvalidOperation(format!(
                "fact input directory '{}' contains no rows; fallback execution was not attempted",
                path.display()
            )));
        }
        return Ok(TraditionalSourceRead { rows, evidence });
    }
    match input_format {
        TraditionalAnalyticsInputFormat::Csv => {
            let source_read_start = std::time::Instant::now();
            let rows = read_traditional_fact_csv(path)?;
            Ok(TraditionalSourceRead {
                rows,
                evidence: TraditionalSourceReadEvidence::scalar(duration_to_micros(
                    source_read_start.elapsed(),
                )),
            })
        }
        TraditionalAnalyticsInputFormat::JsonLines => {
            let source_read_start = std::time::Instant::now();
            let rows = read_traditional_fact_jsonl(path)?;
            Ok(TraditionalSourceRead {
                rows,
                evidence: TraditionalSourceReadEvidence::scalar(duration_to_micros(
                    source_read_start.elapsed(),
                )),
            })
        }
        TraditionalAnalyticsInputFormat::Parquet
        | TraditionalAnalyticsInputFormat::ArrowIpc
        | TraditionalAnalyticsInputFormat::Avro
        | TraditionalAnalyticsInputFormat::Orc => {
            let source_to_columnar_start = std::time::Instant::now();
            let batches =
                read_traditional_arrow_batches(path, input_format, "fact input", resource_policy)?;
            let source_to_columnar_micros = duration_to_micros(source_to_columnar_start.elapsed());
            let record_batch_count = batches.len();
            let source_parse_start = std::time::Instant::now();
            let rows = fact_rows_from_arrow_batches(&batches, path, category_required)?;
            let source_parse_micros = duration_to_micros(source_parse_start.elapsed());
            Ok(TraditionalSourceRead {
                rows,
                evidence: TraditionalSourceReadEvidence::columnar(
                    source_to_columnar_micros,
                    source_parse_micros,
                    record_batch_count,
                )?,
            })
        }
    }
}

