#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn text_source_row_capacity_hint(source_bytes_hint: u64, bytes_per_row: u64) -> usize {
    let estimated = source_bytes_hint
        .checked_div(bytes_per_row.max(1))
        .unwrap_or_default()
        .max(1);
    usize::try_from(estimated.min(1_000_000)).unwrap_or(1_000_000)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::struct_excessive_bools)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct TraditionalFactTextColumnSelection {
    event_date: bool,
    nullable_metric_00: bool,
    nested_payload: bool,
    raw_event_time: bool,
    dirty_numeric: bool,
    dirty_flag: bool,
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
impl TraditionalFactTextColumnSelection {
    const fn full() -> Self {
        Self {
            event_date: true,
            nullable_metric_00: true,
            nested_payload: true,
            raw_event_time: true,
            dirty_numeric: true,
            dirty_flag: true,
        }
    }

    const fn core_only() -> Self {
        Self {
            event_date: false,
            nullable_metric_00: false,
            nested_payload: false,
            raw_event_time: false,
            dirty_numeric: false,
            dirty_flag: false,
        }
    }

    const fn for_scenario(scenario: TraditionalAnalyticsScenario) -> Self {
        match scenario {
            TraditionalAnalyticsScenario::PartitionPruning => Self {
                event_date: true,
                ..Self::core_only()
            },
            TraditionalAnalyticsScenario::NullHeavyAggregate => Self {
                nullable_metric_00: true,
                ..Self::core_only()
            },
            TraditionalAnalyticsScenario::CleanCastFilterWrite => Self {
                raw_event_time: true,
                dirty_numeric: true,
                dirty_flag: true,
                ..Self::core_only()
            },
            TraditionalAnalyticsScenario::MalformedTimestampDirtyCsv => Self {
                raw_event_time: true,
                dirty_numeric: true,
                ..Self::core_only()
            },
            TraditionalAnalyticsScenario::NestedJsonFieldScan => Self {
                nested_payload: true,
                ..Self::core_only()
            },
            _ => Self::core_only(),
        }
    }

    const fn decoded_mask(self) -> u32 {
        SOURCE_READ_FACT_CORE_MASK
            | if self.event_date {
                SOURCE_READ_FACT_EVENT_DATE
            } else {
                0
            }
            | if self.nullable_metric_00 {
                SOURCE_READ_FACT_NULLABLE_METRIC_00
            } else {
                0
            }
            | if self.nested_payload {
                SOURCE_READ_FACT_NESTED_PAYLOAD
            } else {
                0
            }
            | if self.raw_event_time {
                SOURCE_READ_FACT_RAW_EVENT_TIME
            } else {
                0
            }
            | if self.dirty_numeric {
                SOURCE_READ_FACT_DIRTY_NUMERIC
            } else {
                0
            }
            | if self.dirty_flag {
                SOURCE_READ_FACT_DIRTY_FLAG
            } else {
                0
            }
    }

    const fn skipped_mask(self) -> u32 {
        SOURCE_READ_FACT_OPTIONAL_MASK & !self.decoded_mask()
    }

    const fn needs_after_category(self) -> bool {
        self.event_date
            || self.nullable_metric_00
            || self.nested_payload
            || self.raw_event_time
            || self.dirty_numeric
            || self.dirty_flag
    }

    const fn selected_optional_mask(self) -> u32 {
        self.decoded_mask() & SOURCE_READ_FACT_OPTIONAL_MASK
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
const fn fact_category_required_for_scenario(scenario: TraditionalAnalyticsScenario) -> bool {
    matches!(
        scenario,
        TraditionalAnalyticsScenario::DistinctCount
            | TraditionalAnalyticsScenario::MultiKeyGroupBy
            | TraditionalAnalyticsScenario::JoinAggregate
            | TraditionalAnalyticsScenario::HighCardinalityStringGroupDistinct
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn fact_columnar_projection_fields_for_selection(
    column_selection: TraditionalFactTextColumnSelection,
    category_required: bool,
) -> Vec<&'static str> {
    let mut projection = vec!["id", "group_key", "dim_key", "value", "metric", "flag"];
    if category_required {
        projection.push("category");
    }
    if column_selection.event_date {
        projection.push("event_date");
    }
    if column_selection.nullable_metric_00 {
        projection.push("nullable_metric_00");
    }
    if column_selection.nested_payload {
        projection.push("nested_payload");
    }
    if column_selection.raw_event_time {
        projection.push("raw_event_time");
    }
    if column_selection.dirty_numeric {
        projection.push("dirty_numeric");
    }
    if column_selection.dirty_flag {
        projection.push("dirty_flag");
    }
    projection
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn fact_source_projection_evidence(
    scenario: TraditionalAnalyticsScenario,
    column_selection: TraditionalFactTextColumnSelection,
    category_required: bool,
) -> TraditionalTextProjectionEvidence {
    let mut projected_fields = column_selection.decoded_mask();
    let mut skipped_columns = column_selection.skipped_mask();
    if !category_required {
        projected_fields &= !SOURCE_READ_FACT_CATEGORY;
        skipped_columns |= SOURCE_READ_FACT_CATEGORY;
    }
    TraditionalTextProjectionEvidence {
        projected_fields,
        filter_fields: source_read_filter_field_mask_for_scenario(scenario),
        decoded_columns: projected_fields,
        skipped_columns,
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
const fn source_read_filter_field_mask_for_scenario(scenario: TraditionalAnalyticsScenario) -> u32 {
    match scenario {
        TraditionalAnalyticsScenario::SelectiveFilter
        | TraditionalAnalyticsScenario::FilterProjectionLimit => {
            SOURCE_READ_FACT_VALUE | SOURCE_READ_FACT_FLAG
        }
        TraditionalAnalyticsScenario::PartitionPruning => SOURCE_READ_FACT_EVENT_DATE,
        TraditionalAnalyticsScenario::CleanCastFilterWrite => {
            SOURCE_READ_FACT_RAW_EVENT_TIME
                | SOURCE_READ_FACT_DIRTY_NUMERIC
                | SOURCE_READ_FACT_DIRTY_FLAG
        }
        TraditionalAnalyticsScenario::MalformedTimestampDirtyCsv => {
            SOURCE_READ_FACT_RAW_EVENT_TIME | SOURCE_READ_FACT_DIRTY_NUMERIC
        }
        TraditionalAnalyticsScenario::HashJoin
        | TraditionalAnalyticsScenario::JoinAggregate
        | TraditionalAnalyticsScenario::SmallChangeOverLargeBase => SOURCE_READ_FACT_DIM_KEY,
        _ => 0,
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_fact_text_vortex_provider_batch_with_evidence(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    source_bytes_hint: u64,
    scenario: TraditionalAnalyticsScenario,
    column_selection: TraditionalFactTextColumnSelection,
) -> Result<TraditionalVortexProviderBatchRead> {
    if !matches!(
        input_format,
        TraditionalAnalyticsInputFormat::Csv | TraditionalAnalyticsInputFormat::JsonLines
    ) {
        return Err(ShardLoomError::InvalidOperation(format!(
            "internal error: {} is not a text Vortex provider input",
            input_format.as_str()
        )));
    }
    let mut columns = TraditionalFactVortexColumns::with_capacity(text_source_row_capacity_hint(
        source_bytes_hint,
        192,
    ));
    let parse_evidence =
        extend_traditional_fact_text_columns(path, input_format, &mut columns, column_selection)?;
    if parse_evidence.rows == 0 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "fact {} '{}' contains no rows; fallback execution was not attempted",
            input_format.as_str(),
            path.display()
        )));
    }
    let source_to_columnar_start = std::time::Instant::now();
    let batch = columns.into_record_batch()?;
    let source_to_columnar_micros = duration_to_micros(source_to_columnar_start.elapsed());
    let row_count = batch.num_rows();
    Ok(TraditionalVortexProviderBatchRead {
        batch,
        row_count,
        evidence: TraditionalSourceReadEvidence::text_vortex_provider_batch(
            parse_evidence.scout_timing,
            parse_evidence.parse_micros,
            source_to_columnar_micros,
            1,
            column_selection != TraditionalFactTextColumnSelection::full(),
            fact_source_projection_evidence(scenario, column_selection, true),
        )?,
    })
}

