#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn extend_traditional_dim_csv_columns_from_content(
    path: &std::path::Path,
    content: &str,
    columns: &mut TraditionalDimVortexColumns,
) -> Result<usize> {
    let mut lines = content.lines();
    let header = lines.next().ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!("dimension CSV '{}' is empty", path.display()))
    })?;
    if header.trim_end_matches('\r') != "dim_key,dim_label,weight" {
        return Err(ShardLoomError::InvalidOperation(format!(
            "dimension CSV '{}' does not match the benchmark schema",
            path.display()
        )));
    }
    let mut rows = 0_usize;
    for (line_index, line) in lines.enumerate() {
        if line.trim().is_empty() {
            continue;
        }
        let line = line.trim_end_matches('\r');
        let Some((dim_key, dim_label, weight)) = split_dim_csv_record(line, path, line_index + 2)?
        else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "dimension CSV '{}' line {} has {} columns, expected 3",
                path.display(),
                line_index + 2,
                line.split(',').count()
            )));
        };
        columns.push_values(
            parse_csv_field(dim_key.as_ref(), path, line_index + 2, "dim_key")?,
            dim_label.into_owned(),
            parse_csv_field::<f64>(weight.as_ref(), path, line_index + 2, "weight")?,
        );
        rows = rows.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "traditional analytics dimension CSV row count overflow".to_string(),
            )
        })?;
    }
    Ok(rows)
}

