#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_benchmark_fact_jsonl_fast_values_with_selection<'a>(
    line: &'a str,
    path: &std::path::Path,
    line_number: usize,
    column_selection: TraditionalFactTextColumnSelection,
) -> Result<Option<FastFactJsonlValues<'a>>> {
    let Some(mut cursor) = benchmark_jsonl_object_inner(line) else {
        return Ok(None);
    };
    if !take_json_prefix(&mut cursor, "\"id\":") {
        return Ok(None);
    }
    let Some(id) =
        parse_fast_json_number_before(&mut cursor, ",\"group_key\":", path, line_number, "id")?
    else {
        return Ok(None);
    };
    let Some(group_key) = parse_fast_json_number_before(
        &mut cursor,
        ",\"dim_key\":",
        path,
        line_number,
        "group_key",
    )?
    else {
        return Ok(None);
    };
    let Some(dim_key) =
        parse_fast_json_number_before(&mut cursor, ",\"value\":", path, line_number, "dim_key")?
    else {
        return Ok(None);
    };
    let Some(value) =
        parse_fast_json_number_before(&mut cursor, ",\"metric\":", path, line_number, "value")?
    else {
        return Ok(None);
    };
    let Some(metric) =
        parse_fast_json_number_before(&mut cursor, ",\"flag\":", path, line_number, "metric")?
    else {
        return Ok(None);
    };
    let Some(flag) =
        parse_fast_json_number_before(&mut cursor, ",\"category\":", path, line_number, "flag")?
    else {
        return Ok(None);
    };
    let Some(tail) = parse_benchmark_fact_jsonl_tail(cursor, path, line_number, column_selection)?
    else {
        return Ok(None);
    };
    Ok(Some(FastFactJsonlValues {
        id,
        group_key,
        dim_key,
        value,
        metric,
        flag,
        tail,
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn fact_row_from_fast_jsonl_values(
    values: FastFactJsonlValues<'_>,
    path: &std::path::Path,
    line_number: usize,
) -> Result<TraditionalFactRow> {
    let category =
        parse_json_string_token(values.tail.category_token, path, line_number, "category")?;
    Ok(TraditionalFactRow {
        id: values.id,
        group_key: values.group_key,
        dim_key: values.dim_key,
        value: values.value,
        metric: values.metric,
        flag: values.flag,
        category,
        event_date: values.tail.event_date,
        nullable_metric_00: values.tail.nullable_metric_00,
        nested_payload: values.tail.nested_payload,
        raw_event_time: values.tail.raw_event_time,
        dirty_numeric: values.tail.dirty_numeric,
        dirty_flag: values.tail.dirty_flag,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_lines)]
fn parse_benchmark_fact_jsonl_tail<'a>(
    cursor: &'a str,
    path: &std::path::Path,
    line_number: usize,
    column_selection: TraditionalFactTextColumnSelection,
) -> Result<Option<FastFactJsonlTail<'a>>> {
    let Some((category_token, cursor_after_category)) =
        split_fast_json_first_value_then_tail(cursor)
    else {
        return Ok(None);
    };
    let mut tail = fast_fact_jsonl_tail(category_token, None, None, None, None, None, None);
    if !column_selection.needs_after_category() {
        return Ok(Some(tail));
    }
    if let Some(direct_tail) = parse_benchmark_fact_jsonl_tail_direct(
        category_token,
        cursor_after_category,
        path,
        line_number,
        column_selection,
    )? {
        return Ok(Some(direct_tail));
    }
    let selected_mask = column_selection.selected_optional_mask();
    let mut seen_selected_mask = 0_u32;
    let Some(mut remaining) = cursor_after_category else {
        return Ok(Some(tail));
    };
    loop {
        let Some((field, rest)) = split_fast_json_first_value_then_tail(remaining) else {
            return Ok(None);
        };
        let Some((key, value)) = split_fast_json_field_key_value(field) else {
            return Ok(None);
        };
        match key {
            "\"event_date\"" if column_selection.event_date => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_EVENT_DATE,
                    path,
                    line_number,
                    "event_date",
                )?;
                tail.event_date =
                    parse_fast_json_optional_string_token(value, path, line_number, "event_date")?;
            }
            "\"nullable_metric_00\"" if column_selection.nullable_metric_00 => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_NULLABLE_METRIC_00,
                    path,
                    line_number,
                    "nullable_metric_00",
                )?;
                tail.nullable_metric_00 = parse_fast_json_optional_string_token(
                    value,
                    path,
                    line_number,
                    "nullable_metric_00",
                )?;
            }
            "\"nested_payload\"" if column_selection.nested_payload => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_NESTED_PAYLOAD,
                    path,
                    line_number,
                    "nested_payload",
                )?;
                tail.nested_payload = parse_fast_json_optional_string_token(
                    value,
                    path,
                    line_number,
                    "nested_payload",
                )?;
            }
            "\"raw_event_time\"" if column_selection.raw_event_time => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_RAW_EVENT_TIME,
                    path,
                    line_number,
                    "raw_event_time",
                )?;
                tail.raw_event_time = parse_fast_json_optional_string_token(
                    value,
                    path,
                    line_number,
                    "raw_event_time",
                )?;
            }
            "\"dirty_numeric\"" if column_selection.dirty_numeric => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_DIRTY_NUMERIC,
                    path,
                    line_number,
                    "dirty_numeric",
                )?;
                tail.dirty_numeric = parse_fast_json_optional_string_token(
                    value,
                    path,
                    line_number,
                    "dirty_numeric",
                )?;
            }
            "\"dirty_flag\"" if column_selection.dirty_flag => {
                mark_selected_jsonl_tail_field(
                    &mut seen_selected_mask,
                    SOURCE_READ_FACT_DIRTY_FLAG,
                    path,
                    line_number,
                    "dirty_flag",
                )?;
                tail.dirty_flag =
                    parse_fast_json_optional_string_token(value, path, line_number, "dirty_flag")?;
            }
            _ => {}
        }
        if seen_selected_mask & selected_mask == selected_mask {
            return Ok(Some(tail));
        }
        let Some(next) = rest else {
            return Ok(Some(tail));
        };
        remaining = next;
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_benchmark_fact_jsonl_tail_direct<'a>(
    category_token: &'a str,
    cursor_after_category: Option<&'a str>,
    path: &std::path::Path,
    line_number: usize,
    column_selection: TraditionalFactTextColumnSelection,
) -> Result<Option<FastFactJsonlTail<'a>>> {
    let Some(remaining) = cursor_after_category else {
        return Ok(Some(fast_fact_jsonl_tail(
            category_token,
            None,
            None,
            None,
            None,
            None,
            None,
        )));
    };
    if remaining
        .as_bytes()
        .iter()
        .any(|byte| matches!(byte, b' ' | b'\t' | b'\r' | b'\n'))
    {
        return Ok(None);
    }
    let mut tail = fast_fact_jsonl_tail(category_token, None, None, None, None, None, None);
    if column_selection.event_date {
        tail.event_date = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"event_date\":",
            ",\"event_date\":",
            path,
            line_number,
            "event_date",
        )?;
    }
    if column_selection.nullable_metric_00 {
        tail.nullable_metric_00 = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"nullable_metric_00\":",
            ",\"nullable_metric_00\":",
            path,
            line_number,
            "nullable_metric_00",
        )?;
    }
    if column_selection.nested_payload {
        tail.nested_payload = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"nested_payload\":",
            ",\"nested_payload\":",
            path,
            line_number,
            "nested_payload",
        )?;
    }
    if column_selection.raw_event_time {
        tail.raw_event_time = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"raw_event_time\":",
            ",\"raw_event_time\":",
            path,
            line_number,
            "raw_event_time",
        )?;
    }
    if column_selection.dirty_numeric {
        tail.dirty_numeric = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"dirty_numeric\":",
            ",\"dirty_numeric\":",
            path,
            line_number,
            "dirty_numeric",
        )?;
    }
    if column_selection.dirty_flag {
        tail.dirty_flag = parse_fast_json_selected_optional_string_field(
            remaining,
            "\"dirty_flag\":",
            ",\"dirty_flag\":",
            path,
            line_number,
            "dirty_flag",
        )?;
    }
    Ok(Some(tail))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_fast_json_selected_optional_string_field(
    remaining: &str,
    start_prefix: &str,
    comma_prefix: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<Option<String>> {
    let Some(value_cursor) = find_fast_json_selected_field_value_cursor(
        remaining,
        start_prefix,
        comma_prefix,
        path,
        line_number,
        field,
    )?
    else {
        return Ok(None);
    };
    let Some((value, _rest)) = split_fast_json_first_value_then_tail(value_cursor) else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "fact JSONL '{}' line {line_number} contains an invalid selected field '{field}'",
            path.display()
        )));
    };
    parse_fast_json_optional_string_token(value, path, line_number, field)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn find_fast_json_selected_field_value_cursor<'a>(
    remaining: &'a str,
    start_prefix: &str,
    comma_prefix: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<Option<&'a str>> {
    let (value_cursor, duplicate_scan) =
        if let Some(value_cursor) = remaining.strip_prefix(start_prefix) {
            (value_cursor, value_cursor)
        } else if let Some(prefix_index) = remaining.find(comma_prefix) {
            let value_cursor = &remaining[prefix_index + comma_prefix.len()..];
            (value_cursor, value_cursor)
        } else {
            return Ok(None);
        };
    if duplicate_scan.find(comma_prefix).is_some() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "fact JSONL '{}' line {line_number} contains duplicate selected field '{field}'",
            path.display()
        )));
    }
    Ok(Some(value_cursor))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn mark_selected_jsonl_tail_field(
    seen_selected_mask: &mut u32,
    field_mask: u32,
    path: &std::path::Path,
    line_number: usize,
    field_name: &str,
) -> Result<()> {
    if *seen_selected_mask & field_mask != 0 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "fact JSONL '{}' line {line_number} contains duplicate selected field '{field_name}'",
            path.display()
        )));
    }
    *seen_selected_mask |= field_mask;
    Ok(())
}

