#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_benchmark_dim_jsonl_fast(
    line: &str,
    path: &std::path::Path,
    line_number: usize,
) -> Result<Option<TraditionalDimRow>> {
    let Some(values) = parse_benchmark_dim_jsonl_fast_values(line, path, line_number)? else {
        return Ok(None);
    };
    Ok(Some(TraditionalDimRow {
        dim_key: values.dim_key,
        dim_label: values.dim_label,
        weight: values.weight,
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_benchmark_dim_jsonl_fast_values(
    line: &str,
    path: &std::path::Path,
    line_number: usize,
) -> Result<Option<FastDimJsonlValues>> {
    let Some(mut cursor) = benchmark_jsonl_object_inner(line) else {
        return Ok(None);
    };
    if !take_json_prefix(&mut cursor, "\"dim_key\":") {
        return Ok(None);
    }
    let Some(dim_key) = parse_fast_json_number_before(
        &mut cursor,
        ",\"dim_label\":",
        path,
        line_number,
        "dim_key",
    )?
    else {
        return Ok(None);
    };
    let Some((dim_label_token, weight_cursor)) =
        split_fast_json_string_then_number(cursor, ",\"weight\":")
    else {
        return Ok(None);
    };
    cursor = weight_cursor;
    let dim_label = parse_json_string_token(dim_label_token, path, line_number, "dim_label")?;
    if cursor.contains(',') {
        return Ok(None);
    }
    let weight = parse_fast_json_number(cursor, path, line_number, "weight")?;
    Ok(Some(FastDimJsonlValues {
        dim_key,
        dim_label,
        weight,
    }))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn benchmark_jsonl_object_inner(line: &str) -> Option<&str> {
    let trimmed = line.trim();
    trimmed
        .strip_prefix('{')
        .and_then(|value| value.strip_suffix('}'))
}
#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_fast_json_first_value_then_tail(cursor: &str) -> Option<(&str, Option<&str>)> {
    let trimmed = cursor.trim();
    if trimmed.is_empty() {
        return None;
    }
    let mut escaped = false;
    let mut in_string = false;
    for (index, byte) in trimmed.bytes().enumerate() {
        if escaped {
            escaped = false;
            continue;
        }
        match byte {
            b'\\' if in_string => escaped = true,
            b'"' => in_string = !in_string,
            b',' if !in_string => {
                let value = trimmed[..index].trim();
                let rest = trimmed[index + 1..].trim();
                if value.is_empty() {
                    return None;
                }
                return Some((value, (!rest.is_empty()).then_some(rest)));
            }
            _ => {}
        }
    }
    (!in_string && !escaped).then_some((trimmed, None))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_fast_json_field_key_value(field: &str) -> Option<(&str, &str)> {
    let trimmed = field.trim();
    if !trimmed.starts_with('"') {
        return None;
    }
    let mut escaped = false;
    for (index, byte) in trimmed.bytes().enumerate().skip(1) {
        if escaped {
            escaped = false;
            continue;
        }
        match byte {
            b'\\' => escaped = true,
            b'"' => {
                let key = &trimmed[..=index];
                let rest = trimmed[index + 1..].trim_start();
                let value = rest.strip_prefix(':')?.trim();
                return (!value.is_empty()).then_some((key, value));
            }
            _ => {}
        }
    }
    None
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn take_json_prefix(cursor: &mut &str, prefix: &str) -> bool {
    if let Some(rest) = cursor.strip_prefix(prefix) {
        *cursor = rest;
        true
    } else {
        false
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_fast_json_number_before<T>(
    cursor: &mut &str,
    next_prefix: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<Option<T>>
where
    T: std::str::FromStr,
    T::Err: std::fmt::Display,
{
    let Some((token, rest)) = cursor.split_once(next_prefix) else {
        return Ok(None);
    };
    *cursor = rest;
    parse_fast_json_number(token, path, line_number, field).map(Some)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_fast_json_number<T>(
    token: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<T>
where
    T: std::str::FromStr,
    T::Err: std::fmt::Display,
{
    let value = token.trim();
    if value.is_empty() || value.starts_with('"') {
        return Err(ShardLoomError::InvalidOperation(format!(
            "JSONL numeric field '{field}' in '{}' line {line_number} was not a scalar number",
            path.display()
        )));
    }
    value.parse::<T>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to parse JSONL field '{field}' in '{}' line {line_number}: {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_fast_json_string_then_number<'a>(
    cursor: &'a str,
    next_prefix: &str,
) -> Option<(&'a str, &'a str)> {
    split_fast_json_value_then(cursor, next_prefix)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_fast_json_value_then<'a>(
    cursor: &'a str,
    next_prefix: &str,
) -> Option<(&'a str, &'a str)> {
    let mut escaped = false;
    let mut in_string = false;
    let bytes = cursor.as_bytes();
    let mut index = 0;
    while index < bytes.len() {
        let byte = bytes[index];
        if escaped {
            escaped = false;
            index += 1;
            continue;
        }
        match byte {
            b'\\' if in_string => escaped = true,
            b'"' => in_string = !in_string,
            b',' if !in_string && cursor[index..].starts_with(next_prefix) => {
                return Some((&cursor[..index], &cursor[index + next_prefix.len()..]));
            }
            _ => {}
        }
        index += 1;
    }
    None
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_fast_json_optional_string_token(
    value: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<Option<String>> {
    let trimmed = value.trim();
    if trimmed == "null" {
        Ok(None)
    } else {
        parse_json_string_token(trimmed, path, line_number, field).map(Some)
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_csv_record(line: &str, path: &std::path::Path, line_number: usize) -> Result<Vec<String>> {
    if !line.as_bytes().contains(&b'"') {
        return Ok(line.split(',').map(str::to_string).collect());
    }

    let mut fields = Vec::with_capacity(TRADITIONAL_FACT_COLUMN_COUNT);
    let mut field = String::new();
    let mut chars = line.chars().peekable();
    let mut in_quotes = false;
    while let Some(ch) = chars.next() {
        match ch {
            '"' if in_quotes && chars.peek() == Some(&'"') => {
                field.push('"');
                let _ = chars.next();
            }
            '"' => {
                in_quotes = !in_quotes;
            }
            ',' if !in_quotes => {
                fields.push(std::mem::take(&mut field));
            }
            _ => field.push(ch),
        }
    }
    if in_quotes {
        return Err(ShardLoomError::InvalidOperation(format!(
            "CSV '{}' line {line_number} has an unterminated quoted field",
            path.display()
        )));
    }
    fields.push(field);
    Ok(fields)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_selected_csv_record<'a>(
    line: &'a str,
    path: &std::path::Path,
    line_number: usize,
    selected_indices: &[usize],
) -> Result<Vec<Option<std::borrow::Cow<'a, str>>>> {
    let mut selected_fields = vec![None; selected_indices.len()];
    if selected_indices.is_empty() {
        return Ok(selected_fields);
    }
    if !line.as_bytes().contains(&b'"') {
        let mut selected_cursor = 0_usize;
        for (field_index, field) in line.split(',').enumerate() {
            while selected_indices
                .get(selected_cursor)
                .is_some_and(|selected| *selected < field_index)
            {
                selected_cursor += 1;
            }
            if selected_indices.get(selected_cursor) == Some(&field_index) {
                selected_fields[selected_cursor] = Some(std::borrow::Cow::Borrowed(field));
                selected_cursor += 1;
                if selected_cursor >= selected_indices.len() {
                    break;
                }
            }
        }
        return Ok(selected_fields);
    }

    let bytes = line.as_bytes();
    let mut in_quotes = false;
    let mut field_index = 0_usize;
    let mut selected_cursor = 0_usize;
    let mut field_start = 0_usize;
    let mut selected_quoted_buffer: Option<Vec<u8>> = None;
    let mut index = 0_usize;
    while index < bytes.len() {
        let current_selected = selected_indices.get(selected_cursor) == Some(&field_index);
        match bytes[index] {
            b'"' if in_quotes && bytes.get(index + 1) == Some(&b'"') => {
                if current_selected {
                    selected_quoted_buffer
                        .get_or_insert_with(|| bytes[field_start..index].to_vec())
                        .push(b'"');
                }
                index += 2;
                continue;
            }
            b'"' => {
                if current_selected {
                    let _ = selected_quoted_buffer
                        .get_or_insert_with(|| bytes[field_start..index].to_vec());
                }
                in_quotes = !in_quotes;
            }
            b',' if !in_quotes => {
                if current_selected && selected_cursor < selected_fields.len() {
                    selected_fields[selected_cursor] = Some(selected_csv_field_value(
                        line,
                        field_start,
                        index,
                        selected_quoted_buffer.take(),
                        path,
                        line_number,
                    )?);
                    selected_cursor += 1;
                    if selected_cursor >= selected_fields.len() {
                        return Ok(selected_fields);
                    }
                }
                field_index = field_index.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "CSV field index overflow while parsing traditional analytics input"
                            .to_string(),
                    )
                })?;
                field_start = index + 1;
            }
            byte if current_selected && selected_quoted_buffer.is_some() => {
                selected_quoted_buffer
                    .as_mut()
                    .expect("selected quoted CSV buffer initialized")
                    .push(byte);
            }
            _ => {}
        }
        index += 1;
    }
    if in_quotes {
        return Err(ShardLoomError::InvalidOperation(format!(
            "CSV '{}' line {line_number} has an unterminated quoted field",
            path.display()
        )));
    }
    if selected_indices.get(selected_cursor) == Some(&field_index) {
        selected_fields[selected_cursor] = Some(selected_csv_field_value(
            line,
            field_start,
            bytes.len(),
            selected_quoted_buffer,
            path,
            line_number,
        )?);
    }
    Ok(selected_fields)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_field_value<'a>(
    line: &'a str,
    start: usize,
    end: usize,
    quoted_buffer: Option<Vec<u8>>,
    path: &std::path::Path,
    line_number: usize,
) -> Result<std::borrow::Cow<'a, str>> {
    match quoted_buffer {
        Some(buffer) => String::from_utf8(buffer)
            .map(std::borrow::Cow::Owned)
            .map_err(|error| {
                ShardLoomError::InvalidOperation(format!(
                    "CSV '{}' line {line_number} selected field contained invalid UTF-8 after quote normalization: {error}",
                    path.display()
                ))
            }),
        None => Ok(std::borrow::Cow::Borrowed(&line[start..end])),
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::type_complexity)]
fn split_dim_csv_record<'a>(
    line: &'a str,
    path: &std::path::Path,
    line_number: usize,
) -> Result<
    Option<(
        std::borrow::Cow<'a, str>,
        std::borrow::Cow<'a, str>,
        std::borrow::Cow<'a, str>,
    )>,
> {
    if line.as_bytes().contains(&b'"') {
        let mut selected = split_selected_csv_record(line, path, line_number, &[0, 1, 2])?;
        if split_selected_csv_record(line, path, line_number, &[3])?
            .first()
            .and_then(Option::as_ref)
            .is_some()
        {
            return Ok(None);
        }
        let Some(dim_key) = selected.get_mut(0).and_then(Option::take) else {
            return Ok(None);
        };
        let Some(dim_label) = selected.get_mut(1).and_then(Option::take) else {
            return Ok(None);
        };
        let Some(weight) = selected.get_mut(2).and_then(Option::take) else {
            return Ok(None);
        };
        return Ok(Some((dim_key, dim_label, weight)));
    }

    let mut parts = line.split(',');
    let Some(dim_key) = parts.next() else {
        return Ok(None);
    };
    let Some(dim_label) = parts.next() else {
        return Ok(None);
    };
    let Some(weight) = parts.next() else {
        return Ok(None);
    };
    if parts.next().is_some() {
        return Ok(None);
    }
    Ok(Some((
        std::borrow::Cow::Borrowed(dim_key),
        std::borrow::Cow::Borrowed(dim_label),
        std::borrow::Cow::Borrowed(weight),
    )))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_fact_csv_selected_indices(
    event_date_index: Option<usize>,
    nullable_metric_00_index: Option<usize>,
    nested_payload_index: Option<usize>,
    raw_event_time_index: Option<usize>,
    dirty_numeric_index: Option<usize>,
    dirty_flag_index: Option<usize>,
) -> Vec<usize> {
    traditional_fact_csv_selected_indices_for_selection(
        TraditionalFactTextColumnSelection::full(),
        event_date_index,
        nullable_metric_00_index,
        nested_payload_index,
        raw_event_time_index,
        dirty_numeric_index,
        dirty_flag_index,
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn traditional_fact_csv_selected_indices_for_selection(
    column_selection: TraditionalFactTextColumnSelection,
    event_date_index: Option<usize>,
    nullable_metric_00_index: Option<usize>,
    nested_payload_index: Option<usize>,
    raw_event_time_index: Option<usize>,
    dirty_numeric_index: Option<usize>,
    dirty_flag_index: Option<usize>,
) -> Vec<usize> {
    let mut indices = vec![0, 1, 2, 3, 4, 5, 6];
    indices.extend(
        [
            column_selection.event_date.then_some(event_date_index),
            column_selection
                .nullable_metric_00
                .then_some(nullable_metric_00_index),
            column_selection
                .nested_payload
                .then_some(nested_payload_index),
            column_selection
                .raw_event_time
                .then_some(raw_event_time_index),
            column_selection
                .dirty_numeric
                .then_some(dirty_numeric_index),
            column_selection.dirty_flag.then_some(dirty_flag_index),
        ]
        .into_iter()
        .flatten()
        .flatten(),
    );
    indices.sort_unstable();
    indices.dedup();
    indices
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_position(selected_indices: &[usize], field_index: usize) -> usize {
    selected_indices
        .binary_search(&field_index)
        .expect("required traditional analytics CSV field must be selected")
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_optional_position(
    selected_indices: &[usize],
    field_index: Option<usize>,
) -> Option<usize> {
    field_index.map(|index| selected_csv_position(selected_indices, index))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_optional_position_for_selection(
    selected_indices: &[usize],
    field_index: Option<usize>,
    selected: bool,
) -> Option<usize> {
    if selected {
        selected_csv_optional_position(selected_indices, field_index)
    } else {
        None
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_required<'a>(
    fields: &'a [Option<std::borrow::Cow<'a, str>>],
    position: usize,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<&'a str> {
    fields
        .get(position)
        .and_then(Option::as_ref)
        .map(std::borrow::Cow::as_ref)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "fact CSV '{}' line {line_number} is missing required field '{field}'",
                path.display()
            ))
        })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn selected_csv_optional_string(
    fields: &[Option<std::borrow::Cow<'_, str>>],
    position: Option<usize>,
) -> Option<String> {
    position.and_then(|field_position| {
        fields
            .get(field_position)
            .and_then(Option::as_ref)
            .map(std::borrow::Cow::as_ref)
            .filter(|value| !value.is_empty())
            .map(str::to_string)
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_csv_field<T>(
    value: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<T>
where
    T: std::str::FromStr,
    T::Err: std::fmt::Display,
{
    value.parse::<T>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to parse field '{field}' in '{}' line {line_number}: {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_jsonl_to_string(path: &std::path::Path, label: &str) -> Result<String> {
    std::fs::read_to_string(path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to read {label} '{}': {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_jsonl_object(
    line: &str,
    path: &std::path::Path,
    line_number: usize,
    label: &str,
) -> Result<JsonlFieldMap> {
    let trimmed = line.trim();
    let Some(inner) = trimmed
        .strip_prefix('{')
        .and_then(|value| value.strip_suffix('}'))
    else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} is not a JSON object",
            path.display()
        )));
    };
    let mut fields = JsonlFieldMap::with_capacity(TRADITIONAL_FACT_COLUMN_COUNT);
    visit_json_fields(inner, path, line_number, label, |field| {
        let (key, value) = split_json_key_value(field, path, line_number, label)?;
        let key = parse_json_string_token(key.trim(), path, line_number, "field name")?;
        if fields
            .insert(key.clone(), value.trim().to_string())
            .is_some()
        {
            return Err(ShardLoomError::InvalidOperation(format!(
                "{label} '{}' line {line_number} contains duplicate field '{key}'",
                path.display()
            )));
        }
        Ok(())
    })?;
    Ok(fields)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_jsonl_object_selected(
    line: &str,
    path: &std::path::Path,
    line_number: usize,
    label: &str,
    selected_fields: &[&str],
) -> Result<JsonlFieldMap> {
    let trimmed = line.trim();
    let Some(inner) = trimmed
        .strip_prefix('{')
        .and_then(|value| value.strip_suffix('}'))
    else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} is not a JSON object",
            path.display()
        )));
    };
    let mut fields = JsonlFieldMap::with_capacity(selected_fields.len());
    visit_json_fields(inner, path, line_number, label, |field| {
        let (key, value) = split_json_key_value(field, path, line_number, label)?;
        let key = parse_json_string_token(key.trim(), path, line_number, "field name")?;
        if !selected_fields.contains(&key.as_str()) {
            return Ok(());
        }
        if fields
            .insert(key.clone(), value.trim().to_string())
            .is_some()
        {
            return Err(ShardLoomError::InvalidOperation(format!(
                "{label} '{}' line {line_number} contains duplicate selected field '{key}'",
                path.display()
            )));
        }
        Ok(())
    })?;
    Ok(fields)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn visit_json_fields<'a, F>(
    inner: &'a str,
    path: &std::path::Path,
    line_number: usize,
    label: &str,
    mut visit: F,
) -> Result<()>
where
    F: FnMut(&'a str) -> Result<()>,
{
    let mut start = 0;
    let mut in_string = false;
    let mut escaped = false;
    let mut object_depth = 0_u32;
    let mut array_depth = 0_u32;
    for (index, ch) in inner.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        match ch {
            '\\' if in_string => escaped = true,
            '"' => in_string = !in_string,
            '{' if !in_string => {
                object_depth = object_depth.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} JSON object nesting depth overflowed",
                        path.display()
                    ))
                })?;
            }
            '}' if !in_string => {
                object_depth = object_depth.checked_sub(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} contains an unmatched JSON object close",
                        path.display()
                    ))
                })?;
            }
            '[' if !in_string => {
                array_depth = array_depth.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} JSON array nesting depth overflowed",
                        path.display()
                    ))
                })?;
            }
            ']' if !in_string => {
                array_depth = array_depth.checked_sub(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} contains an unmatched JSON array close",
                        path.display()
                    ))
                })?;
            }
            ',' if !in_string && object_depth == 0 && array_depth == 0 => {
                visit(inner[start..index].trim())?;
                start = index + ch.len_utf8();
            }
            _ => {}
        }
    }
    if in_string || escaped {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} contains an unterminated JSON string",
            path.display()
        )));
    }
    if object_depth != 0 || array_depth != 0 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} contains an unterminated JSON object or array",
            path.display()
        )));
    }
    let tail = inner[start..].trim();
    if !tail.is_empty() {
        visit(tail)?;
    }
    Ok(())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn split_json_key_value<'a>(
    field: &'a str,
    path: &std::path::Path,
    line_number: usize,
    label: &str,
) -> Result<(&'a str, &'a str)> {
    let mut delimiter_index = None;
    let mut in_string = false;
    let mut escaped = false;
    let mut object_depth = 0_u32;
    let mut array_depth = 0_u32;
    for (index, ch) in field.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        match ch {
            '\\' if in_string => escaped = true,
            '"' => in_string = !in_string,
            '{' if !in_string => {
                object_depth = object_depth.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} JSON object nesting depth overflowed",
                        path.display()
                    ))
                })?;
            }
            '}' if !in_string => {
                object_depth = object_depth.checked_sub(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} contains an unmatched JSON object close",
                        path.display()
                    ))
                })?;
            }
            '[' if !in_string => {
                array_depth = array_depth.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} JSON array nesting depth overflowed",
                        path.display()
                    ))
                })?;
            }
            ']' if !in_string => {
                array_depth = array_depth.checked_sub(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(format!(
                        "{label} '{}' line {line_number} contains an unmatched JSON array close",
                        path.display()
                    ))
                })?;
            }
            ':' if !in_string
                && object_depth == 0
                && array_depth == 0
                && delimiter_index.is_some() =>
            {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "{label} '{}' line {line_number} has an invalid JSON field",
                    path.display()
                )));
            }
            ':' if !in_string && object_depth == 0 && array_depth == 0 => {
                delimiter_index = Some(index);
            }
            _ => {}
        }
    }
    if in_string || escaped {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} contains an unterminated JSON string",
            path.display()
        )));
    }
    if object_depth != 0 || array_depth != 0 {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} contains an unterminated JSON object or array",
            path.display()
        )));
    }
    let Some(index) = delimiter_index else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} has an invalid JSON field",
            path.display()
        )));
    };
    let key = field[..index].trim();
    let value = field[index + 1..].trim();
    if key.is_empty() || value.is_empty() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} '{}' line {line_number} has an invalid JSON field",
            path.display()
        )));
    }
    Ok((key, value))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_jsonl_numeric_field<T>(
    fields: &JsonlFieldMap,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<T>
where
    T: std::str::FromStr,
    T::Err: std::fmt::Display,
{
    let value = jsonl_required_field(fields, path, line_number, field)?;
    value.parse::<T>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to parse JSONL field '{field}' in '{}' line {line_number}: {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_jsonl_string_field(
    fields: &JsonlFieldMap,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<String> {
    parse_json_string_token(
        jsonl_required_field(fields, path, line_number, field)?,
        path,
        line_number,
        field,
    )
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_jsonl_optional_string_field(
    fields: &JsonlFieldMap,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<Option<String>> {
    fields
        .get(field)
        .map(|value| {
            if value == "null" {
                Ok(None)
            } else {
                parse_json_string_token(value, path, line_number, field).map(Some)
            }
        })
        .transpose()
        .map(Option::flatten)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn jsonl_required_field<'a>(
    fields: &'a JsonlFieldMap,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<&'a str> {
    fields.get(field).map(String::as_str).ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!(
            "JSONL '{}' line {line_number} is missing field '{field}'",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn parse_json_string_token(
    value: &str,
    path: &std::path::Path,
    line_number: usize,
    field: &str,
) -> Result<String> {
    let trimmed = value.trim();
    let Some(inner) = trimmed
        .strip_prefix('"')
        .and_then(|value| value.strip_suffix('"'))
    else {
        return Err(ShardLoomError::InvalidOperation(format!(
            "JSONL string field '{field}' in '{}' line {line_number} was not quoted",
            path.display()
        )));
    };
    if !inner.as_bytes().contains(&b'\\') {
        return Ok(inner.to_string());
    }
    let mut out = String::with_capacity(inner.len());
    let mut chars = inner.chars();
    while let Some(ch) = chars.next() {
        if ch != '\\' {
            out.push(ch);
            continue;
        }
        let Some(escaped) = chars.next() else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "JSONL string field '{field}' in '{}' line {line_number} ended with an escape",
                path.display()
            )));
        };
        match escaped {
            '"' => out.push('"'),
            '\\' => out.push('\\'),
            '/' => out.push('/'),
            'b' => out.push('\u{0008}'),
            'f' => out.push('\u{000c}'),
            'n' => out.push('\n'),
            'r' => out.push('\r'),
            't' => out.push('\t'),
            'u' => {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "JSONL string field '{field}' in '{}' line {line_number} uses unsupported unicode escape",
                    path.display()
                )));
            }
            other => {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "JSONL string field '{field}' in '{}' line {line_number} uses invalid escape '\\{other}'",
                    path.display()
                )));
            }
        }
    }
    Ok(out)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_arrow_batches(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<Vec<arrow_array::RecordBatch>> {
    read_traditional_arrow_batches_with_projection(path, input_format, label, resource_policy, None)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_arrow_batches_with_projection(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    projection: Option<&[usize]>,
) -> Result<Vec<arrow_array::RecordBatch>> {
    match input_format {
        TraditionalAnalyticsInputFormat::Parquet => {
            read_parquet_record_batches(path, label, resource_policy, projection)
        }
        TraditionalAnalyticsInputFormat::ArrowIpc => {
            read_arrow_ipc_record_batches(path, label, projection)
        }
        TraditionalAnalyticsInputFormat::Avro => {
            read_avro_record_batches(path, label, resource_policy, projection)
        }
        TraditionalAnalyticsInputFormat::Orc => {
            read_orc_record_batches(path, label, resource_policy, projection)
        }
        TraditionalAnalyticsInputFormat::Csv | TraditionalAnalyticsInputFormat::JsonLines => {
            Err(ShardLoomError::InvalidOperation(format!(
                "internal error: {} does not use Arrow batch reader",
                input_format.as_str()
            )))
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_fact_arrow_batches_with_projection(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    projection_fields: &[&str],
) -> Result<Vec<arrow_array::RecordBatch>> {
    if !path.is_dir() {
        return read_traditional_arrow_batches_projected_by_field_names(
            path,
            input_format,
            label,
            resource_policy,
            projection_fields,
        );
    }
    let mut batches = Vec::new();
    for part in fact_input_part_paths(path, input_format, label)? {
        batches.extend(read_traditional_arrow_batches_projected_by_field_names(
            &part,
            input_format,
            label,
            resource_policy,
            projection_fields,
        )?);
    }
    if batches
        .iter()
        .map(arrow_array::RecordBatch::num_rows)
        .sum::<usize>()
        == 0
    {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} directory '{}' contains no rows; fallback execution was not attempted",
            path.display()
        )));
    }
    Ok(batches)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_arrow_batches_projected_by_field_names(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    projection_fields: &[&str],
) -> Result<Vec<arrow_array::RecordBatch>> {
    match input_format {
        TraditionalAnalyticsInputFormat::Parquet => read_parquet_record_batches_by_field_names(
            path,
            label,
            resource_policy,
            projection_fields,
        ),
        TraditionalAnalyticsInputFormat::ArrowIpc => {
            read_arrow_ipc_record_batches_by_field_names(path, label, projection_fields)
        }
        TraditionalAnalyticsInputFormat::Avro => {
            read_avro_record_batches_by_field_names(path, label, resource_policy, projection_fields)
        }
        TraditionalAnalyticsInputFormat::Orc => {
            read_orc_record_batches_by_field_names(path, label, resource_policy, projection_fields)
        }
        TraditionalAnalyticsInputFormat::Csv | TraditionalAnalyticsInputFormat::JsonLines => {
            Err(ShardLoomError::InvalidOperation(format!(
                "internal error: {} does not use Arrow batch reader",
                input_format.as_str()
            )))
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn projection_indices_for_arrow_schema(
    schema: &arrow_schema::Schema,
    projection_fields: &[&str],
) -> Vec<usize> {
    projection_fields
        .iter()
        .filter_map(|field| schema.index_of(field).ok())
        .collect()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_traditional_dim_arrow_batches(
    path: &std::path::Path,
    input_format: TraditionalAnalyticsInputFormat,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
) -> Result<Vec<arrow_array::RecordBatch>> {
    if !path.is_dir() {
        return read_traditional_arrow_batches(path, input_format, label, resource_policy);
    }
    let mut batches = Vec::new();
    for part in fact_input_part_paths(path, input_format, label)? {
        batches.extend(read_traditional_arrow_batches(
            &part,
            input_format,
            label,
            resource_policy,
        )?);
    }
    if batches
        .iter()
        .map(arrow_array::RecordBatch::num_rows)
        .sum::<usize>()
        == 0
    {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{label} directory '{}' contains no rows; fallback execution was not attempted",
            path.display()
        )));
    }
    Ok(batches)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn read_parquet_record_batches_by_field_names(
    path: &std::path::Path,
    label: &str,
    resource_policy: TraditionalAnalyticsResourcePolicy,
    projection_fields: &[&str],
) -> Result<Vec<arrow_array::RecordBatch>> {
    let file = std::fs::File::open(path).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to open Parquet {label} '{}': {error}",
            path.display()
        ))
    })?;
    let builder = parquet::arrow::arrow_reader::ParquetRecordBatchReaderBuilder::try_new(file)
        .map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "failed to create Parquet reader for {label} '{}': {error}",
                path.display()
            ))
        })?;
    let projection = projection_indices_for_arrow_schema(builder.schema(), projection_fields);
    let mask =
        parquet::arrow::ProjectionMask::roots(builder.parquet_schema(), projection.iter().copied());
    let reader = builder
        .with_projection(mask)
        .with_batch_size(resource_policy.target_batch_rows)
        .build()
        .map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "failed to build Parquet reader for {label} '{}': {error}",
                path.display()
            ))
        })?;
    collect_record_batches(reader, path, label, "Parquet")
}

