#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn arrow_optional_f64_values(
    array: &dyn arrow_array::Array,
    path: &std::path::Path,
    field: &str,
) -> Result<Vec<Option<String>>> {
    if let Some(values) = array.as_any().downcast_ref::<arrow_array::Float64Array>() {
        Ok((0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    Ok(None)
                } else {
                    Ok(Some(json_float(values.value(row_index))))
                }
            })
            .collect::<Result<Vec<_>>>()?)
    } else if let Some(values) = array.as_any().downcast_ref::<arrow_array::Float32Array>() {
        Ok((0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    Ok(None)
                } else {
                    Ok(Some(json_float(f64::from(values.value(row_index)))))
                }
            })
            .collect::<Result<Vec<_>>>()?)
    } else if let Some(values) = array.as_any().downcast_ref::<arrow_array::Int64Array>() {
        (0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    Ok(None)
                } else {
                    arrow_i64_to_f64(values.value(row_index), path, row_index, field)
                        .map(json_float)
                        .map(Some)
                }
            })
            .collect()
    } else if let Some(values) = array.as_any().downcast_ref::<arrow_array::Int32Array>() {
        Ok((0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    None
                } else {
                    Some(json_float(f64::from(values.value(row_index))))
                }
            })
            .collect())
    } else if let Some(values) = array.as_any().downcast_ref::<arrow_array::UInt64Array>() {
        (0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    Ok(None)
                } else {
                    arrow_u64_to_f64(values.value(row_index), path, row_index, field)
                        .map(json_float)
                        .map(Some)
                }
            })
            .collect()
    } else if let Some(values) = array.as_any().downcast_ref::<arrow_array::UInt32Array>() {
        Ok((0..values.len())
            .map(|row_index| {
                if values.is_null(row_index) {
                    None
                } else {
                    Some(json_float(f64::from(values.value(row_index))))
                }
            })
            .collect())
    } else {
        Err(arrow_type_error(array, path, 0, field, "numeric or string"))
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn ensure_arrow_column_not_null(
    array: &dyn arrow_array::Array,
    path: &std::path::Path,
    field: &str,
) -> Result<()> {
    for row_index in 0..array.len() {
        ensure_arrow_not_null(array, path, row_index, field)?;
    }
    Ok(())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn arrow_i64_to_f64(
    value: i64,
    path: &std::path::Path,
    row_index: usize,
    field: &str,
) -> Result<f64> {
    if value.unsigned_abs() > MAX_EXACT_F64_INTEGER {
        return Err(ShardLoomError::InvalidOperation(format!(
            "Arrow field '{field}' in '{}' row {row_index} cannot be represented exactly as f64",
            path.display()
        )));
    }
    value.to_string().parse::<f64>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "Arrow field '{field}' in '{}' row {row_index} could not be converted to f64: {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn arrow_u64_to_f64(
    value: u64,
    path: &std::path::Path,
    row_index: usize,
    field: &str,
) -> Result<f64> {
    if value > MAX_EXACT_F64_INTEGER {
        return Err(ShardLoomError::InvalidOperation(format!(
            "Arrow field '{field}' in '{}' row {row_index} cannot be represented exactly as f64",
            path.display()
        )));
    }
    value.to_string().parse::<f64>().map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "Arrow field '{field}' in '{}' row {row_index} could not be converted to f64: {error}",
            path.display()
        ))
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn date32_days_to_yyyy_mm_dd(days_since_epoch: i32) -> String {
    let z = i64::from(days_since_epoch) + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let doe = z - era * 146_097;
    let yoe = (doe - doe / 1_460 + doe / 36_524 - doe / 146_096) / 365;
    let mut year = yoe + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let day = doy - (153 * mp + 2) / 5 + 1;
    let month = mp + if mp < 10 { 3 } else { -9 };
    year += i64::from(month <= 2);
    format!("{year:04}-{month:02}-{day:02}")
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn ensure_arrow_not_null(
    array: &dyn arrow_array::Array,
    path: &std::path::Path,
    row_index: usize,
    field: &str,
) -> Result<()> {
    if array.is_null(row_index) {
        return Err(ShardLoomError::InvalidOperation(format!(
            "Arrow input '{}' field '{field}' row {} is null; benchmark schema requires a value",
            path.display(),
            row_index + 1
        )));
    }
    Ok(())
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn arrow_type_error(
    array: &dyn arrow_array::Array,
    path: &std::path::Path,
    row_index: usize,
    field: &str,
    expected: &str,
) -> ShardLoomError {
    ShardLoomError::InvalidOperation(format!(
        "Arrow input '{}' field '{field}' row {} expected {expected}, found {:?}",
        path.display(),
        row_index + 1,
        array.data_type()
    ))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn run_vortex_derived_scenario_from_files(
    scenario: TraditionalAnalyticsScenario,
    fact_path: &std::path::Path,
    dim_path: &std::path::Path,
    cdc_delta_path: Option<&std::path::Path>,
) -> Result<TraditionalScenarioExecution> {
    match scenario {
        TraditionalAnalyticsScenario::CsvFileIngest
        | TraditionalAnalyticsScenario::ManySmallFilesScan => {
            run_streaming_fact_metric_sum_scenario(fact_path, dim_path, None, "metric")
        }
        TraditionalAnalyticsScenario::SelectiveFilter => {
            run_streaming_selective_filter_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::HashJoin => {
            run_streaming_hash_join_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::JoinAggregate => {
            run_streaming_join_aggregate_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::SortAndTopK => {
            run_streaming_sort_top_k_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::TopNPerGroup => {
            run_streaming_top_n_per_group_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::RowNumberWindow => {
            run_streaming_row_number_window_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::HighCardinalityStringGroupDistinct => {
            run_streaming_string_group_distinct_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::PartitionPruning => {
            run_streaming_partition_pruning_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::GroupByAggregation => {
            run_streaming_group_by_aggregation_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::DistinctCount => {
            run_streaming_distinct_count_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::NullHeavyAggregate => {
            run_streaming_null_heavy_aggregate_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::CleanCastFilterWrite => {
            run_streaming_clean_cast_filter_write_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::MalformedTimestampDirtyCsv => {
            run_streaming_malformed_timestamp_dirty_csv_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::NestedJsonFieldScan => {
            run_streaming_nested_json_field_scan_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::SmallChangeOverLargeBase => {
            let cdc_delta_path = cdc_delta_path.ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "small change over large base requires imported CDC delta Vortex source"
                        .to_string(),
                )
            })?;
            run_streaming_small_change_over_large_base_scenario(fact_path, dim_path, cdc_delta_path)
        }
        TraditionalAnalyticsScenario::MultiKeyGroupBy => {
            run_streaming_multi_key_group_by_scenario(fact_path, dim_path)
        }
        TraditionalAnalyticsScenario::WideProjection => {
            run_streaming_fact_metric_sum_scenario(fact_path, dim_path, None, "group_key")
        }
        TraditionalAnalyticsScenario::FilterProjectionLimit => {
            run_streaming_filter_projection_limit_scenario(fact_path, dim_path)
        }
        _ => {
            let fact = read_fact_vortex(fact_path)?;
            let dim = read_dim_vortex(dim_path)?;
            let cdc_delta = cdc_delta_path.map(read_cdc_delta_vortex).transpose()?;
            run_vortex_derived_scenario_from_tables(scenario, &fact, &dim, cdc_delta.as_ref())
        }
    }
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn run_vortex_derived_scenario_from_files_with_batch_source_state(
    scenario: TraditionalAnalyticsScenario,
    fact_path: &std::path::Path,
    dim_path: &std::path::Path,
    cdc_delta_path: Option<&std::path::Path>,
    source_state: &TraditionalVortexBatchSourceState,
) -> Result<TraditionalScenarioExecution> {
    if let Some(fact_delta_overlay_path) = source_state.fact_delta_overlay_vortex_path.as_deref() {
        return run_vortex_derived_scenario_from_files_with_fact_delta_overlay(
            scenario,
            fact_path,
            fact_delta_overlay_path,
            source_state.dim_rows,
        );
    }
    if let Some(execution) = run_fact_metric_batch_source_state_scenario(scenario, source_state)? {
        return Ok(execution);
    }
    if let Some(execution) =
        run_dimension_label_batch_source_state_scenario(scenario, fact_path, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) =
        run_category_metric_batch_source_state_scenario(scenario, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) = run_group_category_batch_source_state_scenario(scenario, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) = run_ranked_metric_batch_source_state_scenario(scenario, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) =
        run_selective_filter_batch_source_state_scenario(scenario, fact_path, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) = run_dirty_input_batch_source_state_scenario(scenario, source_state)? {
        return Ok(execution);
    }
    if let Some(execution) =
        run_date_null_metric_batch_source_state_scenario(scenario, source_state)?
    {
        return Ok(execution);
    }
    if let Some(execution) = run_vortex_derived_scenario_from_files_with_cached_dim_rows(
        scenario,
        fact_path,
        source_state.dim_rows,
        cdc_delta_path,
    )? {
        return Ok(execution);
    }
    run_vortex_derived_scenario_from_files(scenario, fact_path, dim_path, cdc_delta_path)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn run_vortex_derived_scenario_from_files_with_fact_delta_overlay(
    scenario: TraditionalAnalyticsScenario,
    fact_path: &std::path::Path,
    fact_delta_overlay_path: &std::path::Path,
    dim_rows: u64,
) -> Result<TraditionalScenarioExecution> {
    let sum_column = match scenario {
        TraditionalAnalyticsScenario::CsvFileIngest
        | TraditionalAnalyticsScenario::ManySmallFilesScan => "metric",
        _ => {
            return Err(ShardLoomError::InvalidOperation(format!(
                "prepared-state append-only fact delta overlay is not admitted for scenario '{}'; supported overlay consumers for this slice are csv/file ingest and many-small-files scan; fallback execution was not attempted",
                scenario.as_str()
            )));
        }
    };
    let base = run_streaming_fact_metric_sum_scenario_with_dim_rows(
        fact_path, dim_rows, None, sum_column,
    )?;
    let delta = run_streaming_fact_metric_sum_scenario_with_dim_rows(
        fact_delta_overlay_path,
        dim_rows,
        None,
        sum_column,
    )?;
    combine_fact_delta_overlay_metric_sum_execution(&base, &delta)
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn combine_fact_delta_overlay_metric_sum_execution(
    base: &TraditionalScenarioExecution,
    delta: &TraditionalScenarioExecution,
) -> Result<TraditionalScenarioExecution> {
    let (base_row_count, base_metric_sum) = scalar_result_json_parts(&base.result_json)?;
    let (delta_row_count, delta_metric_sum) = scalar_result_json_parts(&delta.result_json)?;
    let result_row_count = checked_u64_sum(base_row_count, delta_row_count)?;
    let metric_sum = base_metric_sum + delta_metric_sum;
    Ok(TraditionalScenarioExecution {
        result_json: scalar_result_json(result_row_count, metric_sum),
        fact_rows: checked_u64_sum(base.fact_rows, delta.fact_rows)?,
        dim_rows: base.dim_rows,
        cdc_delta_rows: 0,
        rows_scanned: checked_u64_sum(base.rows_scanned, delta.rows_scanned)?,
        rows_materialized: 1,
        evidence: combine_fact_delta_overlay_streaming_evidence(&base.evidence, &delta.evidence)?,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn scalar_result_json_parts(result_json: &str) -> Result<(u64, f64)> {
    let value: serde_json::Value = serde_json::from_str(result_json).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "failed to parse scalar result JSON during prepared-state delta overlay compose: {error}; fallback execution was not attempted"
        ))
    })?;
    let row_count = value
        .get("row_count")
        .and_then(serde_json::Value::as_u64)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "scalar result JSON missing row_count during prepared-state delta overlay compose; fallback execution was not attempted"
                    .to_string(),
            )
        })?;
    let metric_sum = value
        .get("metric_sum")
        .and_then(serde_json::Value::as_f64)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "scalar result JSON missing metric_sum during prepared-state delta overlay compose; fallback execution was not attempted"
                    .to_string(),
            )
        })?;
    Ok((row_count, metric_sum))
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn combine_fact_delta_overlay_streaming_evidence(
    base: &TraditionalScenarioExecutionEvidence,
    delta: &TraditionalScenarioExecutionEvidence,
) -> Result<TraditionalScenarioExecutionEvidence> {
    if !base.streaming_vortex_execution_used || !delta.streaming_vortex_execution_used {
        return Err(ShardLoomError::InvalidOperation(
            "prepared-state delta overlay compose requires both base and delta executions to use streaming Vortex scans; fallback execution was not attempted"
                .to_string(),
        ));
    }
    Ok(TraditionalScenarioExecutionEvidence {
        streaming_vortex_execution_used: true,
        full_table_materialization_avoided: base.full_table_materialization_avoided
            && delta.full_table_materialization_avoided,
        filter_pushdown_applied: base.filter_pushdown_applied || delta.filter_pushdown_applied,
        projection_pushdown_applied: base.projection_pushdown_applied
            && delta.projection_pushdown_applied,
        arrays_read_count: base.arrays_read_count + delta.arrays_read_count,
        max_chunk_rows: base.max_chunk_rows.max(delta.max_chunk_rows),
        projected_columns: union_sorted_strings(&base.projected_columns, &delta.projected_columns),
        result_row_count: checked_u64_sum(base.result_row_count, delta.result_row_count)?,
        reader_chunk_columns_observed: union_sorted_strings(
            &base.reader_chunk_columns_observed,
            &delta.reader_chunk_columns_observed,
        ),
        reader_chunk_dtype_summary: union_sorted_strings(
            &base.reader_chunk_dtype_summary,
            &delta.reader_chunk_dtype_summary,
        ),
        reader_chunk_encoding_summary: union_sorted_strings(
            &base.reader_chunk_encoding_summary,
            &delta.reader_chunk_encoding_summary,
        ),
        vortex_footer_open_micros: checked_u64_sum(
            base.vortex_footer_open_micros,
            delta.vortex_footer_open_micros,
        )?,
        vortex_metadata_verify_micros: checked_u64_sum(
            base.vortex_metadata_verify_micros,
            delta.vortex_metadata_verify_micros,
        )?,
        vortex_scan_open_micros: checked_u64_sum(
            base.vortex_scan_open_micros,
            delta.vortex_scan_open_micros,
        )?,
        vortex_scenario_scan_micros: checked_u64_sum(
            base.vortex_scenario_scan_micros,
            delta.vortex_scenario_scan_micros,
        )?,
        scan_chunk_iter_micros: checked_u64_sum(
            base.scan_chunk_iter_micros,
            delta.scan_chunk_iter_micros,
        )?,
        vortex_projected_field_extract_micros: checked_u64_sum(
            base.vortex_projected_field_extract_micros,
            delta.vortex_projected_field_extract_micros,
        )?,
        vortex_encoded_kernel_evidence_micros: checked_u64_sum(
            base.vortex_encoded_kernel_evidence_micros,
            delta.vortex_encoded_kernel_evidence_micros,
        )?,
        operator_kernel_micros: checked_u64_sum(
            base.operator_kernel_micros,
            delta.operator_kernel_micros,
        )?,
        operator_finalize_micros: checked_u64_sum(
            base.operator_finalize_micros,
            delta.operator_finalize_micros,
        )?,
        result_assembly_micros: checked_u64_sum(
            base.result_assembly_micros,
            delta.result_assembly_micros,
        )?,
        vortex_scan_bytes_touched: checked_u64_sum(
            base.vortex_scan_bytes_touched,
            delta.vortex_scan_bytes_touched,
        )?,
        vortex_scan_segments_touched: checked_u64_sum(
            base.vortex_scan_segments_touched,
            delta.vortex_scan_segments_touched,
        )?,
        vortex_scan_segments_skipped: checked_u64_sum(
            base.vortex_scan_segments_skipped,
            delta.vortex_scan_segments_skipped,
        )?,
        vortex_scan_columns_touched: base
            .vortex_scan_columns_touched
            .max(delta.vortex_scan_columns_touched),
        vortex_scan_decoded_values: checked_u64_sum(
            base.vortex_scan_decoded_values,
            delta.vortex_scan_decoded_values,
        )?,
        encoded_predicate_provider:
            TraditionalEncodedPredicateProviderRuntimeEvidence::not_applicable(),
        compressed_kernel_registry_pair_execution_evidence: Vec::new(),
        residual_operator_optimization:
            TraditionalResidualOperatorOptimizationEvidence::not_applicable(),
        data_decoded: base.data_decoded || delta.data_decoded,
        data_materialized: base.data_materialized || delta.data_materialized,
        row_read: base.row_read || delta.row_read,
    })
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn union_sorted_strings(left: &[String], right: &[String]) -> Vec<String> {
    let mut values = std::collections::BTreeSet::new();
    values.extend(left.iter().cloned());
    values.extend(right.iter().cloned());
    values.into_iter().collect()
}

#[cfg(feature = "vortex-traditional-analytics-benchmark")]
fn run_vortex_derived_scenario_from_files_with_cached_dim_rows(
    scenario: TraditionalAnalyticsScenario,
    fact_path: &std::path::Path,
    dim_rows: u64,
    cdc_delta_path: Option<&std::path::Path>,
) -> Result<Option<TraditionalScenarioExecution>> {
    let execution = match scenario {
        TraditionalAnalyticsScenario::CsvFileIngest
        | TraditionalAnalyticsScenario::ManySmallFilesScan => {
            run_streaming_fact_metric_sum_scenario_with_dim_rows(
                fact_path, dim_rows, None, "metric",
            )?
        }
        TraditionalAnalyticsScenario::SelectiveFilter => {
            run_streaming_selective_filter_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::SortAndTopK => {
            run_streaming_sort_top_k_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::TopNPerGroup => {
            run_streaming_ranked_per_group_scenario_with_dim_rows(
                fact_path,
                dim_rows,
                3,
                "top-N per group",
            )?
        }
        TraditionalAnalyticsScenario::RowNumberWindow => {
            run_streaming_ranked_per_group_scenario_with_dim_rows(
                fact_path,
                dim_rows,
                1,
                "row number window",
            )?
        }
        TraditionalAnalyticsScenario::HighCardinalityStringGroupDistinct => {
            run_streaming_string_group_distinct_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::PartitionPruning => {
            run_streaming_partition_pruning_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::GroupByAggregation => {
            run_streaming_group_by_aggregation_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::DistinctCount => {
            run_streaming_distinct_count_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::NullHeavyAggregate => {
            run_streaming_null_heavy_aggregate_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::CleanCastFilterWrite => {
            run_streaming_clean_cast_filter_write_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::MalformedTimestampDirtyCsv => {
            run_streaming_malformed_timestamp_dirty_csv_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::NestedJsonFieldScan => {
            run_streaming_nested_json_field_scan_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::SmallChangeOverLargeBase => {
            let cdc_delta_path = cdc_delta_path.ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "small change over large base requires imported CDC delta Vortex source"
                        .to_string(),
                )
            })?;
            run_streaming_small_change_over_large_base_scenario_with_dim_rows(
                fact_path,
                dim_rows,
                cdc_delta_path,
            )?
        }
        TraditionalAnalyticsScenario::MultiKeyGroupBy => {
            run_streaming_multi_key_group_by_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::WideProjection => {
            run_streaming_fact_metric_sum_scenario_with_dim_rows(
                fact_path,
                dim_rows,
                None,
                "group_key",
            )?
        }
        TraditionalAnalyticsScenario::FilterProjectionLimit => {
            run_streaming_filter_projection_limit_scenario_with_dim_rows(fact_path, dim_rows)?
        }
        TraditionalAnalyticsScenario::HashJoin | TraditionalAnalyticsScenario::JoinAggregate => {
            return Ok(None);
        }
        _ => return Ok(None),
    };
    Ok(Some(execution))
}

