#[cfg(feature = "vortex-traditional-analytics-benchmark")]
#[allow(clippy::too_many_lines)]
fn run_streaming_hash_join_scenario_with_dim_state(
    fact_path: &std::path::Path,
    dim_state: &TraditionalDimensionLabelState,
) -> Result<TraditionalScenarioExecution> {
    let dim_by_key = &dim_state.dim_by_key;
    let dim_stats = &dim_state.stats;
    let mut groups = TraditionalU32GroupAccumulator::default();
    let fact_stats = scan_fact_vortex_projected(
        fact_path,
        &["dim_key", "metric"],
        None,
        |fields, chunk_rows| {
            let dim_keys = primitive_array_field(fields, "dim_key")?;
            let dim_keys = dim_keys.as_slice::<u32>();
            let metrics = primitive_array_field(fields, "metric")?;
            let metrics = metrics.as_slice::<f64>();
            if dim_keys.len() != chunk_rows || metrics.len() != chunk_rows {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "hash join fact Vortex chunk length mismatch: chunk_rows={chunk_rows}, dim_key_len={}, metric_len={}",
                    dim_keys.len(),
                    metrics.len()
                )));
            }
            for (&dim_key, &metric) in dim_keys.iter().zip(metrics) {
                if dim_state.contains_dim_key(dim_key) {
                    groups.add(dim_key, metric)?;
                }
            }
            Ok(())
        },
    )?;

    let residual_operator_optimization = groups
        .optimization_evidence_for_family(
            "hash_join",
            "applied_residual_dense_u32_hash_join_accumulator",
        )
        .with_dimension_membership(&dim_state.key_lookup);
    let result_json = dim_key_group_rows_json(groups.into_btree_map(), dim_by_key)?;
    let rows_materialized = result_rows_materialized(&result_json)?;
    let rows_scanned = checked_u64_sum(fact_stats.source_row_count, dim_stats.source_row_count)?;
    let stats = TraditionalStreamingScanStats {
        source_row_count: fact_stats.source_row_count,
        result_row_count: rows_scanned,
        arrays_read_count: fact_stats.arrays_read_count + dim_stats.arrays_read_count,
        max_chunk_rows: fact_stats.max_chunk_rows.max(dim_stats.max_chunk_rows),
        projected_columns: prefixed_projected_columns(
            "dim",
            &dim_stats.projected_columns,
            "fact",
            &fact_stats.projected_columns,
        ),
        reader_chunk_columns_observed: prefixed_projected_columns(
            "dim",
            &dim_stats.reader_chunk_columns_observed,
            "fact",
            &fact_stats.reader_chunk_columns_observed,
        ),
        reader_chunk_dtype_summary: prefixed_reader_chunk_summary(
            "dim",
            &dim_stats.reader_chunk_dtype_summary,
            "fact",
            &fact_stats.reader_chunk_dtype_summary,
        ),
        reader_chunk_encoding_summary: prefixed_reader_chunk_summary(
            "dim",
            &dim_stats.reader_chunk_encoding_summary,
            "fact",
            &fact_stats.reader_chunk_encoding_summary,
        ),
        filter_pushdown_applied: false,
        projection_pushdown_applied: true,
        vortex_footer_open_micros: checked_u64_sum(
            dim_stats.vortex_footer_open_micros,
            fact_stats.vortex_footer_open_micros,
        )?,
        vortex_metadata_verify_micros: checked_u64_sum(
            dim_stats.vortex_metadata_verify_micros,
            fact_stats.vortex_metadata_verify_micros,
        )?,
        vortex_scan_open_micros: checked_u64_sum(
            dim_stats.vortex_scan_open_micros,
            fact_stats.vortex_scan_open_micros,
        )?,
        vortex_scenario_scan_micros: checked_u64_sum(
            dim_stats.vortex_scenario_scan_micros,
            fact_stats.vortex_scenario_scan_micros,
        )?,
        scan_chunk_iter_micros: checked_u64_sum(
            dim_stats.scan_chunk_iter_micros,
            fact_stats.scan_chunk_iter_micros,
        )?,
        vortex_projected_field_extract_micros: checked_u64_sum(
            dim_stats.vortex_projected_field_extract_micros,
            fact_stats.vortex_projected_field_extract_micros,
        )?,
        vortex_encoded_kernel_evidence_micros: checked_u64_sum(
            dim_stats.vortex_encoded_kernel_evidence_micros,
            fact_stats.vortex_encoded_kernel_evidence_micros,
        )?,
        operator_kernel_micros: checked_u64_sum(
            dim_stats.operator_kernel_micros,
            fact_stats.operator_kernel_micros,
        )?,
        operator_finalize_micros: checked_u64_sum(
            dim_stats.operator_finalize_micros,
            fact_stats.operator_finalize_micros,
        )?,
        result_assembly_micros: checked_u64_sum(
            dim_stats.result_assembly_micros,
            fact_stats.result_assembly_micros,
        )?,
        vortex_scan_bytes_touched: checked_u64_sum(
            dim_stats.vortex_scan_bytes_touched,
            fact_stats.vortex_scan_bytes_touched,
        )?,
        vortex_scan_segments_touched: checked_u64_sum(
            dim_stats.vortex_scan_segments_touched,
            fact_stats.vortex_scan_segments_touched,
        )?,
        vortex_scan_segments_skipped: checked_u64_sum(
            dim_stats.vortex_scan_segments_skipped,
            fact_stats.vortex_scan_segments_skipped,
        )?,
        vortex_scan_columns_touched: checked_u64_sum(
            dim_stats.vortex_scan_columns_touched,
            fact_stats.vortex_scan_columns_touched,
        )?,
        vortex_scan_decoded_values: checked_u64_sum(
            dim_stats.vortex_scan_decoded_values,
            fact_stats.vortex_scan_decoded_values,
        )?,
        residual_operator_optimization,
    };
    Ok(TraditionalScenarioExecution {
        result_json,
        fact_rows: fact_stats.source_row_count,
        dim_rows: dim_stats.source_row_count,
        cdc_delta_rows: 0,
        rows_scanned,
        rows_materialized,
        evidence: TraditionalScenarioExecutionEvidence::streaming(stats),
    })
}

