    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    #[test]
    fn selected_csv_record_borrows_unquoted_fields_and_unescapes_dimension_labels() {
        let unquoted = split_selected_csv_record(
            "1,2,3,4,5.5,1,c1,unused,unused",
            std::path::Path::new("fact.csv"),
            2,
            &[0, 2, 6],
        )
        .expect("unquoted selected CSV record");
        assert!(matches!(
            unquoted.first().and_then(Option::as_ref),
            Some(std::borrow::Cow::Borrowed("1"))
        ));
        assert!(matches!(
            unquoted.get(1).and_then(Option::as_ref),
            Some(std::borrow::Cow::Borrowed("3"))
        ));
        assert!(matches!(
            unquoted.get(2).and_then(Option::as_ref),
            Some(std::borrow::Cow::Borrowed("c1"))
        ));

        let selected = split_selected_csv_record(
            r#"1,alpha,"north,west","unused,field""#,
            std::path::Path::new("dim.csv"),
            2,
            &[0, 2],
        )
        .expect("selected CSV record");
        assert!(matches!(
            selected.first().and_then(Option::as_ref),
            Some(std::borrow::Cow::Borrowed("1"))
        ));
        assert!(matches!(
            selected.get(1).and_then(Option::as_ref),
            Some(std::borrow::Cow::Owned(value)) if value == "north,west"
        ));

        let dim = split_dim_csv_record(r#"1,"north,west",2.5"#, std::path::Path::new("dim.csv"), 2)
            .expect("dimension CSV record")
            .expect("dimension fields");
        assert_eq!(dim.0.as_ref(), "1");
        assert_eq!(dim.1.as_ref(), "north,west");
        assert_eq!(dim.2.as_ref(), "2.5");
    }

    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    #[test]
    fn selected_csv_record_skips_malformed_unselected_trailing_fields() {
        let path = std::path::Path::new("fact.csv");
        let projected = split_selected_csv_record(
            "1,2,3,4,5.5,1,c1,\"unterminated",
            path,
            2,
            &[0, 1, 2, 3, 4, 5, 6],
        )
        .expect("projection-aware CSV reader should stop after selected fields");
        assert_eq!(
            selected_csv_required(&projected, 6, path, 2, "category").expect("category"),
            "c1"
        );

        assert!(
            split_selected_csv_record(
                "1,2,3,4,5.5,1,c1,\"unterminated",
                path,
                2,
                &[0, 1, 2, 3, 4, 5, 6, 7],
            )
            .is_err(),
            "selected malformed fields must still fail deterministically"
        );
    }

