    #[test]
    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn avro_provider_batch_uses_fact_projection_mask_without_row_materialization() {
        let root = traditional_analytics_test_root("avro-projected-provider");
        let (fact_csv, _) = write_tiny_traditional_csv_inputs(&root);
        let fact_rows = read_traditional_fact_rows(
            &fact_csv,
            TraditionalAnalyticsInputFormat::Csv,
            TraditionalAnalyticsResourcePolicy::auto().resolve_for_sources(1024),
        )
        .expect("fact rows");
        let mut columns = TraditionalFactVortexColumns::with_capacity(fact_rows.len());
        for row in &fact_rows {
            columns.push_values(
                row.id,
                row.group_key,
                row.dim_key,
                row.value,
                row.metric,
                row.flag,
                row.category.clone(),
                row.event_date.clone(),
                row.nullable_metric_00.clone(),
                row.nested_payload.clone(),
                row.raw_event_time.clone(),
                row.dirty_numeric.clone(),
                row.dirty_flag.clone(),
            );
        }
        let fact_avro = root.join("fact.avro");
        write_avro_output(
            &columns.into_record_batch().expect("fact batch"),
            &fact_avro,
            "fact input",
        )
        .expect("write avro fixture");

        let source = read_traditional_fact_vortex_provider_batch_with_evidence(
            &fact_avro,
            TraditionalAnalyticsInputFormat::Avro,
            TraditionalAnalyticsResourcePolicy::auto().resolve_for_sources(1024),
            TraditionalAnalyticsScenario::SelectiveFilter,
            TraditionalFactTextColumnSelection::for_scenario(
                TraditionalAnalyticsScenario::SelectiveFilter,
            ),
        )
        .expect("projection-aware avro provider batch");

        assert_eq!(source.row_count, fact_rows.len());
        assert_eq!(
            source.evidence.decode_status(),
            "projection_aware_columnar_provider_decode"
        );
        assert_eq!(source.evidence.projected_field_mask_hex(), "0x0000003f");
        assert_eq!(source.evidence.filter_field_mask_hex(), "0x00000028");
        assert_eq!(
            source.evidence.decoded_columns(),
            "fact.id|fact.group_key|fact.dim_key|fact.value|fact.metric|fact.flag"
        );
        assert_eq!(
            source.evidence.skipped_columns(),
            "fact.category|fact.event_date|fact.nullable_metric_00|fact.nested_payload|fact.raw_event_time|fact.dirty_numeric|fact.dirty_flag"
        );
        assert_eq!(source.evidence.row_assembly_micros, 0);
        assert!(source.evidence.columnar_handoff_micros > 0);
        assert!(source.evidence.columnar_preserved);
        assert!(!source.evidence.scalar_rows_materialized);
        assert_eq!(source.batch.num_rows(), fact_rows.len());
        assert_eq!(source.batch.num_columns(), 13);

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn columnar_providers_push_fact_projection_to_reader() {
        for (input_format, extension) in [
            (TraditionalAnalyticsInputFormat::Parquet, "parquet"),
            (TraditionalAnalyticsInputFormat::ArrowIpc, "arrow"),
            (TraditionalAnalyticsInputFormat::Avro, "avro"),
            (TraditionalAnalyticsInputFormat::Orc, "orc"),
        ] {
            let root = traditional_analytics_test_root(&format!(
                "{}-projected-provider",
                input_format.as_str()
            ));
            let fact_path = if input_format == TraditionalAnalyticsInputFormat::Orc {
                write_tiny_traditional_columnar_inputs(&root, input_format).0
            } else {
                write_projected_traditional_columnar_fact(&root, input_format, extension)
            };
            let projection = fact_columnar_projection_fields_for_selection(
                TraditionalFactTextColumnSelection::for_scenario(
                    TraditionalAnalyticsScenario::NestedJsonFieldScan,
                ),
                false,
            );

            let raw_batches = read_traditional_fact_arrow_batches_with_projection(
                &fact_path,
                input_format,
                "fact input",
                TraditionalAnalyticsResourcePolicy::auto().resolve_for_sources(1024),
                &projection,
            )
            .expect("projected columnar reader batches");
            assert_eq!(raw_batches.len(), 1);
            let raw_schema = raw_batches[0].schema();
            assert_eq!(raw_schema.fields().len(), projection.len());
            assert!(raw_schema.index_of("nested_payload").is_ok());
            assert!(raw_schema.index_of("dirty_numeric").is_err());
            assert!(raw_schema.index_of("raw_event_time").is_err());

            let source = read_traditional_fact_vortex_provider_batch_with_evidence(
                &fact_path,
                input_format,
                TraditionalAnalyticsResourcePolicy::auto().resolve_for_sources(1024),
                TraditionalAnalyticsScenario::NestedJsonFieldScan,
                TraditionalFactTextColumnSelection::for_scenario(
                    TraditionalAnalyticsScenario::NestedJsonFieldScan,
                ),
            )
            .expect("projection-aware columnar provider batch");

            assert_eq!(
                source.evidence.decode_status(),
                "projection_aware_columnar_provider_decode"
            );
            assert_eq!(source.evidence.projected_field_mask_hex(), "0x0000023f");
            assert_eq!(
                source.evidence.skipped_columns(),
                "fact.category|fact.event_date|fact.nullable_metric_00|fact.raw_event_time|fact.dirty_numeric|fact.dirty_flag"
            );
            assert_eq!(source.batch.num_columns(), 13);
            assert_eq!(
                arrow_string_column(&source.batch, &fact_path, "dirty_numeric")
                    .expect("dirty_numeric default"),
                vec![String::new(); source.batch.num_rows()]
            );
            assert!(!source.evidence.scalar_rows_materialized);

            let _ = std::fs::remove_dir_all(root);
        }
    }

    #[test]
    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn avro_provider_batch_resolves_reordered_schema_projection_by_name() {
        use std::sync::Arc;

        use arrow_array::{
            ArrayRef, Float64Array, RecordBatch, UInt8Array, UInt32Array, UInt64Array,
        };
        use arrow_schema::{DataType, Field, Schema};

        let root = traditional_analytics_test_root("avro-reordered-provider");
        std::fs::create_dir_all(&root).unwrap();
        let fact_avro = root.join("fact.avro");
        let schema = Schema::new(vec![
            Field::new("value", DataType::UInt32, false),
            Field::new("id", DataType::UInt64, false),
            Field::new("flag", DataType::UInt8, false),
            Field::new("metric", DataType::Float64, false),
            Field::new("dim_key", DataType::UInt32, false),
            Field::new("group_key", DataType::UInt32, false),
        ]);
        let batch = RecordBatch::try_new(
            Arc::new(schema),
            vec![
                Arc::new(UInt32Array::from(vec![84])) as ArrayRef,
                Arc::new(UInt64Array::from(vec![8])) as ArrayRef,
                Arc::new(UInt8Array::from(vec![1])) as ArrayRef,
                Arc::new(Float64Array::from(vec![2.5])) as ArrayRef,
                Arc::new(UInt32Array::from(vec![5])) as ArrayRef,
                Arc::new(UInt32Array::from(vec![4])) as ArrayRef,
            ],
        )
        .expect("reordered fact batch");
        write_avro_output(&batch, &fact_avro, "reordered fact input")
            .expect("write reordered Avro fixture");

        let source = read_traditional_fact_vortex_provider_batch_with_evidence(
            &fact_avro,
            TraditionalAnalyticsInputFormat::Avro,
            TraditionalAnalyticsResourcePolicy::auto().resolve_for_sources(1024),
            TraditionalAnalyticsScenario::SelectiveFilter,
            TraditionalFactTextColumnSelection::for_scenario(
                TraditionalAnalyticsScenario::SelectiveFilter,
            ),
        )
        .expect("projection-aware reordered Avro provider batch");

        assert_eq!(source.row_count, 1);
        assert_eq!(source.evidence.projected_field_mask_hex(), "0x0000003f");
        assert_eq!(
            arrow_u64_column(&source.batch, &fact_avro, "id").expect("id"),
            vec![8]
        );
        assert_eq!(
            arrow_u32_column(&source.batch, &fact_avro, "value").expect("value"),
            vec![84]
        );
        assert_eq!(
            arrow_string_column(&source.batch, &fact_avro, "category").expect("category"),
            vec![String::new()]
        );

        let _ = std::fs::remove_dir_all(root);
    }

