    #[test]
    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn prepared_batch_keeps_cdc_delta_evidence_on_cdc_child_only() {
        let root = traditional_analytics_test_root("cdc-batch-child-scope");
        let (fact_csv, dim_csv) = write_tiny_traditional_csv_inputs(&root);
        let cdc_csv = root.join("cdc_delta.csv");
        std::fs::write(
            &cdc_csv,
            "id,op,value,metric,effective_ts\n1,update,7000,10.00,2024-12-01T00:00:00Z\n",
        )
        .unwrap();

        let report = run_traditional_analytics_prepared_batch_benchmark(
            TraditionalAnalyticsPreparedBatchRequest::new(
                vec![
                    TraditionalAnalyticsScenario::SmallChangeOverLargeBase,
                    TraditionalAnalyticsScenario::SelectiveFilter,
                ],
                fact_csv,
                dim_csv,
                root.join("prepare-workspace"),
            )
            .with_input_format(TraditionalAnalyticsInputFormat::Csv)
            .with_cdc_delta_input(Some(cdc_csv))
            .with_resource_policy(TraditionalAnalyticsResourcePolicy::new(2, 4)),
        )
        .unwrap();

        let cdc_child = report
            .batch_report
            .reports
            .iter()
            .find(|child| child.scenario == TraditionalAnalyticsScenario::SmallChangeOverLargeBase)
            .expect("cdc child");
        let selective_child = report
            .batch_report
            .reports
            .iter()
            .find(|child| child.scenario == TraditionalAnalyticsScenario::SelectiveFilter)
            .expect("selective child");

        assert_eq!(cdc_child.cdc_delta_rows, 1);
        assert!(cdc_child.cdc_delta_vortex_path.is_some());
        assert!(cdc_child.cdc_delta_vortex_bytes > 0);
        assert_eq!(selective_child.cdc_delta_rows, 0);
        assert!(selective_child.cdc_delta_vortex_path.is_none());
        assert_eq!(selective_child.cdc_delta_vortex_bytes, 0);
        let fields = field_map(report.batch_report.fields());
        assert_field_eq(&fields, "session_source_metadata_cache_seed_count", "1");
        assert_field_eq(&fields, "session_source_metadata_cache_hit_count", "1");
        assert_field_eq(&fields, "session_source_metadata_cache_miss_count", "1");

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn prepared_batch_manifest_register_rejects_stale_source_packet() {
        use std::io::Write as _;

        let root = traditional_analytics_test_root("prepared-register-stale-packet");
        let (fact_csv, dim_csv) = write_tiny_traditional_csv_inputs(&root);
        let workspace = root.join("prepare-workspace");
        let resource_policy = TraditionalAnalyticsResourcePolicy::default();
        let pre_prepare_packet = traditional_prepared_batch_reuse_request_payload(
            &fact_csv,
            &dim_csv,
            None,
            &workspace,
            TraditionalAnalyticsInputFormat::Csv,
            resource_policy,
        )
        .expect("pre-prepare packet");

        std::fs::OpenOptions::new()
            .append(true)
            .open(&fact_csv)
            .unwrap()
            .write_all(b"999,1,10,7,1.0,1,alpha,2024-01-01,,2024-01-01T00:00:00Z,7,true\n")
            .unwrap();
        let post_prepare_packet = traditional_prepared_batch_reuse_request_payload(
            &fact_csv,
            &dim_csv,
            None,
            &workspace,
            TraditionalAnalyticsInputFormat::Csv,
            resource_policy,
        )
        .expect("post-prepare packet");

        let err = ensure_prepared_batch_request_payload_unchanged_after_prepare(
            &pre_prepare_packet,
            &post_prepare_packet,
        )
        .expect_err("stale source packet should block manifest publication");
        assert!(err.to_string().contains("fact_input_fingerprint_changed"));
        assert!(err.to_string().contains("reuse manifest was not published"));

        let _ = std::fs::remove_dir_all(root);
    }

    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn field_map(fields: Vec<(String, String)>) -> std::collections::HashMap<String, String> {
        fields.into_iter().collect()
    }

    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn assert_field_eq(
        fields: &std::collections::HashMap<String, String>,
        name: &str,
        expected: &str,
    ) {
        assert_eq!(
            fields.get(name).map(String::as_str),
            Some(expected),
            "{name}"
        );
    }

    #[cfg(feature = "vortex-traditional-analytics-benchmark")]
    fn assert_field_contains(
        fields: &std::collections::HashMap<String, String>,
        name: &str,
        expected: &str,
    ) {
        assert!(
            fields
                .get(name)
                .is_some_and(|value| value.contains(expected)),
            "{name} should contain {expected}"
        );
    }

