        assert_field_eq(&minimal_fields, "all_result_sink_replays_verified", "false");
        assert_field_eq(&minimal_fields, "result_sink_plan_micros", "none");
        assert_field_eq(&minimal_fields, "result_sink_write_micros", "none");
